import type { StructuredRef } from './formula-ast';
import { columnLettersToIndex } from './formula-ast';

export type FormulaEditorTokenKind =
  | 'ws'
  | 'eq'
  | 'ref'
  | 'number'
  | 'string'
  | 'bool'
  | 'fn'
  | 'ident'
  | 'op'
  | 'lparen'
  | 'rparen'
  | 'comma'
  | 'colon'
  | 'unknown';

export interface FormulaEditorToken {
  readonly kind: FormulaEditorTokenKind;
  readonly text: string;
  /** 0-based inclusive position in the source string. */
  readonly start: number;
  /** 0-based exclusive end position. */
  readonly end: number;
  /** Parsed structured ref — present only when `kind === 'ref'`. */
  readonly ref?: StructuredRef;
}

export interface EditorTokenizeOptions {
  readonly locale?: 'en' | 'fr';
  /**
   * Ordered list of visible column fields — used to map A1 letters to
   * field names. When absent, A1 refs are emitted with `field: ''` so the
   * highlight layer can still position them (pending resolution).
   */
  readonly fieldOrder?: readonly string[];
}

export function tokenizeFormulaEditor(
  source: string,
  options: EditorTokenizeOptions = {},
): FormulaEditorToken[] {
  const locale = options.locale ?? 'en';
  const fieldOrder = options.fieldOrder ?? [];
  const argSeparator = locale === 'fr' ? ';' : ',';
  const out: FormulaEditorToken[] = [];
  const len = source.length;
  let i = 0;

  if (source[0] === '=') {
    out.push({ kind: 'eq', text: '=', start: 0, end: 1 });
    i = 1;
  }

  while (i < len) {
    const ch = source[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      const start = i;
      while (
        i < len &&
        (source[i] === ' ' || source[i] === '\t' || source[i] === '\n' || source[i] === '\r')
      ) {
        i++;
      }
      out.push({ kind: 'ws', text: source.slice(start, i), start, end: i });
      continue;
    }

    if (ch === '(') {
      out.push({ kind: 'lparen', text: '(', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === ')') {
      out.push({ kind: 'rparen', text: ')', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === ':') {
      out.push({ kind: 'colon', text: ':', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === argSeparator) {
      out.push({ kind: 'comma', text: argSeparator, start: i, end: i + 1 });
      i++;
      continue;
    }

    const two = source.slice(i, i + 2);
    if (two === '<=' || two === '>=' || two === '<>') {
      out.push({ kind: 'op', text: two, start: i, end: i + 2 });
      i += 2;
      continue;
    }
    if ('+-*/^&=<>'.includes(ch)) {
      out.push({ kind: 'op', text: ch, start: i, end: i + 1 });
      i++;
      continue;
    }

    if (ch === '"') {
      const start = i;
      i++;
      while (i < len) {
        if (source[i] === '"') {
          if (source[i + 1] === '"') {
            i += 2;
            continue;
          }
          i++;
          break;
        }
        i++;
      }
      out.push({ kind: 'string', text: source.slice(start, i), start, end: i });
      continue;
    }

    // Same-row ref surface: `[field]`. Emitted as a ref token so the
    // coloured overlay picks it up and the click-to-pick machinery can
    // replace it in place. An unclosed `[…` is still emitted (field is the
    // tail) so highlights update live while the user types.
    if (ch === '[') {
      const start = i;
      i++;
      while (i < len && source[i] !== ']') i++;
      const hasClose = i < len;
      if (hasClose) i++;
      const text = source.slice(start, i);
      const inner = hasClose ? text.slice(1, -1) : text.slice(1);
      const field = fieldOrder.includes(inner) ? inner : '';
      out.push({
        kind: 'ref',
        text,
        start,
        end: i,
        ref: { field, row: 0, absField: false, absRow: false, sameRow: true },
      });
      continue;
    }

    // A1 cell ref: `$?LETTERS$?DIGITS`. Detected before identifier scan so
    // `A1` is a ref, not an ident `A` + number `1`.
    const refMatch = tryScanA1(source, i, fieldOrder);
    if (refMatch) {
      out.push({
        kind: 'ref',
        text: source.slice(i, refMatch.end),
        start: i,
        end: refMatch.end,
        ref: refMatch.ref,
      });
      i = refMatch.end;
      continue;
    }

    if (isDigit(ch) || (ch === '.' && isDigit(source[i + 1] ?? ''))) {
      const start = i;
      let seenDot = ch === '.';
      let seenExp = false;
      i++;
      while (i < len) {
        const c = source[i];
        if (isDigit(c)) {
          i++;
          continue;
        }
        if (c === '.' && !seenDot && !seenExp) {
          seenDot = true;
          i++;
          continue;
        }
        if ((c === 'e' || c === 'E') && !seenExp) {
          seenExp = true;
          i++;
          if (source[i] === '+' || source[i] === '-') i++;
          continue;
        }
        break;
      }
      out.push({ kind: 'number', text: source.slice(start, i), start, end: i });
      continue;
    }

    if (isAlpha(ch) || ch === '_') {
      const start = i;
      while (
        i < len &&
        (isAlpha(source[i]) || isDigit(source[i]) || source[i] === '_' || source[i] === '.')
      ) {
        i++;
      }
      const text = source.slice(start, i);
      const upper = text.toUpperCase();
      if (upper === 'TRUE' || upper === 'FALSE') {
        out.push({ kind: 'bool', text, start, end: i });
        continue;
      }
      let k = i;
      while (k < len && (source[k] === ' ' || source[k] === '\t')) k++;
      const isFn = source[k] === '(';
      out.push({ kind: isFn ? 'fn' : 'ident', text, start, end: i });
      continue;
    }

    out.push({ kind: 'unknown', text: ch, start: i, end: i + 1 });
    i++;
  }

  return out;
}

interface A1ScanResult {
  readonly end: number;
  readonly ref: StructuredRef;
}

/**
 * Try to scan an A1 cell reference starting at `source[pos]`. Returns null
 * when the position does not start a ref. The scan is strict: letters MUST
 * be followed by at least one digit (possibly after a `$`) — a bare `A`
 * is an ident, not a ref.
 */
function tryScanA1(
  source: string,
  pos: number,
  fieldOrder: readonly string[],
): A1ScanResult | null {
  const len = source.length;
  let i = pos;
  const absField = source[i] === '$';
  if (absField) i++;

  const lettersStart = i;
  while (i < len && isAlpha(source[i])) i++;
  if (i === lettersStart) return null;
  const letters = source.slice(lettersStart, i);

  const absRow = source[i] === '$';
  const digitsCandidateStart = absRow ? i + 1 : i;
  let j = digitsCandidateStart;
  while (j < len && isDigit(source[j])) j++;
  if (j === digitsCandidateStart) return null;

  // `A1(` → function-call-like identifier (e.g. `ATAN2(`). Skip so the
  // scanner falls back to the ident branch and emits `fn`.
  if (source[j] === '(') return null;

  const digits = source.slice(digitsCandidateStart, j);
  const row = Number(digits);
  if (!Number.isFinite(row) || row < 1) return null;
  const colIdx = columnLettersToIndex(letters);
  const field = fieldOrder[colIdx] ?? '';

  return {
    end: j,
    ref: { field, row, absField, absRow },
  };
}

function isDigit(ch: string): boolean {
  return ch >= '0' && ch <= '9';
}
function isAlpha(ch: string): boolean {
  return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
}

// ─── Public helpers ─────────────────────────────────────────────────────────

/**
 * Token whose `[start, end]` range contains `caret`. When the caret sits
 * exactly between two tokens, the one ending at the caret wins — this is
 * what the autocomplete needs to match an identifier the user just typed.
 */
export function tokenAtCaret(
  tokens: readonly FormulaEditorToken[],
  caret: number,
): FormulaEditorToken | null {
  for (let idx = tokens.length - 1; idx >= 0; idx--) {
    const t = tokens[idx];
    if (caret >= t.start && caret <= t.end) return t;
  }
  return null;
}

/**
 * Detect the function-name autocomplete trigger: the caret sits at the
 * end of an ident/fn/bool token whose text is non-empty.
 */
export function autocompletePrefixAtCaret(
  tokens: readonly FormulaEditorToken[],
  caret: number,
): { token: FormulaEditorToken; prefix: string } | null {
  const tok = tokenAtCaret(tokens, caret);
  if (!tok) return null;
  if (tok.kind !== 'fn' && tok.kind !== 'ident' && tok.kind !== 'bool') return null;
  if (caret !== tok.end) return null;
  return { token: tok, prefix: tok.text.slice(0, caret - tok.start) };
}

export interface EditorRefToken {
  readonly start: number;
  readonly end: number;
  readonly text: string;
  /** `[ref]` for a simple ref, `[start, end]` for a range. */
  readonly refs: readonly StructuredRef[];
  readonly isRange: boolean;
}

/**
 * Group adjacent `ref colon ref` patterns into range tokens while keeping
 * simple refs as single-cell entries. Whitespace between the components
 * is not tolerated (Excel rule).
 */
export function extractEditorRefTokens(tokens: readonly FormulaEditorToken[]): EditorRefToken[] {
  const out: EditorRefToken[] = [];
  for (let i = 0; i < tokens.length; i++) {
    const t = tokens[i];
    if (t.kind !== 'ref' || !t.ref) continue;
    const next = tokens[i + 1];
    const after = tokens[i + 2];
    if (next?.kind === 'colon' && after?.kind === 'ref' && after.ref) {
      out.push({
        start: t.start,
        end: after.end,
        text: t.text + next.text + after.text,
        refs: [t.ref, after.ref],
        isRange: true,
      });
      i += 2;
      continue;
    }
    out.push({
      start: t.start,
      end: t.end,
      text: t.text,
      refs: [t.ref],
      isRange: false,
    });
  }
  return out;
}

import {
  ColumnResizeEvent,
  ColumnReorderEvent,
  ColumnFreezeEvent,
  ColumnVisibilityEvent,
  ColumnSearchToggleEvent,
} from './column.model';
import { SortDef, SortEvent } from './sort.model';
import { PageEvent } from './pagination.model';
import { CellEditEvent, CellEditCancelEvent } from './cell.model';
import { FilterEvent, FilterModel } from './filter.model';

export type { FilterEvent };

/**
 * Lightweight display descriptor for the "FILTERED BY" tag bar. Derived from
 * the active filter model via `FilterEngine.toLabel()`; kept as a separate
 * shape so the tag bar template does not depend on the full `FilterCondition`.
 */
export interface ActiveFilter {
  /** Condition id (not the column field — multiple conditions can target the same field). */
  id: string;
  field: string;
  label: string;
  removable: boolean;
}

export interface GroupEvent {
  columns: string[];
  groups: GroupEntry[];
}

/**
 * Emitted when the toolbar export action is triggered while `exportMode` is
 * `'server'`. The grid does not produce a file itself — the consumer reacts to
 * this event (e.g. calls a back-end export endpoint) using the active view
 * descriptors below.
 */
export interface GridExportEvent {
  format: 'csv';
  /** Active sort descriptors at export time. */
  sorts: SortDef[];
  /** Active filter model at export time. */
  filterModel: FilterModel;
  /** Fields of the currently visible columns, in display order. */
  columns: string[];
}

export interface RowSelectionEvent<T = unknown> {
  selectedIds: unknown[];
  excludedIds: unknown[];
  selectedRows: T[];
  mode: SelectAllMode;
  count: number;
}

export type SelectAllMode = 'none' | 'page' | 'all';

export interface CellSelectionEvent<T = unknown> {
  focusedCell: { row: number; col: number } | null;
  selectedCell: { row: number; col: number } | null;
  range: { start: { row: number; col: number }; end: { row: number; col: number } } | null;
  selectedData: { row: T; column: string; value: unknown }[];
}

export interface GridEventMap<T = unknown> {
  pageChange: PageEvent;
  sortChange: SortEvent;
  filterChange: FilterEvent;
  groupChange: GroupEvent;
  columnResize: ColumnResizeEvent;
  columnReorder: ColumnReorderEvent;
  columnFreeze: ColumnFreezeEvent;
  columnVisibility: ColumnVisibilityEvent;
  columnSearchToggle: ColumnSearchToggleEvent;
  selectionChange: RowSelectionEvent<T>;
  cellSelectionChange: CellSelectionEvent<T>;
  rowClick: { row: T; index: number; event: MouseEvent };
  rowExpand: { row: T; index: number; expanded: boolean };
  cellEdit: CellEditEvent<T>;
  cellEditCancel: CellEditCancelEvent;
}

export type GridEventType = keyof GridEventMap;

export type GridDensity = 'compact' | 'default' | 'comfortable';

export interface GridSettingsData {
  columns: { field: string; headerName: string; visible: boolean }[];
  density: GridDensity;
  defaultColumns: { field: string; headerName: string; visible: boolean }[];
}

export interface GridSettingsResult {
  density: GridDensity;
  columns: { field: string; visible: boolean; order: number }[];
}

export interface GroupEntry {
  field: string;
  sortDirection: 'asc' | 'desc';
}

export interface GroupDrawerData {
  groups: GroupEntry[];
  availableColumns: { field: string; headerName: string }[];
}

export interface GroupDrawerResult {
  groups: GroupEntry[];
}

import type { CellAddress } from '../../models/formula.model';

/** Literal numeric constant — e.g. `3.14`. */
export interface NumberLiteralNode {
  readonly kind: 'number';
  readonly value: number;
}

/** Literal quoted string — e.g. `"hello"`. */
export interface StringLiteralNode {
  readonly kind: 'string';
  readonly value: string;
}

/** Literal boolean constant — `TRUE` / `FALSE`. */
export interface BooleanLiteralNode {
  readonly kind: 'boolean';
  readonly value: boolean;
}

/**
 * Structured cell reference — A1-compatible. The `field` is always the
 * column's stable name (never its letter) so the ref survives reorder.
 *   - `row`      — 1-indexed display position. Ignored when `sameRow`.
 *   - `absRow`   — row locked (matches `$1` / `$A$1`; won't shift under fill).
 *   - `absField` — column locked (matches `$A` / `$A$1`; won't shift under fill).
 *   - `sameRow`  — implicit current-row ref. Surface `[field]`, storage
 *                  `REF(COLUMN("field"))` (no ROW arg). Resolves against
 *                  the host cell's row at evaluation time, so the same
 *                  formula can be placed on every row without per-row
 *                  rewriting. Mutually exclusive with `absRow`.
 */
export interface StructuredRef {
  readonly field: string;
  readonly row: number;
  readonly absRow: boolean;
  readonly absField: boolean;
  readonly sameRow?: boolean;
}

export interface CellRefNode {
  readonly kind: 'ref';
  readonly ref: StructuredRef;
  /** Resolved long-form address, attached post-parse. Optional during tests. */
  readonly resolved?: CellAddress;
}

export interface RangeRefNode {
  readonly kind: 'range';
  readonly start: StructuredRef;
  readonly end: StructuredRef;
  /**
   * Resolved cells in row-major order, attached post-parse by the mapper.
   * An undefined entry means the specific coordinate pointed to a missing
   * column — the evaluator will surface `#REF!` on access.
   */
  readonly resolved?: ReadonlyArray<CellAddress | undefined>;
}

/** Unary prefix operator (`+x`, `-x`). */
export type UnaryOp = '+' | '-';

export interface UnaryOpNode {
  readonly kind: 'unary';
  readonly op: UnaryOp;
  readonly operand: FormulaAst;
}

export type BinaryOp =
  | '+'
  | '-'
  | '*'
  | '/'
  | '^'
  | '&'
  | '='
  | '<>'
  | '<'
  | '>'
  | '<='
  | '>=';

export interface BinaryOpNode {
  readonly kind: 'binary';
  readonly op: BinaryOp;
  readonly left: FormulaAst;
  readonly right: FormulaAst;
}

export interface FunctionCallNode {
  readonly kind: 'call';
  /** Uppercased name for case-insensitive lookup. */
  readonly name: string;
  readonly args: readonly FormulaAst[];
}

export type FormulaAst =
  | NumberLiteralNode
  | StringLiteralNode
  | BooleanLiteralNode
  | CellRefNode
  | RangeRefNode
  | UnaryOpNode
  | BinaryOpNode
  | FunctionCallNode;

// ─── Column-letter helpers ──────────────────────────────────────────────────

/**
 * Convert a 0-based column index to its A1 letter sequence.
 *   0 → A, 25 → Z, 26 → AA, 27 → AB, 701 → ZZ, 702 → AAA, …
 */
export function columnIndexToLetters(index: number): string {
  if (!Number.isInteger(index) || index < 0) return '';
  let out = '';
  let n = index;
  while (true) {
    const rem = n % 26;
    out = String.fromCharCode(65 + rem) + out;
    n = Math.floor(n / 26) - 1;
    if (n < 0) break;
  }
  return out;
}

/**
 * Convert an A1 column-letter sequence to its 0-based index. Returns `-1`
 * for invalid input (empty string, non-letters).
 */
export function columnLettersToIndex(letters: string): number {
  if (letters.length === 0) return -1;
  let n = 0;
  for (let i = 0; i < letters.length; i++) {
    const code = letters.charCodeAt(i);
    const upper = code >= 97 && code <= 122 ? code - 32 : code;
    if (upper < 65 || upper > 90) return -1;
    n = n * 26 + (upper - 64);
  }
  return n - 1;
}

// ─── Field-name helpers ─────────────────────────────────────────────────────

/** Fields that don't need quoting inside `COLUMN("…")` storage form. */
const BARE_FIELD_RE = /^[A-Za-z_][A-Za-z0-9_]*$/;

/** Quote a field name when it contains characters outside the bare set. */
export function formatField(field: string): string {
  if (BARE_FIELD_RE.test(field)) return field;
  return `"${field.replace(/"/g, '""')}"`;
}

// ─── Ref formatters (A1 + long-form) ────────────────────────────────────────

/**
 * Render a structured ref as A1 notation using the column order from the
 * current grid context. Returns `#REF!` when the field is not visible.
 * Same-row refs render as `[field]` surface shorthand.
 */
export function cellRefToA1(ref: StructuredRef, fieldOrder: readonly string[]): string {
  const idx = fieldOrder.indexOf(ref.field);
  if (idx < 0) return '#REF!';
  if (ref.sameRow) return `[${ref.field}]`;
  const col = columnIndexToLetters(idx);
  return `${ref.absField ? '$' : ''}${col}${ref.absRow ? '$' : ''}${ref.row}`;
}

/**
 * Render a structured ref as the long-form storage string. Same-row refs
 * omit the ROW argument entirely (`REF(COLUMN("field"))`), which is the
 * signal consumed by the parser and the ref-mapper to resolve against the
 * host cell's row at evaluation time.
 */
export function cellRefToLongForm(ref: StructuredRef): string {
  const field = ref.field.replace(/"/g, '""');
  if (ref.sameRow) return `REF(COLUMN("${field}"))`;
  return `REF(COLUMN("${field}"),ROW(${ref.row}))`;
}

