import type { FormulaFunctionRegistry } from '../../models/formula.model';
import type { FormulaEditorToken } from './formula-tokenizer';
import { autocompletePrefixAtCaret } from './formula-tokenizer';

export type FormulaSuggestionKind = 'function';

export interface FormulaSuggestion {
  readonly kind: FormulaSuggestionKind;
  /** Uppercase function name. */
  readonly name: string;
  /** `SUM(number1, [number2, ...])` — empty string when no docs are set. */
  readonly signature: string;
  /** One-line human summary — empty string when no docs are set. */
  readonly summary: string;
  /** 0-based character offset where the replacement should start. */
  readonly replaceStart: number;
  /** 0-based character offset where the replacement should end. */
  readonly replaceEnd: number;
  /** What the panel typed so far, preserved for visual match highlighting. */
  readonly prefix: string;
}

export interface ComputeSuggestionsOptions {
  /** Maximum number of entries to return. Defaults to 8. */
  readonly limit?: number;
}

export function computeFormulaSuggestions(
  tokens: readonly FormulaEditorToken[],
  caret: number,
  registry: FormulaFunctionRegistry,
  options: ComputeSuggestionsOptions = {},
): FormulaSuggestion[] {
  const limit = options.limit ?? 8;

  const match = autocompletePrefixAtCaret(tokens, caret);
  if (!match || match.prefix.length === 0) return [];

  const prefixUpper = match.prefix.toUpperCase();
  const names = Object.keys(registry);

  const starts: string[] = [];
  const contains: string[] = [];
  for (const name of names) {
    if (name.startsWith(prefixUpper)) {
      starts.push(name);
    } else if (name.includes(prefixUpper)) {
      contains.push(name);
    }
  }
  starts.sort();
  contains.sort();

  const ranked = [...starts, ...contains];
  return ranked.slice(0, limit).map((name) => {
    const docs = registry[name]?.docs;
    return {
      kind: 'function',
      name,
      signature: docs?.signature ?? '',
      summary: docs?.summary ?? '',
      replaceStart: match.token.start,
      replaceEnd: match.token.end,
      prefix: match.prefix,
    } satisfies FormulaSuggestion;
  });
}

/**
 * Build the text to insert when accepting a function suggestion — always
 * `NAME(` so the user can immediately start typing the first argument.
 */
export function suggestionInsertionText(suggestion: FormulaSuggestion): string {
  return `${suggestion.name}(`;
}

import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { MozDrawerRef, MozDrawerFooterDirective, MozButtonComponent, MozSelectComponent, MozToggleComponent, DRAWER_DATA } from '@mozaic-ds/angular';
import { FormsModule } from '@angular/forms';
import {
  CdkDropList,
  CdkDrag,
  CdkDragHandle,
  CdkDragDrop,
  moveItemInArray,
} from '@angular/cdk/drag-drop';
import { ChevronRight20, Drag20 } from '@mozaic-ds/icons-angular';
import { GridDensity, GridSettingsData, GridSettingsResult } from '../../models/grid-events.model';

type SettingsScreen = 'main' | 'density' | 'columns';

interface DraftColumn {
  field: string;
  headerName: string;
  visible: boolean;
}

const DENSITY_OPTIONS = [
  { text: 'Compact', value: 'compact' },
  { text: 'Default', value: 'default' },
  { text: 'Comfortable', value: 'comfortable' },
];

const DENSITY_LABELS: Record<GridDensity, string> = {
  compact: 'Compact',
  default: 'Default',
  comfortable: 'Comfortable',
};

@Component({
  selector: 'ad-grid-settings-drawer',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    FormsModule,
    CdkDropList,
    CdkDrag,
    CdkDragHandle,
    MozButtonComponent,
    MozDrawerFooterDirective,
    MozSelectComponent,
    MozToggleComponent,
    ChevronRight20,
    Drag20,
  ],
  templateUrl: './grid-settings-drawer.html',
  styleUrls: ['./grid-settings-drawer.scss'],
})
export class GridSettingsDrawerComponent {
  private readonly drawerRef = inject<MozDrawerRef<GridSettingsResult>>(MozDrawerRef);
  private readonly data = inject<GridSettingsData>(DRAWER_DATA);

  readonly screen = signal<SettingsScreen>('main');
  readonly draftDensity = signal<GridDensity>(this.data.density);
  readonly draftColumns = signal<DraftColumn[]>(this.data.columns.map((c) => ({ ...c })));
  readonly searchQuery = signal('');

  readonly densityOptions = DENSITY_OPTIONS;

  readonly densityLabel = computed(() => DENSITY_LABELS[this.draftDensity()]);

  readonly columnsLabel = computed(() => {
    const cols = this.draftColumns();
    const visible = cols.filter((c) => c.visible).length;
    return `${visible}/${cols.length} displayed`;
  });

  readonly filteredColumns = computed(() => {
    const q = this.searchQuery().toLowerCase();
    if (!q) return this.draftColumns();
    return this.draftColumns().filter((c) => c.headerName.toLowerCase().includes(q));
  });

  // Store default columns for factory reset
  private readonly defaultColumns = this.data.defaultColumns.map((c) => ({ ...c }));

  constructor() {
    this.drawerRef.onBackClick().subscribe(() => {
      this.goTo('main');
    });
  }

  goTo(screen: SettingsScreen): void {
    this.screen.set(screen);
    switch (screen) {
      case 'main':
        this.drawerRef.title.set('Settings');
        this.drawerRef.contentTitle.set('');
        this.drawerRef.back.set(false);
        break;
      case 'density':
        this.drawerRef.title.set('Data density');
        this.drawerRef.contentTitle.set('');
        this.drawerRef.back.set(true);
        break;
      case 'columns':
        this.drawerRef.title.set('Display columns');
        this.drawerRef.contentTitle.set('');
        this.drawerRef.back.set(true);
        break;
    }
  }

  onColumnToggle(field: string, checked: boolean): void {
    this.draftColumns.update((cols) =>
      cols.map((c) => (c.field === field ? { ...c, visible: checked } : c))
    );
  }

  onColumnDrop(event: CdkDragDrop<DraftColumn[]>): void {
    const filtered = this.filteredColumns();
    const fromField = filtered[event.previousIndex]?.field;
    const toField = filtered[event.currentIndex]?.field;
    if (!fromField || !toField) return;

    this.draftColumns.update((cols) => {
      const updated = [...cols];
      const fromIdx = updated.findIndex((c) => c.field === fromField);
      const toIdx = updated.findIndex((c) => c.field === toField);
      if (fromIdx >= 0 && toIdx >= 0) {
        moveItemInArray(updated, fromIdx, toIdx);
      }
      return updated;
    });
  }

  onSearchInput(event: Event): void {
    this.searchQuery.set((event.target as HTMLInputElement).value);
  }

  hideAll(): void {
    this.draftColumns.update((cols) => cols.map((c) => ({ ...c, visible: false })));
  }

  showAll(): void {
    this.draftColumns.update((cols) => cols.map((c) => ({ ...c, visible: true })));
  }

  apply(): void {
    const result: GridSettingsResult = {
      density: this.draftDensity(),
      columns: this.draftColumns().map((c, i) => ({
        field: c.field,
        visible: c.visible,
        order: i,
      })),
    };
    this.drawerRef.close(result);
  }

  reset(): void {
    this.draftDensity.set('default');
    this.draftColumns.set(this.defaultColumns.map((c) => ({ ...c })));
    this.searchQuery.set('');
  }
}

import { ChangeDetectionStrategy, Component, computed, inject, signal } from '@angular/core';
import { MozDrawerRef, MozDrawerFooterDirective, MozButtonComponent, DRAWER_DATA } from '@mozaic-ds/angular';
import {
  CdkDropList,
  CdkDrag,
  CdkDragHandle,
  CdkDragDrop,
  moveItemInArray,
} from '@angular/cdk/drag-drop';
import { Drag20, Cross20, ListAdd20 } from '@mozaic-ds/icons-angular';
import { GroupDrawerData, GroupDrawerResult } from '../../models/grid-events.model';

interface DraftGroupItem {
  field: string;
  headerName: string;
  sortDirection: 'asc' | 'desc';
}

@Component({
  selector: 'ad-grid-group-drawer',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CdkDropList,
    CdkDrag,
    CdkDragHandle,
    MozButtonComponent,
    MozDrawerFooterDirective,
    Drag20,
    Cross20,
    ListAdd20,
  ],
  templateUrl: './grid-group-drawer.html',
  styleUrls: ['./grid-group-drawer.scss'],
})
export class GridGroupDrawerComponent {
  private readonly drawerRef = inject<MozDrawerRef<GroupDrawerResult>>(MozDrawerRef);
  private readonly data = inject<GroupDrawerData>(DRAWER_DATA);

  readonly draftGrouped = signal<DraftGroupItem[]>(
    this.data.groups.map((entry) => {
      const col = this.data.availableColumns.find((c) => c.field === entry.field);
      return {
        field: entry.field,
        headerName: col?.headerName ?? entry.field,
        sortDirection: entry.sortDirection,
      };
    })
  );

  private readonly allAvailable = this.data.availableColumns;

  readonly available = computed(() => {
    const grouped = new Set(this.draftGrouped().map((g) => g.field));
    return this.allAvailable.filter((c) => !grouped.has(c.field));
  });

  onDrop(event: CdkDragDrop<DraftGroupItem[]>): void {
    this.draftGrouped.update((items) => {
      const updated = [...items];
      moveItemInArray(updated, event.previousIndex, event.currentIndex);
      return updated;
    });
  }

  onSortDirectionChange(index: number, event: Event): void {
    const value = (event.target as HTMLSelectElement).value as 'asc' | 'desc';
    this.draftGrouped.update((items) =>
      items.map((item, i) => (i === index ? { ...item, sortDirection: value } : item))
    );
  }

  addGroup(field: string): void {
    const col = this.allAvailable.find((c) => c.field === field);
    if (!col) return;
    this.draftGrouped.update((items) => [
      ...items,
      { field: col.field, headerName: col.headerName, sortDirection: 'asc' },
    ]);
  }

  removeGroup(field: string): void {
    this.draftGrouped.update((items) => items.filter((i) => i.field !== field));
  }

  apply(): void {
    const result: GroupDrawerResult = {
      groups: this.draftGrouped().map((i) => ({ field: i.field, sortDirection: i.sortDirection })),
    };
    this.drawerRef.close(result);
  }

  reset(): void {
    this.draftGrouped.set([]);
  }
}

import type { StructuredRef } from './formula-ast';
import { columnLettersToIndex } from './formula-ast';

export type FormulaEditorTokenKind =
  | 'ws'
  | 'eq'
  | 'ref'
  | 'number'
  | 'string'
  | 'bool'
  | 'fn'
  | 'ident'
  | 'op'
  | 'lparen'
  | 'rparen'
  | 'comma'
  | 'colon'
  | 'unknown';

export interface FormulaEditorToken {
  readonly kind: FormulaEditorTokenKind;
  readonly text: string;
  /** 0-based inclusive position in the source string. */
  readonly start: number;
  /** 0-based exclusive end position. */
  readonly end: number;
  /** Parsed structured ref — present only when `kind === 'ref'`. */
  readonly ref?: StructuredRef;
}

export interface EditorTokenizeOptions {
  readonly locale?: 'en' | 'fr';
  /**
   * Ordered list of visible column fields — used to map A1 letters to
   * field names. When absent, A1 refs are emitted with `field: ''` so the
   * highlight layer can still position them (pending resolution).
   */
  readonly fieldOrder?: readonly string[];
}

export function tokenizeFormulaEditor(
  source: string,
  options: EditorTokenizeOptions = {},
): FormulaEditorToken[] {
  const locale = options.locale ?? 'en';
  const fieldOrder = options.fieldOrder ?? [];
  const argSeparator = locale === 'fr' ? ';' : ',';
  const out: FormulaEditorToken[] = [];
  const len = source.length;
  let i = 0;

  if (source[0] === '=') {
    out.push({ kind: 'eq', text: '=', start: 0, end: 1 });
    i = 1;
  }

  while (i < len) {
    const ch = source[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      const start = i;
      while (
        i < len &&
        (source[i] === ' ' || source[i] === '\t' || source[i] === '\n' || source[i] === '\r')
      ) {
        i++;
      }
      out.push({ kind: 'ws', text: source.slice(start, i), start, end: i });
      continue;
    }

    if (ch === '(') {
      out.push({ kind: 'lparen', text: '(', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === ')') {
      out.push({ kind: 'rparen', text: ')', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === ':') {
      out.push({ kind: 'colon', text: ':', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === argSeparator) {
      out.push({ kind: 'comma', text: argSeparator, start: i, end: i + 1 });
      i++;
      continue;
    }

    const two = source.slice(i, i + 2);
    if (two === '<=' || two === '>=' || two === '<>') {
      out.push({ kind: 'op', text: two, start: i, end: i + 2 });
      i += 2;
      continue;
    }
    if ('+-*/^&=<>'.includes(ch)) {
      out.push({ kind: 'op', text: ch, start: i, end: i + 1 });
      i++;
      continue;
    }

    if (ch === '"') {
      const start = i;
      i++;
      while (i < len) {
        if (source[i] === '"') {
          if (source[i + 1] === '"') {
            i += 2;
            continue;
          }
          i++;
          break;
        }
        i++;
      }
      out.push({ kind: 'string', text: source.slice(start, i), start, end: i });
      continue;
    }

    // Same-row ref surface: `[field]`. Emitted as a ref token so the
    // coloured overlay picks it up and the click-to-pick machinery can
    // replace it in place. An unclosed `[…` is still emitted (field is the
    // tail) so highlights update live while the user types.
    if (ch === '[') {
      const start = i;
      i++;
      while (i < len && source[i] !== ']') i++;
      const hasClose = i < len;
      if (hasClose) i++;
      const text = source.slice(start, i);
      const inner = hasClose ? text.slice(1, -1) : text.slice(1);
      const field = fieldOrder.includes(inner) ? inner : '';
      out.push({
        kind: 'ref',
        text,
        start,
        end: i,
        ref: { field, row: 0, absField: false, absRow: false, sameRow: true },
      });
      continue;
    }

    // A1 cell ref: `$?LETTERS$?DIGITS`. Detected before identifier scan so
    // `A1` is a ref, not an ident `A` + number `1`.
    const refMatch = tryScanA1(source, i, fieldOrder);
    if (refMatch) {
      out.push({
        kind: 'ref',
        text: source.slice(i, refMatch.end),
        start: i,
        end: refMatch.end,
        ref: refMatch.ref,
      });
      i = refMatch.end;
      continue;
    }

    if (isDigit(ch) || (ch === '.' && isDigit(source[i + 1] ?? ''))) {
      const start = i;
      let seenDot = ch === '.';
      let seenExp = false;
      i++;
      while (i < len) {
        const c = source[i];
        if (isDigit(c)) {
          i++;
          continue;
        }
        if (c === '.' && !seenDot && !seenExp) {
          seenDot = true;
          i++;
          continue;
        }
        if ((c === 'e' || c === 'E') && !seenExp) {
          seenExp = true;
          i++;
          if (source[i] === '+' || source[i] === '-') i++;
          continue;
        }
        break;
      }
      out.push({ kind: 'number', text: source.slice(start, i), start, end: i });
      continue;
    }

    if (isAlpha(ch) || ch === '_') {
      const start = i;
      while (
        i < len &&
        (isAlpha(source[i]) || isDigit(source[i]) || source[i] === '_' || source[i] === '.')
      ) {
        i++;
      }
      const text = source.slice(start, i);
      const upper = text.toUpperCase();
      if (upper === 'TRUE' || upper === 'FALSE') {
        out.push({ kind: 'bool', text, start, end: i });
        continue;
      }
      let k = i;
      while (k < len && (source[k] === ' ' || source[k] === '\t')) k++;
      const isFn = source[k] === '(';
      out.push({ kind: isFn ? 'fn' : 'ident', text, start, end: i });
      continue;
    }

    out.push({ kind: 'unknown', text: ch, start: i, end: i + 1 });
    i++;
  }

  return out;
}

interface A1ScanResult {
  readonly end: number;
  readonly ref: StructuredRef;
}

/**
 * Try to scan an A1 cell reference starting at `source[pos]`. Returns null
 * when the position does not start a ref. The scan is strict: letters MUST
 * be followed by at least one digit (possibly after a `$`) — a bare `A`
 * is an ident, not a ref.
 */
function tryScanA1(
  source: string,
  pos: number,
  fieldOrder: readonly string[],
): A1ScanResult | null {
  const len = source.length;
  let i = pos;
  const absField = source[i] === '$';
  if (absField) i++;

  const lettersStart = i;
  while (i < len && isAlpha(source[i])) i++;
  if (i === lettersStart) return null;
  const letters = source.slice(lettersStart, i);

  const absRow = source[i] === '$';
  const digitsCandidateStart = absRow ? i + 1 : i;
  let j = digitsCandidateStart;
  while (j < len && isDigit(source[j])) j++;
  if (j === digitsCandidateStart) return null;

  // `A1(` → function-call-like identifier (e.g. `ATAN2(`). Skip so the
  // scanner falls back to the ident branch and emits `fn`.
  if (source[j] === '(') return null;

  const digits = source.slice(digitsCandidateStart, j);
  const row = Number(digits);
  if (!Number.isFinite(row) || row < 1) return null;
  const colIdx = columnLettersToIndex(letters);
  const field = fieldOrder[colIdx] ?? '';

  return {
    end: j,
    ref: { field, row, absField, absRow },
  };
}

function isDigit(ch: string): boolean {
  return ch >= '0' && ch <= '9';
}
function isAlpha(ch: string): boolean {
  return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
}

// ─── Public helpers ─────────────────────────────────────────────────────────

/**
 * Token whose `[start, end]` range contains `caret`. When the caret sits
 * exactly between two tokens, the one ending at the caret wins — this is
 * what the autocomplete needs to match an identifier the user just typed.
 */
export function tokenAtCaret(
  tokens: readonly FormulaEditorToken[],
  caret: number,
): FormulaEditorToken | null {
  for (let idx = tokens.length - 1; idx >= 0; idx--) {
    const t = tokens[idx];
    if (caret >= t.start && caret <= t.end) return t;
  }
  return null;
}

/**
 * Detect the function-name autocomplete trigger: the caret sits at the
 * end of an ident/fn/bool token whose text is non-empty.
 */
export function autocompletePrefixAtCaret(
  tokens: readonly FormulaEditorToken[],
  caret: number,
): { token: FormulaEditorToken; prefix: string } | null {
  const tok = tokenAtCaret(tokens, caret);
  if (!tok) return null;
  if (tok.kind !== 'fn' && tok.kind !== 'ident' && tok.kind !== 'bool') return null;
  if (caret !== tok.end) return null;
  return { token: tok, prefix: tok.text.slice(0, caret - tok.start) };
}

export interface EditorRefToken {
  readonly start: number;
  readonly end: number;
  readonly text: string;
  /** `[ref]` for a simple ref, `[start, end]` for a range. */
  readonly refs: readonly StructuredRef[];
  readonly isRange: boolean;
}

/**
 * Group adjacent `ref colon ref` patterns into range tokens while keeping
 * simple refs as single-cell entries. Whitespace between the components
 * is not tolerated (Excel rule).
 */
export function extractEditorRefTokens(tokens: readonly FormulaEditorToken[]): EditorRefToken[] {
  const out: EditorRefToken[] = [];
  for (let i = 0; i < tokens.length; i++) {
    const t = tokens[i];
    if (t.kind !== 'ref' || !t.ref) continue;
    const next = tokens[i + 1];
    const after = tokens[i + 2];
    if (next?.kind === 'colon' && after?.kind === 'ref' && after.ref) {
      out.push({
        start: t.start,
        end: after.end,
        text: t.text + next.text + after.text,
        refs: [t.ref, after.ref],
        isRange: true,
      });
      i += 2;
      continue;
    }
    out.push({
      start: t.start,
      end: t.end,
      text: t.text,
      refs: [t.ref],
      isRange: false,
    });
  }
  return out;
}

import type { StructuredRef } from './formula-ast';
import { columnLettersToIndex } from './formula-ast';

export type FormulaEditorTokenKind =
  | 'ws'
  | 'eq'
  | 'ref'
  | 'number'
  | 'string'
  | 'bool'
  | 'fn'
  | 'ident'
  | 'op'
  | 'lparen'
  | 'rparen'
  | 'comma'
  | 'colon'
  | 'unknown';

export interface FormulaEditorToken {
  readonly kind: FormulaEditorTokenKind;
  readonly text: string;
  /** 0-based inclusive position in the source string. */
  readonly start: number;
  /** 0-based exclusive end position. */
  readonly end: number;
  /** Parsed structured ref — present only when `kind === 'ref'`. */
  readonly ref?: StructuredRef;
}

export interface EditorTokenizeOptions {
  readonly locale?: 'en' | 'fr';
  /**
   * Ordered list of visible column fields — used to map A1 letters to
   * field names. When absent, A1 refs are emitted with `field: ''` so the
   * highlight layer can still position them (pending resolution).
   */
  readonly fieldOrder?: readonly string[];
}

export function tokenizeFormulaEditor(
  source: string,
  options: EditorTokenizeOptions = {},
): FormulaEditorToken[] {
  const locale = options.locale ?? 'en';
  const fieldOrder = options.fieldOrder ?? [];
  const argSeparator = locale === 'fr' ? ';' : ',';
  const out: FormulaEditorToken[] = [];
  const len = source.length;
  let i = 0;

  if (source[0] === '=') {
    out.push({ kind: 'eq', text: '=', start: 0, end: 1 });
    i = 1;
  }

  while (i < len) {
    const ch = source[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      const start = i;
      while (
        i < len &&
        (source[i] === ' ' || source[i] === '\t' || source[i] === '\n' || source[i] === '\r')
      ) {
        i++;
      }
      out.push({ kind: 'ws', text: source.slice(start, i), start, end: i });
      continue;
    }

    if (ch === '(') {
      out.push({ kind: 'lparen', text: '(', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === ')') {
      out.push({ kind: 'rparen', text: ')', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === ':') {
      out.push({ kind: 'colon', text: ':', start: i, end: i + 1 });
      i++;
      continue;
    }
    if (ch === argSeparator) {
      out.push({ kind: 'comma', text: argSeparator, start: i, end: i + 1 });
      i++;
      continue;
    }

    const two = source.slice(i, i + 2);
    if (two === '<=' || two === '>=' || two === '<>') {
      out.push({ kind: 'op', text: two, start: i, end: i + 2 });
      i += 2;
      continue;
    }
    if ('+-*/^&=<>'.includes(ch)) {
      out.push({ kind: 'op', text: ch, start: i, end: i + 1 });
      i++;
      continue;
    }

    if (ch === '"') {
      const start = i;
      i++;
      while (i < len) {
        if (source[i] === '"') {
          if (source[i + 1] === '"') {
            i += 2;
            continue;
          }
          i++;
          break;
        }
        i++;
      }
      out.push({ kind: 'string', text: source.slice(start, i), start, end: i });
      continue;
    }

    // Same-row ref surface: `[field]`. Emitted as a ref token so the
    // coloured overlay picks it up and the click-to-pick machinery can
    // replace it in place. An unclosed `[…` is still emitted (field is the
    // tail) so highlights update live while the user types.
    if (ch === '[') {
      const start = i;
      i++;
      while (i < len && source[i] !== ']') i++;
      const hasClose = i < len;
      if (hasClose) i++;
      const text = source.slice(start, i);
      const inner = hasClose ? text.slice(1, -1) : text.slice(1);
      const field = fieldOrder.includes(inner) ? inner : '';
      out.push({
        kind: 'ref',
        text,
        start,
        end: i,
        ref: { field, row: 0, absField: false, absRow: false, sameRow: true },
      });
      continue;
    }

    // A1 cell ref: `$?LETTERS$?DIGITS`. Detected before identifier scan so
    // `A1` is a ref, not an ident `A` + number `1`.
    const refMatch = tryScanA1(source, i, fieldOrder);
    if (refMatch) {
      out.push({
        kind: 'ref',
        text: source.slice(i, refMatch.end),
        start: i,
        end: refMatch.end,
        ref: refMatch.ref,
      });
      i = refMatch.end;
      continue;
    }

    if (isDigit(ch) || (ch === '.' && isDigit(source[i + 1] ?? ''))) {
      const start = i;
      let seenDot = ch === '.';
      let seenExp = false;
      i++;
      while (i < len) {
        const c = source[i];
        if (isDigit(c)) {
          i++;
          continue;
        }
        if (c === '.' && !seenDot && !seenExp) {
          seenDot = true;
          i++;
          continue;
        }
        if ((c === 'e' || c === 'E') && !seenExp) {
          seenExp = true;
          i++;
          if (source[i] === '+' || source[i] === '-') i++;
          continue;
        }
        break;
      }
      out.push({ kind: 'number', text: source.slice(start, i), start, end: i });
      continue;
    }

    if (isAlpha(ch) || ch === '_') {
      const start = i;
      while (
        i < len &&
        (isAlpha(source[i]) || isDigit(source[i]) || source[i] === '_' || source[i] === '.')
      ) {
        i++;
      }
      const text = source.slice(start, i);
      const upper = text.toUpperCase();
      if (upper === 'TRUE' || upper === 'FALSE') {
        out.push({ kind: 'bool', text, start, end: i });
        continue;
      }
      let k = i;
      while (k < len && (source[k] === ' ' || source[k] === '\t')) k++;
      const isFn = source[k] === '(';
      out.push({ kind: isFn ? 'fn' : 'ident', text, start, end: i });
      continue;
    }

    out.push({ kind: 'unknown', text: ch, start: i, end: i + 1 });
    i++;
  }

  return out;
}

interface A1ScanResult {
  readonly end: number;
  readonly ref: StructuredRef;
}

/**
 * Try to scan an A1 cell reference starting at `source[pos]`. Returns null
 * when the position does not start a ref. The scan is strict: letters MUST
 * be followed by at least one digit (possibly after a `$`) — a bare `A`
 * is an ident, not a ref.
 */
function tryScanA1(
  source: string,
  pos: number,
  fieldOrder: readonly string[],
): A1ScanResult | null {
  const len = source.length;
  let i = pos;
  const absField = source[i] === '$';
  if (absField) i++;

  const lettersStart = i;
  while (i < len && isAlpha(source[i])) i++;
  if (i === lettersStart) return null;
  const letters = source.slice(lettersStart, i);

  const absRow = source[i] === '$';
  const digitsCandidateStart = absRow ? i + 1 : i;
  let j = digitsCandidateStart;
  while (j < len && isDigit(source[j])) j++;
  if (j === digitsCandidateStart) return null;

  // `A1(` → function-call-like identifier (e.g. `ATAN2(`). Skip so the
  // scanner falls back to the ident branch and emits `fn`.
  if (source[j] === '(') return null;

  const digits = source.slice(digitsCandidateStart, j);
  const row = Number(digits);
  if (!Number.isFinite(row) || row < 1) return null;
  const colIdx = columnLettersToIndex(letters);
  const field = fieldOrder[colIdx] ?? '';

  return {
    end: j,
    ref: { field, row, absField, absRow },
  };
}

function isDigit(ch: string): boolean {
  return ch >= '0' && ch <= '9';
}
function isAlpha(ch: string): boolean {
  return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
}

