import { inject, Injectable } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { ColumnStateEntry, ColumnDef } from '../models/column.model';

export interface ExportOptions {
  filename?: string;
  separator?: string;
  includeHeaders?: boolean;
  columns?: string[];
}

@Injectable()
export class ExportEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  // ── helpers ─────────────────────────────────────────────────────────────

  private escapeCsvValue(value: string, separator: string): string {
    if (value.includes(separator) || value.includes('"') || value.includes('\n')) {
      return `"${value.replace(/"/g, '""')}"`;
    }
    return value;
  }

  private buildCsvRow(
    row: T,
    cols: ColumnStateEntry[],
    defMap: Map<string, ColumnDef<T>>,
    separator: string,
  ): string {
    return cols
      .map((col) => {
        const def = defMap.get(col.field);
        let value: unknown;
        if (def?.valueGetter) {
          value = def.valueGetter(row);
        } else {
          value = (row as Record<string, unknown>)[col.field];
        }
        if (def?.valueFormatter) {
          return this.escapeCsvValue(def.valueFormatter(value, row), separator);
        }
        return this.escapeCsvValue(String(value ?? ''), separator);
      })
      .join(separator);
  }

  private downloadBlob(filename: string, blob: Blob): void {
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    link.style.display = 'none';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }

  private downloadFile(filename: string, content: string, mimeType: string): void {
    this.downloadBlob(filename, new Blob([content], { type: mimeType }));
  }

  // ── streaming helpers (B18) ──────────────────────────────────────────────

  private async exportCsvStreaming(
    data: T[],
    cols: ColumnStateEntry[],
    defMap: Map<string, ColumnDef<T>>,
    filename: string,
    separator: string,
    includeHeaders: boolean,
  ): Promise<void> {
    const encoder = new TextEncoder();
    const ts = new TransformStream<Uint8Array, Uint8Array>();
    const writer = ts.writable.getWriter();

    if (includeHeaders) {
      const headerRow =
        cols
          .map((col) => this.escapeCsvValue(defMap.get(col.field)?.headerName ?? col.field, separator))
          .join(separator) + '\n';
      await writer.write(encoder.encode(headerRow));
    }

    const CHUNK = 1_000;
    for (let i = 0; i < data.length; i += CHUNK) {
      const chunk =
        data
          .slice(i, i + CHUNK)
          .map((row) => this.buildCsvRow(row, cols, defMap, separator))
          .join('\n') + '\n';
      await writer.write(encoder.encode(chunk));
    }

    await writer.close();
    const blob = await new Response(ts.readable).blob();
    this.downloadBlob(`${filename}.csv`, blob);
  }

  private async exportJsonStreaming(
    data: T[],
    fields: string[],
    defMap: Map<string, ColumnDef<T>>,
    filename: string,
  ): Promise<void> {
    const encoder = new TextEncoder();
    const ts = new TransformStream<Uint8Array, Uint8Array>();
    const writer = ts.writable.getWriter();

    await writer.write(encoder.encode('[\n'));

    const CHUNK = 1_000;
    for (let i = 0; i < data.length; i += CHUNK) {
      const slice = data.slice(i, i + CHUNK);
      const isLast = i + CHUNK >= data.length;
      const rows = slice.map((row) => {
        const obj: Record<string, unknown> = {};
        for (const field of fields) {
          const def = defMap.get(field);
          obj[field] = def?.valueGetter
            ? def.valueGetter(row)
            : (row as Record<string, unknown>)[field];
        }
        return obj;
      });
      const chunk =
        rows
          .map((obj, idx) => '  ' + JSON.stringify(obj) + (isLast && idx === rows.length - 1 ? '' : ','))
          .join('\n') + '\n';
      await writer.write(encoder.encode(chunk));
    }

    await writer.write(encoder.encode(']'));
    await writer.close();
    const blob = await new Response(ts.readable).blob();
    this.downloadBlob(`${filename}.json`, blob);
  }

  // ── public API ───────────────────────────────────────────────────────────

  exportCsv(data: T[], options: ExportOptions = {}): void {
    const {
      filename = 'export',
      separator = ',',
      includeHeaders = true,
      columns,
    } = options;

    const cols = columns
      ? this.state.visibleColumns().filter((c) => columns.includes(c.field))
      : this.state.visibleColumns();

    const defMap = this.state.columnDefMap();

    // B18: stream when available, synchronous fallback otherwise.
    if (typeof TransformStream !== 'undefined') {
      void this.exportCsvStreaming(data, cols, defMap, filename, separator, includeHeaders);
      return;
    }

    const lines: string[] = [];
    if (includeHeaders) {
      lines.push(
        cols
          .map((col) => this.escapeCsvValue(defMap.get(col.field)?.headerName ?? col.field, separator))
          .join(separator),
      );
    }
    for (const row of data) {
      lines.push(this.buildCsvRow(row, cols, defMap, separator));
    }
    this.downloadFile(`${filename}.csv`, lines.join('\n'), 'text/csv;charset=utf-8;');
  }

  exportJson(data: T[], options: { filename?: string; columns?: string[] } = {}): void {
    const { filename = 'export', columns } = options;

    const cols = columns
      ? this.state.visibleColumns().filter((c) => columns.includes(c.field))
      : this.state.visibleColumns();

    const fields = cols.map((c) => c.field);
    const defMap = this.state.columnDefMap();

    // B18: stream when available, synchronous fallback otherwise.
    if (typeof TransformStream !== 'undefined') {
      void this.exportJsonStreaming(data, fields, defMap, filename);
      return;
    }

    const exportData = data.map((row) => {
      const obj: Record<string, unknown> = {};
      for (const field of fields) {
        const def = defMap.get(field);
        obj[field] = def?.valueGetter
          ? def.valueGetter(row)
          : (row as Record<string, unknown>)[field];
      }
      return obj;
    });
    this.downloadFile(`${filename}.json`, JSON.stringify(exportData, null, 2), 'application/json;charset=utf-8;');
  }
}

export interface CellCoord {
  row: number;
  col: number;
}

export interface CellRange {
  start: CellCoord;
  end: CellCoord;
}

export interface CellEditState {
  editingCell: CellCoord | null;
  originalValue: unknown;
  draftValue: unknown;
  validationError: string | null;
}

export interface CellEditEvent<T = unknown> {
  row: T;
  rowIndex: number;
  field: string;
  oldValue: unknown;
  newValue: unknown;
}

export interface CellEditCancelEvent {
  rowIndex: number;
  field: string;
  originalValue: unknown;
}

export interface BulkEditEvent {
  range: CellRange | null;
  cellCount: number;
  rowIds: unknown[];
  fields: string[];
  selectionMode?: 'rows' | 'cells';
  rowSelection?: unknown;
}

export interface BulkCopyEvent {
  range: CellRange | null;
  data: string[][];
  rowIds: unknown[];
  fields: string[];
  selectionMode?: 'rows' | 'cells';
  rowSelection?: unknown;
}

/**
 * A single cell change produced by a bulk operation (paste, delete, …).
 * Values are already coerced to the column's expected type and have passed
 * `cellEditorValidator`; consumers can persist them as-is.
 */
export interface BulkCellChange {
  rowIndex: number;
  rowId: unknown;
  field: string;
  oldValue: unknown;
  newValue: unknown;
}

export interface BulkPasteEvent {
  range: CellRange | null;
  data: string[][];
  rowIds: unknown[];
  fields: string[];
  /**
   * Fully resolved per-cell changes applied by the grid (post-coercion,
   * post-validation). Use this to persist server-side — no need to replicate
   * the fill logic from `data` vs `range`.
   */
  changes: BulkCellChange[];
  selectionMode?: 'rows' | 'cells';
  rowSelection?: unknown;
}

export interface FillDownEvent {
  sourceCell: CellCoord;
  sourceValue: unknown;
  direction: 'vertical' | 'horizontal';
  /** Total cells actually written (excludes the anchor and non-editable columns). */
  affectedCellCount: number;

  // --- Vertical fill (single source column, multiple target rows) ---
  field?: string;
  targetRange?: { startRow: number; endRow: number };
  /** @deprecated Use `affectedCellCount` instead. */
  affectedRowCount?: number;

  // --- Horizontal fill (single row, multiple target columns) ---
  /** Target columns written in the horizontal fill. Non-editable columns are filtered out. */
  targetFields?: string[];
}

export interface CellError {
  message: string;
}

export interface BulkDeleteEvent {
  range: CellRange | null;
  cellCount: number;
  rowIds: unknown[];
  fields: string[];
  /**
   * Fully resolved per-cell changes applied by the grid (post-coercion,
   * post-validation). Use this to persist server-side.
   */
  changes: BulkCellChange[];
  selectionMode?: 'rows' | 'cells';
  rowSelection?: unknown;
}

import { InputSignal, OutputEmitterRef, Type } from '@angular/core';

/** Controls where filter evaluation happens. */
export type FilterMode = 'client' | 'server';

export type FilterDataType = 'text' | 'number' | 'date' | 'set' | 'boolean' | 'custom';

export type TextOperator =
  | 'contains'
  | 'notContains'
  | 'equals'
  | 'notEquals'
  | 'startsWith'
  | 'endsWith'
  | 'blank'
  | 'notBlank';

export type NumberOperator =
  | 'equals'
  | 'notEquals'
  | 'gt'
  | 'gte'
  | 'lt'
  | 'lte'
  | 'between'
  | 'blank'
  | 'notBlank';

export type DateOperator = NumberOperator;
export type SetOperator = 'in' | 'notIn' | 'blank' | 'notBlank';
export type BooleanOperator = 'equals' | 'blank' | 'notBlank';

export type FilterOperator =
  | TextOperator
  | NumberOperator
  | DateOperator
  | SetOperator
  | BooleanOperator;

export type FilterCombinator = 'and' | 'or';

export interface FilterValue {
  /** Primary value. Absent / ignored for `blank` / `notBlank`. */
  value?: unknown;
  /** Upper bound for `between`. */
  valueTo?: unknown;
}

export interface FilterCondition {
  /** Stable identifier — used for trackBy and drag-drop reordering. */
  id: string;
  /** Ignored for the first condition. Rendered as "Where" in the UI. */
  combinator: FilterCombinator;
  field: string;
  operator: FilterOperator;
  value: FilterValue;
}

export interface FilterModel {
  conditions: FilterCondition[];
}

export type FilterChangeReason =
  | 'add'
  | 'update'
  | 'remove'
  | 'reorder'
  | 'clear'
  | 'replace';

/**
 * Payload emitted whenever the filter model changes. Replaces the legacy
 * `{ filters: ActiveFilter[] }` shape.
 */
export interface FilterEvent {
  /** Full model after mutation. */
  model: FilterModel;
  /** Condition concerned by the mutation. null for `clear` / `replace`. */
  condition: FilterCondition | null;
  /** Mutation kind. */
  reason: FilterChangeReason;
}

/** Drawer data / result for the Filters drawer (toolbar). */
export interface FilterDrawerData {
  model: FilterModel;
  availableColumns: FilterColumnDescriptor[];
  applyMode: FilterApplyMode;
}

export interface FilterDrawerResult {
  model: FilterModel;
  applied: boolean;
}

export type FilterApplyMode = 'auto' | 'manual';

/**
 * Base class for custom filter components. Extend this class and declare:
 *   readonly condition = input.required<FilterCondition>();
 *   readonly conditionChange = output<FilterValue>();
 *
 * The filter builder instantiates the component via ViewContainerRef and wires
 * the inputs/outputs automatically — the component has no dependency on the grid.
 */
export abstract class AdeoGridCustomFilter {
  abstract readonly condition: InputSignal<FilterCondition>;
  abstract readonly conditionChange: OutputEmitterRef<FilterValue>;
}

/** Minimal column info the builder needs to render labels, operators and value editors. */
export interface FilterColumnDescriptor {
  field: string;
  headerName: string;
  filterType: FilterDataType;
  operators: FilterOperator[];
  options?: { value: unknown; label: string }[];
  defaultOperator: FilterOperator;
  /** Custom component rendered in the builder for filterType === 'custom'. */
  filterComponent?: Type<AdeoGridCustomFilter>;
  /** Override for completion check. Defaults to value.value != null && !== ''. */
  filterIsComplete?: (value: FilterValue) => boolean;
}

/**
 * Default operator sets per data type. Consumers can restrict the set via
 * `ColumnDef.filterOperators`.
 */
export const DEFAULT_OPERATORS: Record<FilterDataType, FilterOperator[]> = {
  text: [
    'contains',
    'notContains',
    'equals',
    'notEquals',
    'startsWith',
    'endsWith',
    'blank',
    'notBlank',
  ],
  number: ['equals', 'notEquals', 'gt', 'gte', 'lt', 'lte', 'between', 'blank', 'notBlank'],
  date: ['equals', 'notEquals', 'gt', 'gte', 'lt', 'lte', 'between', 'blank', 'notBlank'],
  set: ['in', 'notIn', 'blank', 'notBlank'],
  boolean: ['equals', 'blank', 'notBlank'],
  custom: [],
};

export const DEFAULT_OPERATOR_PER_TYPE: Record<FilterDataType, FilterOperator> = {
  text: 'contains',
  number: 'equals',
  date: 'equals',
  set: 'in',
  boolean: 'equals',
  custom: 'equals',
};

/** Human-readable operator labels (used by `toLabel`). */
export const OPERATOR_LABELS: Record<FilterOperator, string> = {
  contains: 'contains',
  notContains: 'does not contain',
  equals: 'equals',
  notEquals: 'does not equal',
  startsWith: 'starts with',
  endsWith: 'ends with',
  gt: '>',
  gte: '≥',
  lt: '<',
  lte: '≤',
  between: 'between',
  in: 'in',
  notIn: 'not in',
  blank: 'is blank',
  notBlank: 'is not blank',
};

/** Operators that do not require a user-entered value. */
export const VALUELESS_OPERATORS: ReadonlySet<FilterOperator> = new Set<FilterOperator>([
  'blank',
  'notBlank',
]);

/** Operators that need a secondary value (`between`). */
export const RANGE_OPERATORS: ReadonlySet<FilterOperator> = new Set<FilterOperator>(['between']);

/** Small helper for generating condition ids without pulling in a uuid dep. */
export function generateConditionId(): string {
  return `cond-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
}

/** True when a condition has enough information to participate in evaluation. */
export function isConditionComplete(condition: FilterCondition): boolean {
  if (!condition.field) return false;
  if (VALUELESS_OPERATORS.has(condition.operator)) return true;
  const { value, valueTo } = condition.value;
  if (value == null || value === '') return false;
  if (RANGE_OPERATORS.has(condition.operator)) {
    if (valueTo == null || valueTo === '') return false;
  }
  return true;
}

