import type { FormulaFunctionRegistry } from '../../models/formula.model';
import type { FormulaEditorToken } from './formula-tokenizer';
import { autocompletePrefixAtCaret } from './formula-tokenizer';

export type FormulaSuggestionKind = 'function';

export interface FormulaSuggestion {
  readonly kind: FormulaSuggestionKind;
  /** Uppercase function name. */
  readonly name: string;
  /** `SUM(number1, [number2, ...])` — empty string when no docs are set. */
  readonly signature: string;
  /** One-line human summary — empty string when no docs are set. */
  readonly summary: string;
  /** 0-based character offset where the replacement should start. */
  readonly replaceStart: number;
  /** 0-based character offset where the replacement should end. */
  readonly replaceEnd: number;
  /** What the panel typed so far, preserved for visual match highlighting. */
  readonly prefix: string;
}

export interface ComputeSuggestionsOptions {
  /** Maximum number of entries to return. Defaults to 8. */
  readonly limit?: number;
}

export function computeFormulaSuggestions(
  tokens: readonly FormulaEditorToken[],
  caret: number,
  registry: FormulaFunctionRegistry,
  options: ComputeSuggestionsOptions = {},
): FormulaSuggestion[] {
  const limit = options.limit ?? 8;

  const match = autocompletePrefixAtCaret(tokens, caret);
  if (!match || match.prefix.length === 0) return [];

  const prefixUpper = match.prefix.toUpperCase();
  const names = Object.keys(registry);

  const starts: string[] = [];
  const contains: string[] = [];
  for (const name of names) {
    if (name.startsWith(prefixUpper)) {
      starts.push(name);
    } else if (name.includes(prefixUpper)) {
      contains.push(name);
    }
  }
  starts.sort();
  contains.sort();

  const ranked = [...starts, ...contains];
  return ranked.slice(0, limit).map((name) => {
    const docs = registry[name]?.docs;
    return {
      kind: 'function',
      name,
      signature: docs?.signature ?? '',
      summary: docs?.summary ?? '',
      replaceStart: match.token.start,
      replaceEnd: match.token.end,
      prefix: match.prefix,
    } satisfies FormulaSuggestion;
  });
}

/**
 * Build the text to insert when accepting a function suggestion — always
 * `NAME(` so the user can immediately start typing the first argument.
 */
export function suggestionInsertionText(suggestion: FormulaSuggestion): string {
  return `${suggestion.name}(`;
}

import type { CellAddress } from '../../models/formula.model';

/** Literal numeric constant — e.g. `3.14`. */
export interface NumberLiteralNode {
  readonly kind: 'number';
  readonly value: number;
}

/** Literal quoted string — e.g. `"hello"`. */
export interface StringLiteralNode {
  readonly kind: 'string';
  readonly value: string;
}

/** Literal boolean constant — `TRUE` / `FALSE`. */
export interface BooleanLiteralNode {
  readonly kind: 'boolean';
  readonly value: boolean;
}

/**
 * Structured cell reference — A1-compatible. The `field` is always the
 * column's stable name (never its letter) so the ref survives reorder.
 *   - `row`      — 1-indexed display position. Ignored when `sameRow`.
 *   - `absRow`   — row locked (matches `$1` / `$A$1`; won't shift under fill).
 *   - `absField` — column locked (matches `$A` / `$A$1`; won't shift under fill).
 *   - `sameRow`  — implicit current-row ref. Surface `[field]`, storage
 *                  `REF(COLUMN("field"))` (no ROW arg). Resolves against
 *                  the host cell's row at evaluation time, so the same
 *                  formula can be placed on every row without per-row
 *                  rewriting. Mutually exclusive with `absRow`.
 */
export interface StructuredRef {
  readonly field: string;
  readonly row: number;
  readonly absRow: boolean;
  readonly absField: boolean;
  readonly sameRow?: boolean;
}

export interface CellRefNode {
  readonly kind: 'ref';
  readonly ref: StructuredRef;
  /** Resolved long-form address, attached post-parse. Optional during tests. */
  readonly resolved?: CellAddress;
}

export interface RangeRefNode {
  readonly kind: 'range';
  readonly start: StructuredRef;
  readonly end: StructuredRef;
  /**
   * Resolved cells in row-major order, attached post-parse by the mapper.
   * An undefined entry means the specific coordinate pointed to a missing
   * column — the evaluator will surface `#REF!` on access.
   */
  readonly resolved?: ReadonlyArray<CellAddress | undefined>;
}

/** Unary prefix operator (`+x`, `-x`). */
export type UnaryOp = '+' | '-';

export interface UnaryOpNode {
  readonly kind: 'unary';
  readonly op: UnaryOp;
  readonly operand: FormulaAst;
}

export type BinaryOp =
  | '+'
  | '-'
  | '*'
  | '/'
  | '^'
  | '&'
  | '='
  | '<>'
  | '<'
  | '>'
  | '<='
  | '>=';

export interface BinaryOpNode {
  readonly kind: 'binary';
  readonly op: BinaryOp;
  readonly left: FormulaAst;
  readonly right: FormulaAst;
}

export interface FunctionCallNode {
  readonly kind: 'call';
  /** Uppercased name for case-insensitive lookup. */
  readonly name: string;
  readonly args: readonly FormulaAst[];
}

export type FormulaAst =
  | NumberLiteralNode
  | StringLiteralNode
  | BooleanLiteralNode
  | CellRefNode
  | RangeRefNode
  | UnaryOpNode
  | BinaryOpNode
  | FunctionCallNode;

// ─── Column-letter helpers ──────────────────────────────────────────────────

/**
 * Convert a 0-based column index to its A1 letter sequence.
 *   0 → A, 25 → Z, 26 → AA, 27 → AB, 701 → ZZ, 702 → AAA, …
 */
export function columnIndexToLetters(index: number): string {
  if (!Number.isInteger(index) || index < 0) return '';
  let out = '';
  let n = index;
  while (true) {
    const rem = n % 26;
    out = String.fromCharCode(65 + rem) + out;
    n = Math.floor(n / 26) - 1;
    if (n < 0) break;
  }
  return out;
}

/**
 * Convert an A1 column-letter sequence to its 0-based index. Returns `-1`
 * for invalid input (empty string, non-letters).
 */
export function columnLettersToIndex(letters: string): number {
  if (letters.length === 0) return -1;
  let n = 0;
  for (let i = 0; i < letters.length; i++) {
    const code = letters.charCodeAt(i);
    const upper = code >= 97 && code <= 122 ? code - 32 : code;
    if (upper < 65 || upper > 90) return -1;
    n = n * 26 + (upper - 64);
  }
  return n - 1;
}

// ─── Field-name helpers ─────────────────────────────────────────────────────

/** Fields that don't need quoting inside `COLUMN("…")` storage form. */
const BARE_FIELD_RE = /^[A-Za-z_][A-Za-z0-9_]*$/;

/** Quote a field name when it contains characters outside the bare set. */
export function formatField(field: string): string {
  if (BARE_FIELD_RE.test(field)) return field;
  return `"${field.replace(/"/g, '""')}"`;
}

// ─── Ref formatters (A1 + long-form) ────────────────────────────────────────

/**
 * Render a structured ref as A1 notation using the column order from the
 * current grid context. Returns `#REF!` when the field is not visible.
 * Same-row refs render as `[field]` surface shorthand.
 */
export function cellRefToA1(ref: StructuredRef, fieldOrder: readonly string[]): string {
  const idx = fieldOrder.indexOf(ref.field);
  if (idx < 0) return '#REF!';
  if (ref.sameRow) return `[${ref.field}]`;
  const col = columnIndexToLetters(idx);
  return `${ref.absField ? '$' : ''}${col}${ref.absRow ? '$' : ''}${ref.row}`;
}

/**
 * Render a structured ref as the long-form storage string. Same-row refs
 * omit the ROW argument entirely (`REF(COLUMN("field"))`), which is the
 * signal consumed by the parser and the ref-mapper to resolve against the
 * host cell's row at evaluation time.
 */
export function cellRefToLongForm(ref: StructuredRef): string {
  const field = ref.field.replace(/"/g, '""');
  if (ref.sameRow) return `REF(COLUMN("${field}"))`;
  return `REF(COLUMN("${field}"),ROW(${ref.row}))`;
}

import { Directive, TemplateRef, inject, input } from '@angular/core';

/**
 * Discriminator for the empty-state context.
 * - `no-data`     : the source dataset is empty (no rows ever loaded).
 * - `no-results`  : the dataset is non-empty but the active filter / search
 *                   produced zero rows.
 *
 * A template registered without an explicit kind defaults to `no-data` and
 * is also used as the fallback when `no-results` has no dedicated template.
 */
export type GridEmptyKind = 'no-data' | 'no-results';

/**
 * Marks a `<ng-template>` projected into `<ad-grid-angular>` as the renderer for
 * the empty state. Register one or two templates:
 *
 * ```html
 * <ad-grid-angular [data]="rows">
 *   <ng-template mozGridEmptyDef>
 *     <p>Aucune donnée pour le moment</p>
 *   </ng-template>
 *
 *   <ng-template mozGridEmptyDef="no-results" let-ctx>
 *     <p>Aucun résultat pour vos filtres ({{ ctx.activeFilterCount }})</p>
 *     <button (click)="ctx.clearFilters()">Réinitialiser</button>
 *   </ng-template>
 * </ad-grid-angular>
 * ```
 *
 * The implicit context (`let-ctx`) exposes `{ activeFilterCount, clearFilters }`.
 */
@Directive({
  selector: '[mozGridEmptyDef]',
})
export class AdeoGridEmptyDef {
  readonly kind = input<GridEmptyKind>('no-data', { alias: 'mozGridEmptyDef' });
  readonly template = inject<TemplateRef<GridEmptyContext>>(TemplateRef);
}

/** Context object passed to a `mozGridEmptyDef` template. */
export interface GridEmptyContext {
  /** Number of active filter conditions; `0` when called with `no-data`. */
  activeFilterCount: number;
  /** Convenience callback to clear all filter conditions. */
  clearFilters: () => void;
}

