import { Injectable, inject, signal, computed } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { GroupEntry } from '../models/grid-events.model';
import { DisplayRow, GroupRow } from '../models/display-row.model';

// ---------------------------------------------------------------------------
// Public contract types
// ---------------------------------------------------------------------------

export interface GroupSummary {
  /** Raw group value (the distinct field value). */
  value: unknown;
  /** Total number of rows in this group on the server. */
  count: number;
}

export interface ServerGroupingOptions<T = unknown> {
  /**
   * Fetch the list of distinct group values + counts for the given fields.
   * Called when group fields change.
   */
  fetchGroups: (fields: string[]) => Promise<GroupSummary[]>;

  /**
   * Fetch a slice of rows for a specific group value.
   * `start` and `end` are zero-based indices within the group.
   */
  fetchGroupRows: (
    field: string,
    value: unknown,
    start: number,
    end: number,
  ) => Promise<T[]>;

  /** Page size for lazy-loading rows within an expanded group. Default: 100. */
  pageSize?: number;
}

interface GroupCache<T> {
  rows: Array<T | null>;
  total: number;
  loaded: number;
  /** Pages already fetched or in-flight. */
  fetchedPages: Set<number>;
}

// ---------------------------------------------------------------------------
// Engine
// ---------------------------------------------------------------------------

@Injectable()
export class ServerGroupEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  // ── Configuration ────────────────────────────────────────────────────────

  /** Options provided by the consumer. When null, the engine is inactive. */
  private options: ServerGroupingOptions<T> | null = null;

  configure(opts: ServerGroupingOptions<T> | null): void {
    this.options = opts;
    if (!opts) {
      this.groupSummaries.set([]);
      this.expandedKeys.set(new Set());
      this.loadedGroups.set(new Map());
    }
  }

  // ── Local state ─────────────────────────────────────────────────────────

  /** Group field stack (mirrors `state.groupColumns` but owns server semantics). */
  readonly groupFields = computed<string[]>(() =>
    this.state.groupColumns().map((g) => g.field),
  );

  /** Whether the engine is active (options configured + at least one field). */
  readonly active = computed(
    () => this.options !== null && this.groupFields().length > 0,
  );

  /** Server-provided group summaries (value + count). */
  readonly groupSummaries = signal<GroupSummary[]>([]);

  /** Set of group keys that are currently expanded. */
  readonly expandedKeys = signal<Set<string>>(new Set());

  /** Loaded row caches per group key. */
  readonly loadedGroups = signal<Map<string, GroupCache<T>>>(new Map());

  /** Set of group keys where a fetch is in flight. */
  readonly loadingGroups = signal<Set<string>>(new Set());

  /** `true` when the summary-level fetch is in flight. */
  readonly isFetchingSummaries = signal(false);

  /** `true` when any group-level fetch is in flight. */
  readonly isLoading = computed(
    () =>
      this.isFetchingSummaries() ||
      this.loadingGroups().size > 0,
  );

  private _pageSize(): number {
    return this.options?.pageSize ?? 100;
  }

  // ── Group field management (mirrors GroupEngine API) ─────────────────────

  addGroup(field: string): void {
    const current = this.state.groupColumns();
    if (current.some((g) => g.field === field)) return;
    this.state.groupColumns.set([...current, { field, sortDirection: 'asc' }]);
    this.fetchGroupSummaries();
  }

  removeGroup(field: string): void {
    this.state.groupColumns.update((cols) => cols.filter((g) => g.field !== field));
    // Clean expanded state for this field.
    this.expandedKeys.update((keys) => {
      const next = new Set(keys);
      for (const key of next) {
        if (key.includes(`${field}::`)) next.delete(key);
      }
      return next;
    });
    this.fetchGroupSummaries();
  }

  clearGroups(): void {
    this.state.groupColumns.set([]);
    this.groupSummaries.set([]);
    this.expandedKeys.set(new Set());
    this.loadedGroups.set(new Map());
  }

  applyGroups(groups: GroupEntry[]): void {
    this.state.groupColumns.set(groups);
    this.fetchGroupSummaries();
  }

  // ── Summary fetch ────────────────────────────────────────────────────────

  async fetchGroupSummaries(): Promise<void> {
    const opts = this.options;
    const fields = this.groupFields();
    if (!opts || fields.length === 0) {
      this.groupSummaries.set([]);
      return;
    }

    this.isFetchingSummaries.set(true);
    try {
      const summaries = await opts.fetchGroups(fields);
      this.groupSummaries.set(summaries);
      // Reset expand / cache state on new summary fetch.
      this.expandedKeys.set(new Set());
      this.loadedGroups.set(new Map());
    } finally {
      this.isFetchingSummaries.set(false);
    }
  }

  // ── Expand / collapse ────────────────────────────────────────────────────

  toggleGroupExpand(groupKey: string): void {
    this.expandedKeys.update((keys) => {
      const next = new Set(keys);
      if (next.has(groupKey)) {
        next.delete(groupKey);
      } else {
        next.add(groupKey);
        // Trigger initial row fetch for this group if not cached.
        const field = this.groupFields()[0];
        const summary = this.groupSummaries().find(
          (s) => this._buildKey(field!, s.value) === groupKey,
        );
        if (summary && field && !this.loadedGroups().has(groupKey)) {
          this.expandGroupServer(groupKey, field, summary.value, summary.count, 0);
        }
      }
      return next;
    });
  }

  isGroupExpanded(groupKey: string): boolean {
    return this.expandedKeys().has(groupKey);
  }

  // ── Server fetch of rows within an expanded group ────────────────────────

  /**
   * Fetches page `page` of rows for `groupKey`. No-op if already fetched or
   * no options are configured.
   */
  async expandGroupServer(
    groupKey: string,
    field: string,
    value: unknown,
    total: number,
    page: number,
  ): Promise<void> {
    const opts = this.options;
    if (!opts) return;

    // Initialise the cache entry if needed.
    const existingMap = this.loadedGroups();
    let cache = existingMap.get(groupKey);
    if (!cache) {
      cache = { rows: [], total, loaded: 0, fetchedPages: new Set() };
      const next = new Map(existingMap);
      next.set(groupKey, cache);
      this.loadedGroups.set(next);
    }

    if (cache.fetchedPages.has(page)) return;
    cache.fetchedPages.add(page);

    const ps = this._pageSize();
    const start = page * ps;
    const end = Math.min(start + ps, total);

    this.loadingGroups.update((s) => new Set([...s, groupKey]));

    try {
      const fetched = await opts.fetchGroupRows(field, value, start, end);
      this.loadedGroups.update((map) => {
        const updated = new Map(map);
        const existing = updated.get(groupKey);
        if (!existing) return updated;
        const rows = [...existing.rows];
        // Ensure array is long enough.
        while (rows.length < end) rows.push(null);
        for (let i = 0; i < fetched.length; i++) {
          rows[start + i] = fetched[i] ?? null;
        }
        updated.set(groupKey, {
          ...existing,
          rows,
          loaded: rows.filter((r) => r !== null).length,
        });
        return updated;
      });
    } finally {
      this.loadingGroups.update((s) => {
        const next = new Set(s);
        next.delete(groupKey);
        return next;
      });
    }
  }

  // ── Flat renderable rows ─────────────────────────────────────────────────

  /**
   * Flat list of rows ready for virtual scroll, typed as `DisplayRow<T>[]` so
   * `GridEngine.displayRows` can consume it without a cast.
   *
   * - Group header rows become `{ type: 'group', group: GroupRow<T> }`.
   * - Loaded data rows become `{ type: 'data', data: T, index: number, depth: 1 }`.
   * - Skeleton/placeholder rows become `{ type: 'data', data: skeletonSentinel, ... }`
   *   where `skeletonSentinel` is a plain object that carries `__adgSkeleton: true`
   *   and the offset metadata needed by `onVisibleRangeChange`.
   */
  readonly flatRows = computed<DisplayRow<T>[]>(() => {
    if (!this.active()) return [];

    const fields = this.groupFields();
    const field = fields[0];
    if (!field) return [];

    const def = this.state.columnDefMap().get(field);
    const headerName = def?.headerName ?? field;
    const result: DisplayRow<T>[] = [];
    const summaries = this.groupSummaries();
    const expandedSet = this.expandedKeys();
    const loadedMap = this.loadedGroups();
    let dataIndex = 0;

    for (const summary of summaries) {
      const key = this._buildKey(field, summary.value);
      const isExpanded = expandedSet.has(key);

      // Build a GroupRow<T> for the group header.
      const groupRow: GroupRow<T> = {
        type: 'group',
        field,
        value: summary.value,
        displayValue: `${headerName}: ${String(summary.value ?? '')}`,
        depth: 0,
        count: summary.count,
        expanded: isExpanded,
        groupKey: key,
        children: [],
        parent: null,
      };

      result.push({ type: 'group', group: groupRow });

      if (!isExpanded) continue;

      const cache = loadedMap.get(key);
      if (!cache) {
        // Cache not ready — emit all-skeleton placeholder rows.
        for (let i = 0; i < summary.count; i++) {
          result.push({
            type: 'data',
            data: {
              __adgSkeleton: true,
              __adgGroupKey: key,
              __adgOffsetInGroup: i,
            } as unknown as T,
            index: dataIndex++,
            depth: 1,
          });
        }
        continue;
      }

      for (let i = 0; i < cache.total; i++) {
        const row = cache.rows[i];
        if (row !== null && row !== undefined) {
          result.push({ type: 'data', data: row, index: dataIndex++, depth: 1 });
        } else {
          result.push({
            type: 'data',
            data: {
              __adgSkeleton: true,
              __adgGroupKey: key,
              __adgOffsetInGroup: i,
            } as unknown as T,
            index: dataIndex++,
            depth: 1,
          });
        }
      }
    }

    return result;
  });

  // ── Lazy-load trigger ────────────────────────────────────────────────────

  /**
   * Called by the grid body when the visible range changes. Detects skeleton
   * rows inside expanded groups and fetches their pages on demand.
   */
  onVisibleRangeChange(startIdx: number, endIdx: number): void {
    const rows = this.flatRows();
    const ps = this._pageSize();
    const field = this.groupFields()[0];
    if (!field) return;

    for (let i = startIdx; i < endIdx && i < rows.length; i++) {
      const displayRow = rows[i];
      if (!displayRow || displayRow.type !== 'data') continue;
      const data = displayRow.data as Record<string, unknown>;
      if (!data || !data['__adgSkeleton'] || !data['__adgGroupKey']) continue;
      const key = String(data['__adgGroupKey']);
      const offset = Number(data['__adgOffsetInGroup'] ?? 0);
      const page = Math.floor(offset / ps);
      const summary = this.groupSummaries().find(
        (s) => this._buildKey(field, s.value) === key,
      );
      if (summary) {
        this.expandGroupServer(key, field, summary.value, summary.count, page);
      }
    }
  }

  // ── Private helpers ──────────────────────────────────────────────────────

  private _buildKey(field: string, value: unknown): string {
    return `${field}::${String(value ?? '')}`;
  }
}

import { TemplateRef, Type } from '@angular/core';
import { MozSelectOption } from '@mozaic-ds/angular';
import { CellError } from './cell.model';
import { FilterDataType, FilterOperator, FilterValue, AdeoGridCustomFilter } from './filter.model';

export type SortDirection = 'asc' | 'desc' | null;

export type CellEditorType =
  | 'text'
  | 'number'
  | 'textarea'
  | 'select'
  | 'checkbox'
  | 'date'
  | 'toggle'
  | 'custom';

export interface ColumnDef<T = unknown> {
  /** Unique column identifier */
  field: string;

  /** Display name in header */
  headerName?: string;

  /** Fixed width in px (e.g. '120px') */
  width?: string;

  /** Minimum width in px for resize */
  minWidth?: string;

  /** Maximum width in px for resize */
  maxWidth?: string;

  /** Flex grow factor (like CSS flex) */
  flex?: number;

  /** Whether column is sortable */
  sortable?: boolean;

  /** Custom sort comparator */
  sortComparator?: (a: T, b: T) => number;

  /** Whether column is resizable */
  resizable?: boolean;

  /** Whether column is reorderable */
  reorderable?: boolean;

  /** Whether column is groupable */
  groupable?: boolean;

  /** Whether column supports filtering */
  filterable?: boolean;

  /**
   * Filter data type. When omitted, it is derived from `cellEditor`:
   * `number → number`, `date → date`, `select → set`, anything else → `text`.
   */
  filterType?: FilterDataType;

  /** Allowed operators — subset of the defaults for `filterType`. Optional. */
  filterOperators?: FilterOperator[];

  /** Default operator used when a condition is created for this column. */
  defaultFilterOperator?: FilterOperator;

  /** For `set` filters: the options shown in the value picker. */
  filterOptions?: { value: unknown; label: string }[];

  /**
   * Whether column is pinned/frozen. Canonical values are `'start' | 'end'`,
   * but the Vue grid's `'left' | 'right'` aliases are also accepted and
   * normalized internally by `AdeoGridColumnDef` so consumers can share
   * column definitions verbatim between the two libraries.
   */
  pinned?: 'start' | 'end' | 'left' | 'right' | null;

  /** Whether column is visible */
  visible?: boolean;

  /** Whether column can be hidden via header menu */
  hideable?: boolean;

  /** Whether column can be frozen via header menu */
  freezable?: boolean;

  /** Whether the column header search (filter input) is visible */
  searchVisible?: boolean;

  /** Disable the header menu entirely for this column */
  headerMenuDisabled?: boolean;

  /** Cell value accessor (alternative to field for nested data) */
  valueGetter?: (row: T) => unknown;

  /** Cell value formatter for display */
  valueFormatter?: (value: unknown, row: T) => string;

  /** CSS class for column cells */
  cellClass?: string | ((row: T) => string);

  /** CSS class for header cell */
  headerClass?: string;

  /** Whether this column supports inline editing (double-click to edit) */
  editable?: boolean;

  /** Editor type — determines which Mozaic component is rendered in edit mode */
  cellEditor?: CellEditorType;

  /** Options for select editors (MozSelectOption[]) */
  cellEditorOptions?: MozSelectOption[];

  /** Custom validation before commit */
  cellEditorValidator?: (value: unknown, row: T) => boolean | string;

  /**
   * Custom cell template.
   *  - `TemplateRef<unknown>` — rendered with `ngTemplateOutlet` (classic slot).
   *  - `Type<unknown>`        — rendered as a standalone component via `ngComponentOutlet`.
   *
   * Consumers can write their own renderer factory that returns a
   * `Type<{ value }>` standalone component for richer behavior (status
   * badges, tags, …) — see `mrxgrid/src/app/renderers/` for examples.
   */
  cellTemplate?: TemplateRef<unknown> | Type<unknown>;

  /** Custom edit template */
  editTemplate?: TemplateRef<unknown>;

  /** Custom filter template rendered in the sub-header filter row */
  filterTemplate?: TemplateRef<unknown>;

  /**
   * Custom Angular component rendered as the value editor in the filter builder.
   * The component must extend `AdeoGridCustomFilter`.
   * Automatically sets filterType to 'custom'.
   */
  filterComponent?: Type<AdeoGridCustomFilter>;

  /**
   * Client-side predicate used when filterMode="client" and filterType is 'custom'.
   * If absent, custom conditions are silently skipped in client mode.
   */
  filterPredicate?: (row: T, value: FilterValue) => boolean;

  /**
   * Determines whether a custom filter condition is "complete" (has enough data
   * to participate in evaluation). Defaults to value.value != null && !== ''.
   */
  filterIsComplete?: (value: FilterValue) => boolean;

  /** Validation function for cell values. Returns CellError or null. */
  cellValidator?: (value: unknown, row: T) => CellError | null;

  /**
   * Enables spreadsheet-style formulas for this column. Setting this to
   * `true` implies `editable: true` (users need to type the formula). When
   * the committed value starts with `=`, it is routed to the `FormulaEngine`
   * and the evaluated result is rendered in place of the raw formula text.
   *
   * Requires the grid-level `formulas` input to be `true` and the row to
   * expose a stable id via `rowIdField`.
   */
  allowFormula?: boolean;
}

export interface ColumnStateEntry {
  field: string;
  currentWidth: number;
  order: number;
  visible: boolean;
  sort: SortDirection;
  sortIndex: number | null;
  pinned: 'start' | 'end' | null;
  searchVisible: boolean;
}

export interface ColumnResizeEvent {
  field: string;
  previousWidth: number;
  newWidth: number;
}

export interface ColumnReorderEvent {
  field: string;
  previousIndex: number;
  newIndex: number;
  columns: string[];
}

export interface ColumnFreezeEvent {
  field: string;
  side: 'start' | 'end' | null;
  frozenLeftColumns: string[];
  frozenRightColumns: string[];
}

export interface ColumnVisibilityEvent {
  field: string;
  visible: boolean;
  visibleColumns: string[];
}

export interface ColumnSearchToggleEvent {
  field: string;
  searchVisible: boolean;
}

export type HeaderMenuActionId =
  | 'sort-asc'
  | 'sort-desc'
  | 'filter-column'
  | 'group-column'
  | 'freeze-column-left'
  | 'freeze-column-right'
  | 'unfreeze-column'
  | 'hide-column'
  | 'toggle-column-search'
  | 'autosize-this'
  | 'autosize-all';

export interface HeaderMenuConfig {
  field: string;
  columnIndex: number;
  headerName: string;
  sortable: boolean;
  filterable: boolean;
  groupable: boolean;
  freezable: boolean;
  hideable: boolean;
  searchVisible: boolean;
  currentSort: SortDirection;
}

import { Injectable, computed, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { CellRange } from '../models/cell.model';
import { GridEngine } from '../engine/grid-engine';
import { shiftFormulaRefs } from './formula/formula-shift';

export const PASTE_SKIP = Symbol('PASTE_SKIP');

export interface HistoryCellChange {
  rowIndex: number;
  field: string;
  before: unknown;
  after: unknown;
}

/**
 * Applies a set of cell-level mutations to sourceData and returns the list of
 * actual changes that occurred, so the caller (usually the history engine) can
 * record them. `PASTE_SKIP` return values are filtered out transparently.
 */
@Injectable()
export class ClipboardEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);
  private readonly gridEngine = inject<GridEngine<T>>(GridEngine);

  /** Derived by components (marching-ants outline). */
  readonly cutRange = computed(() => this.state.cutSource());

  /**
   * Maps every display row index inside `range` to its actual sourceData
   * index. Unknown indices (e.g. outside the current page) are skipped so
   * callers can safely iterate only over rows that exist in sourceData.
   */
  private resolveRangeSourceIndices(range: CellRange): number[] {
    const out: number[] = [];
    for (let r = range.start.row; r <= range.end.row; r++) {
      const srcIdx = this.gridEngine.displayIndexToSourceIndex(r);
      if (srcIdx >= 0) out.push(srcIdx);
    }
    return out;
  }

  /**
   * Like {@link resolveRangeSourceIndices} but also keeps each row's display
   * position. Needed by formula-aware fills, where the shift applied to
   * relative refs is driven by the *display* row delta (column axis is named,
   * so field references never rewrite on horizontal fill).
   */
  private resolveRangeWithDisplay(range: CellRange): { display: number; source: number }[] {
    const out: { display: number; source: number }[] = [];
    for (let r = range.start.row; r <= range.end.row; r++) {
      const srcIdx = this.gridEngine.displayIndexToSourceIndex(r);
      if (srcIdx >= 0) out.push({ display: r, source: srcIdx });
    }
    return out;
  }

  /**
   * Shifts the relative refs of a spreadsheet-style formula when the value
   * is being dropped on a different row/column during a fill operation.
   * Non-formula values (anything that doesn't start with `=`) are returned
   * as-is, so downstream coercion still runs over the raw string.
   */
  private shiftIfFormula(value: unknown, allowFormula: boolean, rowDelta: number, colDelta: number): unknown {
    if (!allowFormula) return value;
    if (typeof value !== 'string') return value;
    if (!value.trimStart().startsWith('=')) return value;
    if (rowDelta === 0 && colDelta === 0) return value;
    const fieldOrder = this.state.visibleColumns().map((c) => c.field);
    return shiftFormulaRefs(value, { rowDelta, colDelta, fieldOrder });
  }

  markCut(range: CellRange): void {
    this.state.cutSource.set(range);
  }

  clearCut(): void {
    this.state.cutSource.set(null);
  }

  // ── B21 — Series detection for fill handle ────────────────────────────

  private detectSeries(sourceValues: unknown[]): { type: 'number' | 'date'; step: number; base: number } | null {
    if (sourceValues.length < 2) return null;

    const allNumbers = sourceValues.every((v) => typeof v === 'number' && isFinite(v as number));
    if (allNumbers) {
      const nums = sourceValues as number[];
      const step = nums[1]! - nums[0]!;
      const isArithmetic = nums.every((v, i) => i === 0 || Math.abs(v - nums[i - 1]! - step) < 1e-9);
      if (isArithmetic) return { type: 'number', step, base: nums[nums.length - 1]! };
    }

    const parsedDates = sourceValues.map((v) => {
      if (v instanceof Date) return v.getTime();
      if (typeof v === 'string') { const t = Date.parse(v); return isNaN(t) ? null : t; }
      return null;
    });
    if (parsedDates.every((t) => t !== null)) {
      const timestamps = parsedDates as number[];
      const step = timestamps[1]! - timestamps[0]!;
      const isArithmetic = timestamps.every((t, i) => i === 0 || Math.abs(t - timestamps[i - 1]! - step) < 1);
      if (isArithmetic) return { type: 'date', step, base: timestamps[timestamps.length - 1]! };
    }
    return null;
  }

  private projectSeries(series: { type: 'number' | 'date'; step: number; base: number }, offset: number): unknown {
    if (series.type === 'number') return series.base + series.step * offset;
    return new Date(series.base + series.step * offset).toISOString().slice(0, 10);
  }

  /** Vertical fill: row 0 of the range is the source, subsequent rows are targets. */
  fillDown(range: CellRange): HistoryCellChange[] {
    if (range.start.row === range.end.row) return [];
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const changes: HistoryCellChange[] = [];
    const rows = this.resolveRangeWithDisplay(range);
    if (rows.length < 2) return [];
    const [source, ...targets] = rows;

    this.state.sourceData.update((data) => {
      const updated = [...data];
      const sourceRow = updated[source.source];
      if (!sourceRow) return updated;

      // B21: pre-compute series per column from the entire range's source rows.
      const seriesMap = new Map<string, ReturnType<typeof this.detectSeries>>();
      const allRows = [source, ...targets];
      for (let c = range.start.col; c <= range.end.col; c++) {
        const field = cols[c]?.field;
        if (!field) continue;
        const def = defMap.get(field);
        if (!def?.editable) continue;
        // Collect values from all-but-last rows as "source" values for series
        // detection. Using allRows.slice(0, -1) means [source, ...targets.slice(0, -1)]
        // so a range like [1, 2] → fill 5 rows detects step=1 → projects 3,4,5,6,7.
        const sourceRows = allRows.slice(0, -1);
        const vals = sourceRows.map(({ source: si }) => {
          const r = updated[si];
          if (!r) return undefined;
          return def.valueGetter ? def.valueGetter(r) : (r as Record<string, unknown>)[field];
        }).filter((v) => v !== undefined);
        seriesMap.set(field, this.detectSeries(vals));
      }

      for (const target of targets) {
        if (!updated[target.source]) continue;
        const rowCopy = { ...updated[target.source] } as Record<string, unknown>;
        let changed = false;
        const rowDelta = target.display - source.display;
        for (let c = range.start.col; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const sourceValue = def.valueGetter
            ? def.valueGetter(sourceRow)
            : (sourceRow as Record<string, unknown>)[field];
          const series = seriesMap.get(field) ?? null;
          const fillValue = series
            ? this.projectSeries(series, rowDelta)
            : this.shiftIfFormula(sourceValue, def.allowFormula === true, rowDelta, 0);
          const coerced = this.coerceAndValidate(field, fillValue, updated[target.source]);
          if (coerced === PASTE_SKIP) continue;
          const before = (updated[target.source] as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: target.source, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[target.source] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Horizontal fill: col 0 of the range is the source, subsequent cols are targets. */
  fillRight(range: CellRange): HistoryCellChange[] {
    if (range.start.col === range.end.col) return [];
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const sourceField = cols[range.start.col]?.field;
    if (!sourceField) return [];
    const sourceDef = defMap.get(sourceField);
    if (!sourceDef) return [];
    const changes: HistoryCellChange[] = [];

    const sourceIndices = this.resolveRangeSourceIndices(range);
    this.state.sourceData.update((data) => {
      const updated = [...data];
      for (const sourceIdx of sourceIndices) {
        const row = updated[sourceIdx];
        if (!row) continue;

        // B21: collect source values across all columns (except last) for series detection.
        const sourceColValues: unknown[] = [];
        for (let c = range.start.col; c < range.end.col; c++) {
          const f = cols[c]?.field;
          if (!f) break;
          const d = defMap.get(f);
          sourceColValues.push(d?.valueGetter ? d.valueGetter(row) : (row as Record<string, unknown>)[f]);
        }
        const series = this.detectSeries(sourceColValues);

        const sourceValue = sourceDef.valueGetter
          ? sourceDef.valueGetter(row)
          : (row as Record<string, unknown>)[sourceField];
        const rowCopy = { ...row } as Record<string, unknown>;
        let changed = false;
        for (let c = range.start.col + 1; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const colDelta = c - range.start.col;
          const fillValue = series
            ? this.projectSeries(series, colDelta)
            : this.shiftIfFormula(sourceValue, def.allowFormula === true, 0, colDelta);
          const coerced = this.coerceAndValidate(field, fillValue, row);
          if (coerced === PASTE_SKIP) continue;
          const before = (row as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[sourceIdx] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Ctrl+Enter: write `value` into every editable cell of `range`. */
  fillSelection(range: CellRange, value: unknown): HistoryCellChange[] {
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const changes: HistoryCellChange[] = [];
    const sourceIndices = this.resolveRangeSourceIndices(range);

    this.state.sourceData.update((data) => {
      const updated = [...data];
      for (const sourceIdx of sourceIndices) {
        const row = updated[sourceIdx];
        if (!row) continue;
        const rowCopy = { ...row } as Record<string, unknown>;
        let changed = false;
        for (let c = range.start.col; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const coerced = this.coerceAndValidate(field, value, row);
          if (coerced === PASTE_SKIP) continue;
          const before = (row as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[sourceIdx] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Clears every editable cell in `range` and returns the undo payload. */
  clearRange(range: CellRange): HistoryCellChange[] {
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const changes: HistoryCellChange[] = [];
    const sourceIndices = this.resolveRangeSourceIndices(range);

    this.state.sourceData.update((data) => {
      const updated = [...data];
      for (const sourceIdx of sourceIndices) {
        const row = updated[sourceIdx];
        if (!row) continue;
        const rowCopy = { ...row } as Record<string, unknown>;
        let changed = false;
        for (let c = range.start.col; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const coerced = this.coerceAndValidate(field, null, row);
          if (coerced === PASTE_SKIP) continue;
          const before = (row as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[sourceIdx] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Applies TSV `pasteRows` starting at `range.start`, returning actual changes.
   *  B20 — Excel-style tile: when the selection dimensions are integer multiples
   *  of the source block (or the source is 1×1), the source block is tiled to
   *  fill the whole selection. Otherwise pastes the block as-is. */
  applyPaste(range: CellRange, pasteRows: string[][]): HistoryCellChange[] {
    const cols = this.state.visibleColumns();
    const changes: HistoryCellChange[] = [];

    const selRows = range.end.row - range.start.row + 1;
    const selCols = range.end.col - range.start.col + 1;
    const srcRows = pasteRows.length;
    const srcCols = Math.max(...pasteRows.map((r) => r.length), 1);

    const tileRow = srcRows === 1 || selRows % srcRows === 0;
    const tileCol = srcCols === 1 || selCols % srcCols === 0;
    const shouldTile = tileRow && tileCol && (srcRows > 1 || srcCols > 1 || (pasteRows[0]?.length ?? 0) === 1);

    this.state.sourceData.update((data) => {
      const updated = [...data];

      if (shouldTile) {
        for (let dr = 0; dr < selRows; dr++) {
          const targetDisplayRow = range.start.row + dr;
          const sourceIdx = this.gridEngine.displayIndexToSourceIndex(targetDisplayRow);
          if (sourceIdx < 0) continue;
          const row = updated[sourceIdx];
          if (!row) continue;
          const pasteRow = pasteRows[dr % srcRows];
          if (!pasteRow) continue;
          const rowCopy = { ...row } as Record<string, unknown>;
          let changed = false;
          for (let dc = 0; dc < selCols; dc++) {
            const targetCol = range.start.col + dc;
            if (targetCol >= cols.length) break;
            const field = cols[targetCol]?.field;
            if (!field) continue;
            const cellVal = pasteRow[dc % srcCols] ?? '';
            const coerced = this.coerceAndValidate(field, cellVal, row);
            if (coerced === PASTE_SKIP) continue;
            const before = (row as Record<string, unknown>)[field];
            if (before === coerced) continue;
            rowCopy[field] = coerced;
            changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
            changed = true;
          }
          if (changed) updated[sourceIdx] = rowCopy as T;
        }
      } else {
        for (let ri = 0; ri < pasteRows.length; ri++) {
          const targetDisplayRow = range.start.row + ri;
          const sourceIdx = this.gridEngine.displayIndexToSourceIndex(targetDisplayRow);
          if (sourceIdx < 0) continue;
          const row = updated[sourceIdx];
          if (!row) continue;
          const rowCopy = { ...row } as Record<string, unknown>;
          let changed = false;
          for (let ci = 0; ci < pasteRows[ri].length; ci++) {
            const targetCol = range.start.col + ci;
            if (targetCol >= cols.length) break;
            const field = cols[targetCol]?.field;
            if (!field) continue;
            const coerced = this.coerceAndValidate(field, pasteRows[ri][ci], row);
            if (coerced === PASTE_SKIP) continue;
            const before = (row as Record<string, unknown>)[field];
            if (before === coerced) continue;
            rowCopy[field] = coerced;
            changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
            changed = true;
          }
          if (changed) updated[sourceIdx] = rowCopy as T;
        }
      }

      return updated;
    });

    return changes;
  }

  /**
   * Reverses a previously-recorded list of changes by writing `before` back into
   * the cells. Used by the history engine for both undo and redo.
   */
  applyChanges(changes: HistoryCellChange[], direction: 'before' | 'after'): void {
    if (changes.length === 0) return;
    this.state.sourceData.update((data) => {
      const updated = [...data];
      // Group changes by rowIndex so each row is cloned once.
      const byRow = new Map<number, HistoryCellChange[]>();
      for (const change of changes) {
        const list = byRow.get(change.rowIndex) ?? [];
        list.push(change);
        byRow.set(change.rowIndex, list);
      }
      for (const [rowIndex, rowChanges] of byRow) {
        const row = updated[rowIndex];
        if (!row) continue;
        const rowCopy = { ...row } as Record<string, unknown>;
        for (const change of rowChanges) {
          rowCopy[change.field] = direction === 'before' ? change.before : change.after;
        }
        updated[rowIndex] = rowCopy as T;
      }
      return updated;
    });
  }

  /**
   * Coerces a raw value (string from TSV, unknown from fill, null for clears)
   * into the editor's expected type, running the field's validator when present.
   * Returns PASTE_SKIP when the column isn't editable or the value is rejected.
   */
  coerceAndValidate(field: string, rawValue: unknown, row: T): unknown {
    const def = this.state.columnDefMap().get(field);
    if (!def?.editable) return PASTE_SKIP;

    const editorType = def.cellEditor;

    if (rawValue === null) {
      let clearValue: unknown;
      switch (editorType) {
        case 'number':
          clearValue = null;
          break;
        case 'checkbox':
          clearValue = false;
          break;
        default:
          clearValue = '';
      }
      if (def.cellEditorValidator) {
        const result = def.cellEditorValidator(clearValue, row);
        if (result === false || typeof result === 'string') return PASTE_SKIP;
      }
      return clearValue;
    }

    let value: unknown = rawValue;

    if (editorType === 'number') {
      const num = Number(rawValue);
      if (isNaN(num)) return PASTE_SKIP;
      value = num;
    } else if (editorType === 'checkbox') {
      if (rawValue === 'true' || rawValue === true) {
        value = true;
      } else if (rawValue === 'false' || rawValue === false) {
        value = false;
      } else {
        return PASTE_SKIP;
      }
    } else if (
      (editorType === 'select' || editorType === 'custom') &&
      def.cellEditorOptions?.length
    ) {
      // Whitelist clipboard values against the declared allowed set. Applies
      // to both the built-in `select` editor and `custom` editors that expose
      // a constrained option list (combobox, pill-picker, …).
      const allowed = def.cellEditorOptions.map((o) => String(o.value));
      if (!allowed.includes(String(rawValue))) return PASTE_SKIP;
      value = rawValue;
    }

    if (def.cellEditorValidator) {
      const result = def.cellEditorValidator(value, row);
      if (result === false || typeof result === 'string') return PASTE_SKIP;
    }

    return value;
  }

  // ── B19 — RFC-4180 TSV escape / unescape ─────────────────────────────

  private escapeTsvCell(v: unknown): string {
    const s = v == null ? '' : String(v);
    if (s.includes('\t') || s.includes('\n') || s.includes('"')) {
      return '"' + s.replace(/"/g, '""') + '"';
    }
    return s;
  }

  /**
   * Parses a single TSV row string into cells, handling RFC-4180 quoted fields
   * that may contain embedded tabs, newlines, or double-quote pairs.
   */
  parseTsvRow(line: string): string[] {
    const cells: string[] = [];
    let i = 0;
    while (i <= line.length) {
      if (line[i] === '"') {
        i++;
        let cell = '';
        while (i < line.length) {
          if (line[i] === '"') {
            if (line[i + 1] === '"') {
              cell += '"';
              i += 2;
            } else {
              i++;
              break;
            }
          } else {
            cell += line[i++];
          }
        }
        cells.push(cell);
        if (line[i] === '\t') i++;
      } else {
        const end = line.indexOf('\t', i);
        if (end === -1) {
          cells.push(line.slice(i));
          break;
        } else {
          cells.push(line.slice(i, end));
          i = end + 1;
        }
      }
    }
    return cells;
  }

  /** TSV string for a range — used by copy / cut.
   *  B19: cells are RFC-4180 escaped so tab/newline/quote in values don't corrupt the TSV. */
  extractTsv(range: CellRange): string[][] {
    const cols = this.state.visibleColumns();
    const data = this.state.sourceData();
    const defMap = this.state.columnDefMap();
    const values: string[][] = [];

    for (let r = range.start.row; r <= range.end.row; r++) {
      const row = data[r];
      if (!row) continue;
      const rowValues: string[] = [];
      for (let c = range.start.col; c <= range.end.col; c++) {
        const field = cols[c]?.field;
        if (!field) {
          rowValues.push('');
          continue;
        }
        const def = defMap.get(field);
        const val = def?.valueGetter
          ? def.valueGetter(row)
          : (row as Record<string, unknown>)[field];
        rowValues.push(this.escapeTsvCell(val));
      }
      values.push(rowValues);
    }
    return values;
  }

  /**
   * Checks whether a cell sits on any edge of the current cut outline. Four
   * booleans rather than a single "isCut" so the view can paint only the edges
   * that face outward — which is what produces the Excel-like marching ants.
   */
  cutEdges(
    row: number,
    col: number
  ): { top: boolean; right: boolean; bottom: boolean; left: boolean; any: boolean } {
    const cut = this.state.cutSource();
    if (!cut) return { top: false, right: false, bottom: false, left: false, any: false };
    const minRow = Math.min(cut.start.row, cut.end.row);
    const maxRow = Math.max(cut.start.row, cut.end.row);
    const minCol = Math.min(cut.start.col, cut.end.col);
    const maxCol = Math.max(cut.start.col, cut.end.col);
    if (row < minRow || row > maxRow || col < minCol || col > maxCol) {
      return { top: false, right: false, bottom: false, left: false, any: false };
    }
    return {
      top: row === minRow,
      right: col === maxCol,
      bottom: row === maxRow,
      left: col === minCol,
      any: true,
    };
  }
}

import { Injectable, computed, inject, signal } from '@angular/core';
import { ClipboardEngine, HistoryCellChange } from './clipboard.engine';

export type HistoryOpType = 'edit' | 'paste' | 'cut' | 'fill' | 'delete' | 'fill-down' | 'fill-right' | 'fill-selection';

export interface HistoryOp {
  type: HistoryOpType;
  changes: HistoryCellChange[];
  timestamp: number;
}

const MAX_HISTORY = 50;
const STORAGE_PREFIX = 'adeo-grid-history:';

@Injectable()
export class HistoryEngine<T = unknown> {
  private readonly clipboard = inject<ClipboardEngine<T>>(ClipboardEngine);

  private readonly past = signal<HistoryOp[]>([]);
  private readonly future = signal<HistoryOp[]>([]);
  private storageKey: string | null = null;

  readonly canUndo = computed(() => this.past().length > 0);
  readonly canRedo = computed(() => this.future().length > 0);

  /**
   * Binds a persistence key: all record/undo/redo calls will mirror the stacks
   * to localStorage, and past state is restored on bind. Pass null to detach.
   */
  attach(gridId: string | null): void {
    this.storageKey = gridId ? `${STORAGE_PREFIX}${gridId}` : null;
    if (!this.storageKey) {
      this.past.set([]);
      this.future.set([]);
      return;
    }
    this.restore();
  }

  /** Records a new mutation. Clears the redo stack (standard undo semantics). */
  record(type: HistoryOpType, changes: HistoryCellChange[]): void {
    if (changes.length === 0) return;
    const op: HistoryOp = { type, changes, timestamp: Date.now() };
    this.past.update((stack) => {
      const next = [...stack, op];
      return next.length > MAX_HISTORY ? next.slice(next.length - MAX_HISTORY) : next;
    });
    this.future.set([]);
    this.persist();
  }

  undo(): HistoryOp | null {
    const stack = this.past();
    if (stack.length === 0) return null;
    const op = stack[stack.length - 1];
    this.clipboard.applyChanges(op.changes, 'before');
    this.past.set(stack.slice(0, -1));
    this.future.update((f) => [...f, op]);
    this.persist();
    return op;
  }

  redo(): HistoryOp | null {
    const stack = this.future();
    if (stack.length === 0) return null;
    const op = stack[stack.length - 1];
    this.clipboard.applyChanges(op.changes, 'after');
    this.future.set(stack.slice(0, -1));
    this.past.update((p) => [...p, op]);
    this.persist();
    return op;
  }

  clear(): void {
    this.past.set([]);
    this.future.set([]);
    if (this.storageKey) {
      try {
        localStorage.removeItem(this.storageKey);
      } catch {
        // Storage unavailable (private mode, quota) — non-fatal.
      }
    }
  }

  private persist(): void {
    if (!this.storageKey) return;
    try {
      const payload = JSON.stringify({
        past: this.past(),
        future: this.future(),
      });
      localStorage.setItem(this.storageKey, payload);
    } catch {
      // Quota exceeded or storage disabled — we silently drop persistence.
    }
  }

  private restore(): void {
    if (!this.storageKey) return;
    try {
      const raw = localStorage.getItem(this.storageKey);
      if (!raw) {
        this.past.set([]);
        this.future.set([]);
        return;
      }
      const parsed = JSON.parse(raw) as { past?: HistoryOp[]; future?: HistoryOp[] };
      this.past.set(Array.isArray(parsed.past) ? parsed.past : []);
      this.future.set(Array.isArray(parsed.future) ? parsed.future : []);
    } catch {
      this.past.set([]);
      this.future.set([]);
    }
  }
}

