import {
  BinaryOp,
  FormulaAst,
  StructuredRef,
  UnaryOp,
} from './formula-ast';

export type ParserLocale = 'en' | 'fr';

export interface ParseOptions {
  readonly locale?: ParserLocale;
  /** Maximum parse depth, guarding against pathological nesting. */
  readonly maxDepth?: number;
}

export class FormulaParseError extends Error {
  constructor(
    message: string,
    /** 0-based column in the source string. */
    readonly position: number,
  ) {
    super(message);
    this.name = 'FormulaParseError';
  }
}

// ─── Token types ────────────────────────────────────────────────────────────

type TokenType =
  | 'number'
  | 'string'
  | 'bool'
  | 'ident'
  | 'lparen'
  | 'rparen'
  | 'comma'
  | 'colon'
  | 'op'
  | 'eof';

interface Token {
  readonly type: TokenType;
  readonly value: string;
  readonly position: number;
}

// ─── Public entry point ─────────────────────────────────────────────────────

/**
 * Parse a formula source string into an AST. Accepts either form with or
 * without a leading `=`. Throws `FormulaParseError` on malformed input —
 * callers should translate that into a `#PARSE!` error value.
 */
export function parseFormula(source: string, options: ParseOptions = {}): FormulaAst {
  const locale = options.locale ?? 'en';
  const maxDepth = options.maxDepth ?? 256;
  const body = source.startsWith('=') ? source.slice(1) : source;
  const tokens = tokenize(body, locale);
  const parser = new RecursiveDescent(tokens, maxDepth);
  const ast = parser.parseExpression();
  parser.expect('eof');
  return ast;
}

// ─── Tokenizer ──────────────────────────────────────────────────────────────

function tokenize(source: string, locale: ParserLocale): Token[] {
  const tokens: Token[] = [];
  const argSeparator = locale === 'fr' ? ';' : ',';
  let i = 0;
  const len = source.length;

  while (i < len) {
    const ch = source[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i++;
      continue;
    }

    if (ch === '(') {
      tokens.push({ type: 'lparen', value: '(', position: i });
      i++;
      continue;
    }
    if (ch === ')') {
      tokens.push({ type: 'rparen', value: ')', position: i });
      i++;
      continue;
    }
    if (ch === argSeparator) {
      tokens.push({ type: 'comma', value: argSeparator, position: i });
      i++;
      continue;
    }
    if (ch === ':') {
      tokens.push({ type: 'colon', value: ':', position: i });
      i++;
      continue;
    }

    const twoChar = source.slice(i, i + 2);
    if (twoChar === '<=' || twoChar === '>=' || twoChar === '<>') {
      tokens.push({ type: 'op', value: twoChar, position: i });
      i += 2;
      continue;
    }
    if ('+-*/^&=<>'.includes(ch)) {
      tokens.push({ type: 'op', value: ch, position: i });
      i++;
      continue;
    }

    if (ch === '"') {
      const parsed = scanQuotedString(source, i);
      tokens.push({ type: 'string', value: parsed.value, position: i });
      i = parsed.end;
      continue;
    }

    if (isDigit(ch) || (ch === '.' && isDigit(source[i + 1] ?? ''))) {
      const start = i;
      let seenDot = ch === '.';
      let seenExp = false;
      i++;
      while (i < len) {
        const c = source[i];
        if (isDigit(c)) {
          i++;
          continue;
        }
        if (c === '.' && !seenDot && !seenExp) {
          seenDot = true;
          i++;
          continue;
        }
        if ((c === 'e' || c === 'E') && !seenExp) {
          seenExp = true;
          i++;
          if (source[i] === '+' || source[i] === '-') i++;
          continue;
        }
        break;
      }
      tokens.push({ type: 'number', value: source.slice(start, i), position: start });
      continue;
    }

    if (isAlpha(ch) || ch === '_') {
      const start = i;
      while (i < len && (isAlpha(source[i]) || isDigit(source[i]) || source[i] === '_' || source[i] === '.')) {
        i++;
      }
      const value = source.slice(start, i);
      const upper = value.toUpperCase();
      if (upper === 'TRUE' || upper === 'FALSE') {
        tokens.push({ type: 'bool', value: upper, position: start });
      } else {
        tokens.push({ type: 'ident', value, position: start });
      }
      continue;
    }

    throw new FormulaParseError(`Unexpected character "${ch}"`, i);
  }

  tokens.push({ type: 'eof', value: '', position: len });
  return tokens;
}

/** Consume a `"…"` literal, treating `""` as an escaped quote. */
function scanQuotedString(source: string, start: number): { value: string; end: number } {
  let i = start + 1;
  let value = '';
  const len = source.length;
  while (i < len) {
    if (source[i] === '"') {
      if (source[i + 1] === '"') {
        value += '"';
        i += 2;
        continue;
      }
      return { value, end: i + 1 };
    }
    value += source[i];
    i++;
  }
  throw new FormulaParseError('Unterminated string literal', start);
}

function isDigit(ch: string): boolean {
  return ch >= '0' && ch <= '9';
}

function isAlpha(ch: string): boolean {
  return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
}

// ─── Parser ─────────────────────────────────────────────────────────────────

class RecursiveDescent {
  private cursor = 0;
  private depth = 0;

  constructor(
    private readonly tokens: Token[],
    private readonly maxDepth: number,
  ) {}

  parseExpression(): FormulaAst {
    return this.guarded(() => this.parseComparison());
  }

  expect(type: TokenType): Token {
    const tok = this.peek();
    if (tok.type !== type) {
      throw new FormulaParseError(`Expected ${type}, got ${tok.type} "${tok.value}"`, tok.position);
    }
    this.cursor++;
    return tok;
  }

  private parseComparison(): FormulaAst {
    let left = this.parseConcat();
    while (true) {
      const op = this.peekOp();
      if (op !== '=' && op !== '<>' && op !== '<' && op !== '<=' && op !== '>' && op !== '>=') break;
      this.cursor++;
      const right = this.parseConcat();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  private parseConcat(): FormulaAst {
    let left = this.parseAdditive();
    while (this.peekOp() === '&') {
      this.cursor++;
      const right = this.parseAdditive();
      left = { kind: 'binary', op: '&', left, right };
    }
    return left;
  }

  private parseAdditive(): FormulaAst {
    let left = this.parseMultiplicative();
    while (true) {
      const op = this.peekOp();
      if (op !== '+' && op !== '-') break;
      this.cursor++;
      const right = this.parseMultiplicative();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  private parseMultiplicative(): FormulaAst {
    let left = this.parsePower();
    while (true) {
      const op = this.peekOp();
      if (op !== '*' && op !== '/') break;
      this.cursor++;
      const right = this.parsePower();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  /** `^` is right-associative in Excel. */
  private parsePower(): FormulaAst {
    const left = this.parseUnary();
    if (this.peekOp() === '^') {
      this.cursor++;
      const right = this.parsePower();
      return { kind: 'binary', op: '^', left, right };
    }
    return left;
  }

  private parseUnary(): FormulaAst {
    const op = this.peekOp();
    if (op === '+' || op === '-') {
      this.cursor++;
      return { kind: 'unary', op: op as UnaryOp, operand: this.parseUnary() };
    }
    return this.parsePrimary();
  }

  private parsePrimary(): FormulaAst {
    const tok = this.peek();
    switch (tok.type) {
      case 'number':
        this.cursor++;
        return { kind: 'number', value: Number(tok.value) };
      case 'string':
        this.cursor++;
        return { kind: 'string', value: tok.value };
      case 'bool':
        this.cursor++;
        return { kind: 'boolean', value: tok.value === 'TRUE' };
      case 'ident':
        return this.parseIdentExpression();
      case 'lparen': {
        this.cursor++;
        const inner = this.parseExpression();
        this.expect('rparen');
        return inner;
      }
      default:
        throw new FormulaParseError(`Unexpected token "${tok.value}"`, tok.position);
    }
  }

  /**
   * An ident followed by `(` is either the `REF(COLUMN(...),ROW(...))`
   * ref primitive (possibly chained as a range), or a regular function call.
   */
  private parseIdentExpression(): FormulaAst {
    const ident = this.expect('ident');
    const upper = ident.value.toUpperCase();
    if (upper === 'REF' && this.peek().type === 'lparen') {
      const ref = this.parseRefPrimitive(ident.position);
      if (this.peek().type === 'colon') {
        this.cursor++;
        const endIdent = this.expect('ident');
        if (endIdent.value.toUpperCase() !== 'REF' || this.peek().type !== 'lparen') {
          throw new FormulaParseError('Expected `REF(` after `:` in range', endIdent.position);
        }
        const endRef = this.parseRefPrimitive(endIdent.position);
        return { kind: 'range', start: ref, end: endRef };
      }
      return { kind: 'ref', ref };
    }
    // Regular function call.
    this.expect('lparen');
    const args: FormulaAst[] = [];
    if (this.peek().type !== 'rparen') {
      args.push(this.parseExpression());
      while (this.peek().type === 'comma') {
        this.cursor++;
        args.push(this.parseExpression());
      }
    }
    this.expect('rparen');
    return { kind: 'call', name: upper, args };
  }

  /**
   * Parse `REF(COLUMN("field")[,ROW(N) [,"$C"|"$R"|"$CR"]])` starting from
   * just after the `REF` ident. Returns the `StructuredRef`. A missing
   * `ROW(...)` arg marks the ref as same-row (resolves against the host
   * cell's row at evaluation time).
   */
  private parseRefPrimitive(position: number): StructuredRef {
    this.expect('lparen');

    const colIdent = this.expect('ident');
    if (colIdent.value.toUpperCase() !== 'COLUMN') {
      throw new FormulaParseError('Expected `COLUMN(` inside REF', colIdent.position);
    }
    this.expect('lparen');
    const fieldTok = this.expect('string');
    this.expect('rparen');

    // Same-row form: `REF(COLUMN("field"))` — no ROW arg.
    if (this.peek().type === 'rparen') {
      this.cursor++;
      void position;
      return {
        field: fieldTok.value,
        row: 0,
        absField: false,
        absRow: false,
        sameRow: true,
      };
    }

    this.expect('comma');

    const rowIdent = this.expect('ident');
    if (rowIdent.value.toUpperCase() !== 'ROW') {
      throw new FormulaParseError('Expected `ROW(` inside REF', rowIdent.position);
    }
    this.expect('lparen');
    const rowTok = this.expect('number');
    this.expect('rparen');

    const row = Number(rowTok.value);
    if (!Number.isFinite(row) || row < 1 || !Number.isInteger(row)) {
      throw new FormulaParseError('ROW must be a positive integer', rowTok.position);
    }

    let absField = false;
    let absRow = false;
    if (this.peek().type === 'comma') {
      this.cursor++;
      const lockTok = this.expect('string');
      const lock = lockTok.value;
      if (lock !== '$C' && lock !== '$R' && lock !== '$CR' && lock !== '') {
        throw new FormulaParseError(
          `Invalid REF lock marker: "${lock}" (expected "$C", "$R", or "$CR")`,
          lockTok.position,
        );
      }
      absField = lock === '$C' || lock === '$CR';
      absRow = lock === '$R' || lock === '$CR';
    }

    this.expect('rparen');

    void position;
    return { field: fieldTok.value, row, absField, absRow };
  }

  private peek(): Token {
    return this.tokens[this.cursor];
  }

  private peekOp(): BinaryOp | null {
    const tok = this.tokens[this.cursor];
    if (tok?.type !== 'op') return null;
    return tok.value as BinaryOp;
  }

  private guarded<T>(fn: () => T): T {
    if (++this.depth > this.maxDepth) {
      throw new FormulaParseError(`Formula exceeds max depth (${this.maxDepth})`, this.peek().position);
    }
    try {
      return fn();
    } finally {
      this.depth--;
    }
  }
}

import { inject, Injectable } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { SortDirection } from '../models/column.model';
import { SortDef } from '../models/sort.model';
import { FilterCondition, generateConditionId } from '../models/filter.model';

export interface PersistedGridState {
  columns: Array<{
    field: string;
    currentWidth: number;
    order: number;
    visible: boolean;
    pinned: 'start' | 'end' | null;
  }>;
  sorts: SortDef[];
  /** Serialised filter conditions. `id` is regenerated on restore. */
  filters?: Array<Omit<FilterCondition, 'id'>>;
}

@Injectable()
export class StatePersistenceEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  save(storageKey: string): void {
    const persisted: PersistedGridState = {
      columns: this.state.columnStates().map((col) => ({
        field: col.field,
        currentWidth: col.currentWidth,
        order: col.order,
        visible: col.visible,
        pinned: col.pinned,
      })),
      sorts: this.state.activeSorts(),
      filters: this.state.filterModel().conditions.map((condition) => {
        const { id, ...rest } = condition;
        void id;
        return rest;
      }),
    };

    try {
      localStorage.setItem(storageKey, JSON.stringify(persisted));
    } catch {
      // localStorage may be unavailable or full
    }
  }

  restore(storageKey: string): boolean {
    try {
      const raw = localStorage.getItem(storageKey);
      if (!raw) return false;

      const persisted: PersistedGridState = JSON.parse(raw);
      if (!persisted.columns?.length) return false;

      this.state.columnStates.update((currentStates) => {
        return currentStates.map((col) => {
          const saved = persisted.columns.find((s) => s.field === col.field);
          if (!saved) return col;
          return {
            ...col,
            currentWidth: saved.currentWidth,
            order: saved.order,
            visible: saved.visible,
            pinned: saved.pinned,
          };
        });
      });

      if (persisted.sorts?.length) {
        this.state.activeSorts.set(persisted.sorts);
        this.state.columnStates.update((states) =>
          states.map((s) => {
            const sortDef = persisted.sorts.find((sd) => sd.field === s.field);
            return sortDef
              ? {
                  ...s,
                  sort: sortDef.direction as SortDirection,
                  sortIndex: persisted.sorts.indexOf(sortDef),
                }
              : { ...s, sort: null as SortDirection, sortIndex: null };
          })
        );
      }

      if (persisted.filters?.length) {
        this.state.filterModel.set({
          conditions: persisted.filters.map((f) => ({ ...f, id: generateConditionId() })),
        });
      }

      return true;
    } catch {
      return false;
    }
  }

  clear(storageKey: string): void {
    try {
      localStorage.removeItem(storageKey);
    } catch {
      // localStorage may be unavailable
    }
  }
}

import { Injectable, Signal, computed, signal } from '@angular/core';
import type { CellAddress } from '../../models/formula.model';
import { FormulaRefPalette, paletteColorVar } from './formula-ref-palette';

export interface RefHighlight {
  /** Normalised key (e.g. `"A1"`, `"A1:B3"`). Drives the colour slot. */
  readonly key: string;
  /** Source-relative character range of the token in the edit buffer. */
  readonly tokenStart: number;
  readonly tokenEnd: number;
  /** Resolved cells covered by the ref (1 entry for a simple ref). */
  readonly cells: readonly CellAddress[];
  readonly colorIndex: number;
  /** `var(--ad-grid-ref-color-N)` — ready to use in `[style]` bindings. */
  readonly cssVar: string;
}

export interface PickHandler {
  pickCell(addr: CellAddress, opts: { absolute: boolean }): void;
  pickRangeStart(addr: CellAddress, opts: { absolute: boolean }): void;
  pickRangeExtend(end: CellAddress): void;
  pickRangeCommit(): void;
}

function cellKey(addr: CellAddress): string {
  return `${addr.rowId}|${addr.field}`;
}

@Injectable()
export class FormulaRefHighlightService {
  private readonly palette = new FormulaRefPalette();

  private readonly highlightsSignal = signal<readonly RefHighlight[]>([]);
  private readonly isActiveSignal = signal(false);
  private readonly isPickModeSignal = signal(false);
  private readonly isPickDraggingSignal = signal(false);

  readonly highlights: Signal<readonly RefHighlight[]> = this.highlightsSignal.asReadonly();
  /** `true` while any formula editor is active — used by cells/headers to
   *  render ref-color borders and column-letter badges. Orthogonal to
   *  pick mode: a text-only editor (e.g. the formula bar) still marks itself
   *  active so highlights appear, but never flips pick mode on. */
  readonly isActive: Signal<boolean> = this.isActiveSignal.asReadonly();
  /** `true` when cell clicks should be intercepted to insert refs into the
   *  active editor. The formula bar deliberately disables this to keep its
   *  input purely text-driven. */
  readonly isPickMode: Signal<boolean> = this.isPickModeSignal.asReadonly();
  /** `true` between `pickRangeStart` and `pickRangeCommit` — used by cells
   *  to know that a mouseenter should extend the range being built. */
  readonly isPickDragging: Signal<boolean> = this.isPickDraggingSignal.asReadonly();

  /** `rowId|field` → CSS var — used by grid cells to paint ref borders. */
  readonly colorByCell: Signal<ReadonlyMap<string, string>> = computed(() => {
    const map = new Map<string, string>();
    for (const h of this.highlightsSignal()) {
      for (const cell of h.cells) {
        map.set(cellKey(cell), h.cssVar);
      }
    }
    return map;
  });

  private pickHandler: PickHandler | null = null;

  /**
   * Called by the editor on mount. Registers the handler used by cells
   * to dispatch pick events.
   *
   * `isActive` flips on unconditionally so cells paint ref-color borders
   * and headers show column-letter badges — the *visual* feedback is
   * useful in both inline and formula-bar editors.
   *
   * `pickMode` (default `true`) controls whether cell clicks are
   * intercepted to insert refs. The formula bar passes `false` so typing
   * stays keyboard-only and normal cell selection keeps working.
   */
  activate(handler: PickHandler, options?: { pickMode?: boolean }): void {
    this.pickHandler = handler;
    this.isActiveSignal.set(true);
    this.isPickModeSignal.set(options?.pickMode ?? true);
  }

  /** Called on editor teardown. Resets state + palette. */
  deactivate(): void {
    this.pickHandler = null;
    this.isActiveSignal.set(false);
    this.isPickModeSignal.set(false);
    this.isPickDraggingSignal.set(false);
    this.highlightsSignal.set([]);
    this.palette.clear();
  }

  /** Produce a {index, cssVar} pair for a normalised ref key. */
  colorFor(key: string): { index: number; cssVar: string } {
    const index = this.palette.indexFor(key);
    return { index, cssVar: paletteColorVar(index) };
  }

  /** Replaces the highlight list — typically from an editor effect. */
  setHighlights(next: readonly RefHighlight[]): void {
    this.highlightsSignal.set(next);
  }

  // ─── Pick API — called by cells ──────────────────────────────────────────

  pickCell(addr: CellAddress, opts: { absolute: boolean }): void {
    this.pickHandler?.pickCell(addr, opts);
  }
  pickRangeStart(addr: CellAddress, opts: { absolute: boolean }): void {
    this.isPickDraggingSignal.set(true);
    this.pickHandler?.pickRangeStart(addr, opts);
  }
  pickRangeExtend(end: CellAddress): void {
    if (!this.isPickDraggingSignal()) return;
    this.pickHandler?.pickRangeExtend(end);
  }
  pickRangeCommit(): void {
    if (!this.isPickDraggingSignal()) return;
    this.isPickDraggingSignal.set(false);
    this.pickHandler?.pickRangeCommit();
  }
}

