export function generateWideRows(rowCount: number, colCount: number): WideRow[] {
  return Array.from({ length: rowCount }, (_, r) => {
    const row: WideRow = { id: r + 1 };
    for (let c = 0; c < colCount; c++) {
      row[`c${c}`] = `R${r + 1}·C${c + 1}`;
    }
    return row;
  });
}

