import { Injectable, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';

/** Maximum rows sampled per column. */
const SAMPLE_CAP = 1000;

/** Absolute minimum column width in px. */
const MIN_WIDTH = 50;

/** Hard cap — no column exceeds this regardless of content. */
const MAX_WIDTH = 800;

/**
 * Extra pixels added to the canvas-measured content width to absorb
 * canvas↔DOM measurement divergence (kerning, ligatures) plus left/right
 * cell padding and a small ellipsis safety buffer.
 */
const PADDING_PX = 24;

/**
 * Header-specific affordance: sort indicator (~14 px) + gap + kebab
 * trigger (~28 px with padding). Layered on top of `PADDING_PX` for
 * header-text width calculation only.
 */
const HEADER_AFFORDANCE = 52;

// Module-level canvas singleton — avoids GC pressure when autosizing
// many columns in a single "Autosize all" pass.
let measurementCanvas: HTMLCanvasElement | null = null;

function getMeasurementCtx(): CanvasRenderingContext2D | null {
  if (typeof document === 'undefined') return null;
  if (!measurementCanvas) measurementCanvas = document.createElement('canvas');
  return measurementCanvas.getContext('2d');
}

/** CSS-escape a value for use in attribute selectors. */
function cssEscape(value: string): string {
  const css = (globalThis as { CSS?: { escape?: (v: string) => string } }).CSS;
  if (css?.escape) return css.escape(value);
  return value.replace(/["\\]/g, '\\$&');
}

@Injectable()
export class AutosizeEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  /**
   * Options accepted by `autosizeColumn` / `autosizeAllColumns`.
   */

  /**
   * Autosize a single column. Measures content via canvas and updates
   * `state.columnStates[field].currentWidth`.
   *
   * @param field     Column field identifier.
   * @param wrapperEl Optional DOM wrapper element for font sampling and
   *                  custom-renderer DOM probe. When `null`, font defaults
   *                  to `14px sans-serif` and the DOM probe is skipped.
   * @param options   Optional overrides. `maxWidth` caps the computed width
   *                  (default: 800 px).
   */
  autosizeColumn(
    field: string,
    wrapperEl: HTMLElement | null = null,
    options?: { maxWidth?: number },
  ): void {
    const ctx = getMeasurementCtx();
    if (!ctx) return;

    const env = this.sampleCellEnv(wrapperEl, field, ctx);
    const width = this.measureColumn(field, env, ctx, wrapperEl, options?.maxWidth);
    if (width == null) return;
    this.state.updateColumnState(field, { currentWidth: width });
  }

  /**
   * Autosize all currently visible columns in a single pass.
   * Hoists the `getComputedStyle` DOM read outside the per-column loop so
   * the style-recalc cost is O(1) instead of O(n-columns).
   *
   * @param wrapperEl Optional DOM wrapper element (same as `autosizeColumn`).
   * @param options   Optional overrides. `maxWidth` caps the computed width
   *                  (default: 800 px).
   */
  autosizeAllColumns(wrapperEl: HTMLElement | null = null, options?: { maxWidth?: number }): void {
    const ctx = getMeasurementCtx();
    if (!ctx) return;

    // Single shared env for all columns — all `.ad-grid-cell` share the
    // same font / padding, so one sample is representative for everyone.
    const env = this.sampleCellEnv(wrapperEl, null, ctx);

    for (const col of this.state.visibleColumns()) {
      const width = this.measureColumn(col.field, env, ctx, wrapperEl, options?.maxWidth);
      if (width != null) {
        this.state.updateColumnState(col.field, { currentWidth: width });
      }
    }
  }

  // ---------------------------------------------------------------------------
  // Private helpers
  // ---------------------------------------------------------------------------

  /**
   * Sample a real grid cell to extract the canvas font string and the
   * horizontal padding/border reserve. Hoisted so "autosize all" can call
   * it once and share the result across every column.
   */
  private sampleCellEnv(
    wrapperEl: HTMLElement | null,
    field: string | null,
    ctx: CanvasRenderingContext2D,
  ): { reserve: number; borderX: number } {
    if (!wrapperEl) {
      // No DOM available — fall back to a reasonable default font.
      ctx.font = '14px sans-serif';
      return { reserve: PADDING_PX, borderX: 0 };
    }

    const sample = this.pickStyleSample(wrapperEl, field ?? '');
    const cs = window.getComputedStyle(sample);
    ctx.font = `${cs.fontStyle} ${cs.fontWeight} ${cs.fontSize} ${cs.fontFamily}`;
    const padX =
      (parseFloat(cs.paddingLeft) || 0) + (parseFloat(cs.paddingRight) || 0);
    const borderX =
      (parseFloat(cs.borderLeftWidth) || 0) + (parseFloat(cs.borderRightWidth) || 0);
    return { reserve: padX + borderX + 4 /* safety pad */, borderX };
  }

  private measureColumn(
    field: string,
    env: { reserve: number; borderX: number },
    ctx: CanvasRenderingContext2D,
    wrapperEl: HTMLElement | null,
    maxWidthOverride?: number,
  ): number | null {
    const def = this.state.columnDefMap().get(field);
    if (!def) return null;

    const { reserve, borderX } = env;

    const minDef = def.minWidth ? parseInt(def.minWidth, 10) : NaN;
    const maxDef = def.maxWidth ? parseInt(def.maxWidth, 10) : NaN;
    const min = Number.isFinite(minDef) ? Math.max(MIN_WIDTH, minDef) : MIN_WIDTH;
    // maxWidthOverride from caller > per-column def > module constant.
    const cap = maxWidthOverride ?? (Number.isFinite(maxDef) ? maxDef : MAX_WIDTH);

    // --- Header width ---
    const headerText = def.headerName ?? def.field;
    let maxWidth = ctx.measureText(headerText).width + reserve + HEADER_AFFORDANCE;
    if (maxWidth >= cap) return Math.max(min, Math.ceil(cap));

    // --- Body data sample ---
    const data = this.state.sourceData();
    const total = data.length;
    const stride = total > SAMPLE_CAP ? Math.ceil(total / SAMPLE_CAP) : 1;

    for (let i = 0; i < total; i += stride) {
      const row = data[i];
      if (!row) continue;
      const displayValue = this.getDisplayValue(row, def);
      const w = ctx.measureText(displayValue).width + reserve;
      if (w > maxWidth) {
        maxWidth = w;
        if (maxWidth >= cap) {
          maxWidth = cap;
          break;
        }
      }
    }

    // --- Custom cellTemplate fallback: probe rendered DOM cells ---
    // Canvas measureText only knows about the raw string. Columns with
    // cellTemplate (badge, avatar, chip…) have wider true widths. For
    // these we also read scrollWidth of the currently rendered cells.
    // Limitation: only covers rows inside the current virtual viewport.
    if (def.cellTemplate != null && wrapperEl) {
      const escaped = cssEscape(field);
      const renderedCells = wrapperEl.querySelectorAll<HTMLElement>(
        `[data-field="${escaped}"]`,
      );
      for (const cell of renderedCells) {
        const w = cell.scrollWidth + borderX + 4;
        if (w > maxWidth) {
          maxWidth = w;
          if (maxWidth >= cap) {
            maxWidth = cap;
            break;
          }
        }
      }
    }

    return Math.max(min, Math.min(cap, Math.ceil(maxWidth + PADDING_PX)));
  }

  private getDisplayValue(row: T, def: { valueGetter?: (r: T) => unknown; valueFormatter?: (v: unknown, r: T) => string; field: string }): string {
    const raw = def.valueGetter ? def.valueGetter(row) : (row as Record<string, unknown>)[def.field];
    if (def.valueFormatter) return def.valueFormatter(raw, row);
    if (raw === null || raw === undefined) return '';
    return String(raw);
  }

  /** Picks a rendered cell element to derive font/padding from. */
  private pickStyleSample(wrapper: HTMLElement, field: string): HTMLElement {
    const escaped = cssEscape(field);
    if (field) {
      const colCell = wrapper.querySelector(`[data-field="${escaped}"]`) as HTMLElement | null;
      if (colCell) return colCell;
    }
    const anyCell = wrapper.querySelector('[data-field]') as HTMLElement | null;
    return anyCell ?? wrapper;
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { CellRange } from '../models/cell.model';

@Injectable()
export class CellSelectionEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  // ---------------------------------------------------------------------------
  // Multi-range (Ctrl+Click) — Angular-parity port of Vue useCellSelection
  // ---------------------------------------------------------------------------

  /**
   * Frozen ranges from previous Ctrl+Click operations.
   * Each entry is a snapshot of a completed `cellRange` that was "frozen"
   * when the user held Ctrl and clicked elsewhere.
   */
  readonly frozenRanges = signal<CellRange[]>([]);

  /**
   * All active ranges: frozen (Ctrl+Click) + the current live range.
   * Consumed by grid-cell to paint multi-range highlights.
   */
  readonly allRanges = computed<CellRange[]>(() => {
    const cur = this.state.cellRange();
    return [...this.frozenRanges(), ...(cur ? [cur] : [])];
  });

  /**
   * Freeze the current live range and start a new single-cell selection at
   * `range`. Caller is responsible for also updating `state.cellRange` to
   * the new anchor so keyboard extend keeps working from the new cell.
   */
  addRange(range: CellRange): void {
    const cur = this.state.cellRange();
    if (cur) {
      this.frozenRanges.update((prev) => [...prev, cur]);
    }
    this.state.cellRange.set(range);
    this.state.focusedCell.set(range.start);
    this.state.selectedCell.set(range.start);
  }

  /** Discard all frozen ranges (single selection revert). */
  clearFrozenRanges(): void {
    this.frozenRanges.set([]);
  }

  /**
   * Returns true when (row, col) belongs to any active range
   * (frozen or current). Used by grid-cell for multi-range highlight.
   */
  isCellInAnyRange(row: number, col: number): boolean {
    for (const range of this.allRanges()) {
      const minRow = Math.min(range.start.row, range.end.row);
      const maxRow = Math.max(range.start.row, range.end.row);
      const minCol = Math.min(range.start.col, range.end.col);
      const maxCol = Math.max(range.start.col, range.end.col);
      if (row >= minRow && row <= maxRow && col >= minCol && col <= maxCol) {
        return true;
      }
    }
    return false;
  }

  focusCell(row: number, col: number, source: 'click' | 'keyboard' = 'click'): void {
    this.state.focusSource.set(source);
    this.state.focusedCell.set({ row, col });
    this.state.selectedCell.set({ row, col });
    this.state.cellRange.set(null);
    this.state.isDragging.set(false);
    // A plain focus always resets multi-range selection.
    this.frozenRanges.set([]);
  }

  clearFocus(): void {
    this.state.focusSource.set(null);
    this.state.focusedCell.set(null);
    this.state.selectedCell.set(null);
    this.state.cellRange.set(null);
    this.state.isDragging.set(false);
    this.frozenRanges.set([]);
  }

  isCellFocused(row: number, col: number): boolean {
    const focused = this.state.focusedCell();
    return focused?.row === row && focused?.col === col;
  }

  isCellInRange(row: number, col: number): boolean {
    const range = this.state.cellRange();
    if (!range) {
      return this.isCellFocused(row, col);
    }
    const minRow = Math.min(range.start.row, range.end.row);
    const maxRow = Math.max(range.start.row, range.end.row);
    const minCol = Math.min(range.start.col, range.end.col);
    const maxCol = Math.max(range.start.col, range.end.col);
    return row >= minRow && row <= maxRow && col >= minCol && col <= maxCol;
  }

  selectRange(start: { row: number; col: number }, end: { row: number; col: number }): void {
    this.state.cellRange.set({ start, end });
    this.state.isDragging.set(false);
  }

  startRangeSelection(row: number, col: number): void {
    this.state.focusedCell.set({ row, col });
    this.state.cellRange.set({ start: { row, col }, end: { row, col } });
    this.state.isDragging.set(true);
  }

  extendRange(row: number, col: number): void {
    if (!this.state.isDragging()) return;
    const range = this.state.cellRange();
    if (!range) return;
    this.state.cellRange.set({ start: range.start, end: { row, col } });
  }

  endRangeSelection(): void {
    this.state.isDragging.set(false);
  }

  moveUp(): void {
    this.moveBy(-1, 0);
  }

  moveDown(): void {
    this.moveBy(1, 0);
  }

  moveLeft(): void {
    this.moveBy(0, -1);
  }

  moveRight(): void {
    this.moveBy(0, 1);
  }

  // --- Home / End / Grid bounds -------------------------------------------------

  moveToRowStart(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    this.focusCell(focused.row, 0, 'keyboard');
  }

  moveToRowEnd(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;
    this.focusCell(focused.row, this.findLastNonEmptyCol(focused.row, maxCol), 'keyboard');
  }

  moveToGridStart(): void {
    const pageStart = this.state.pageIndex() * this.state.pageSize();
    this.focusCell(pageStart, 0, 'keyboard');
  }

  moveToGridEnd(): void {
    const pageStart = this.state.pageIndex() * this.state.pageSize();
    const pageEnd = pageStart + Math.max(0, this.state.visibleRowCount() - 1);
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;
    this.focusCell(pageEnd, this.findLastNonEmptyCol(pageEnd, maxCol), 'keyboard');
  }

  /**
   * Excel-style Ctrl+Arrow: jump to the edge of the current data block.
   * If on an empty cell, jumps to the next non-empty cell. If on a filled
   * cell, jumps to the last filled cell before the next empty transition
   * (or to the grid edge if no empty cell is encountered).
   */
  jumpToEdge(direction: 'up' | 'down' | 'left' | 'right'): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const { dRow, dCol } = this.directionVector(direction);
    const bounds = this.pageBounds();
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;

    const startFilled = this.isCellFilled(focused.row, focused.col);
    let row = focused.row;
    let col = focused.col;

    // Step once to start looking at the neighbour
    let nextRow = row + dRow;
    let nextCol = col + dCol;
    while (this.inBounds(nextRow, nextCol, bounds, maxCol)) {
      const filled = this.isCellFilled(nextRow, nextCol);
      if (startFilled) {
        // Moving through filled cells — stop right before the next empty gap.
        if (!filled) break;
        row = nextRow;
        col = nextCol;
      } else {
        // Moving through empty cells — stop on the first filled cell we meet.
        if (filled) {
          row = nextRow;
          col = nextCol;
          break;
        }
        row = nextRow;
        col = nextCol;
      }
      nextRow += dRow;
      nextCol += dCol;
    }

    this.focusCell(row, col, 'keyboard');
  }

  movePage(direction: 'up' | 'down'): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const step = this.pageRowStep() * (direction === 'down' ? 1 : -1);
    this.moveBy(step, 0);
  }

  // --- Shift + navigation : extend current range --------------------------------

  extendRangeBy(dRow: number, dCol: number): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const range = this.state.cellRange();
    const bounds = this.pageBounds();
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;

    const currentEnd = range ? range.end : focused;
    const newEnd = {
      row: Math.max(bounds.start, Math.min(bounds.end, currentEnd.row + dRow)),
      col: Math.max(0, Math.min(maxCol, currentEnd.col + dCol)),
    };
    const start = range ? range.start : focused;
    this.state.cellRange.set({ start, end: newEnd });
  }

  /**
   * Extends the current selection from the focused-cell anchor to (row, col).
   * Mirrors Vue's `extendRangeTo(row, col)` — used for Shift+Click without drag.
   */
  extendRangeTo(row: number, col: number): void {
    const anchor = this.state.focusedCell() ?? this.state.cellRange()?.start;
    if (!anchor) return;
    this.state.cellRange.set({ start: anchor, end: { row, col } });
  }

  extendRangeToRowStart(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const range = this.state.cellRange();
    const start = range?.start ?? focused;
    this.state.cellRange.set({ start, end: { row: (range?.end ?? focused).row, col: 0 } });
  }

  extendRangeToRowEnd(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;
    const range = this.state.cellRange();
    const start = range?.start ?? focused;
    this.state.cellRange.set({ start, end: { row: (range?.end ?? focused).row, col: maxCol } });
  }

  extendRangeToGridStart(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const bounds = this.pageBounds();
    const range = this.state.cellRange();
    const start = range?.start ?? focused;
    this.state.cellRange.set({ start, end: { row: bounds.start, col: 0 } });
  }

  extendRangeToGridEnd(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const bounds = this.pageBounds();
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;
    const range = this.state.cellRange();
    const start = range?.start ?? focused;
    this.state.cellRange.set({ start, end: { row: bounds.end, col: maxCol } });
  }

  extendRangeJumpToEdge(direction: 'up' | 'down' | 'left' | 'right'): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const range = this.state.cellRange();
    const anchor = range?.start ?? focused;
    const end = range?.end ?? focused;
    const target = this.edgeFromCell(end, direction);
    this.state.cellRange.set({ start: anchor, end: target });
  }

  extendRangeByPage(direction: 'up' | 'down'): void {
    const step = this.pageRowStep() * (direction === 'down' ? 1 : -1);
    this.extendRangeBy(step, 0);
  }

  // --- Whole row / column / grid selection --------------------------------------

  selectRow(row: number): void {
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;
    this.state.focusedCell.set({ row, col: 0 });
    this.state.focusSource.set('keyboard');
    this.state.cellRange.set({
      start: { row, col: 0 },
      end: { row, col: maxCol },
    });
  }

  selectColumn(col: number): void {
    const bounds = this.pageBounds();
    this.state.focusedCell.set({ row: bounds.start, col });
    this.state.focusSource.set('keyboard');
    this.state.cellRange.set({
      start: { row: bounds.start, col },
      end: { row: bounds.end, col },
    });
  }

  selectAll(): void {
    const bounds = this.pageBounds();
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return;
    this.state.focusedCell.set({ row: bounds.start, col: 0 });
    this.state.focusSource.set('keyboard');
    this.state.cellRange.set({
      start: { row: bounds.start, col: 0 },
      end: { row: bounds.end, col: maxCol },
    });
  }

  // --- Private helpers ----------------------------------------------------------

  private pageBounds(): { start: number; end: number } {
    const start = this.state.pageIndex() * this.state.pageSize();
    const end = start + Math.max(0, this.state.visibleRowCount() - 1);
    return { start, end };
  }

  private pageRowStep(): number {
    const rowHeight = this.state.rowHeight() || 48;
    const viewportHeight = this.state.scrollViewportHeight();
    if (viewportHeight > 0) {
      return Math.max(1, Math.floor(viewportHeight / rowHeight));
    }
    // Fallback: a sensible default when the viewport hasn't been measured yet.
    return Math.max(1, Math.floor(this.state.visibleRowCount() / 2) || 10);
  }

  private directionVector(dir: 'up' | 'down' | 'left' | 'right'): { dRow: number; dCol: number } {
    switch (dir) {
      case 'up':
        return { dRow: -1, dCol: 0 };
      case 'down':
        return { dRow: 1, dCol: 0 };
      case 'left':
        return { dRow: 0, dCol: -1 };
      case 'right':
        return { dRow: 0, dCol: 1 };
    }
  }

  private inBounds(
    row: number,
    col: number,
    bounds: { start: number; end: number },
    maxCol: number,
  ): boolean {
    return row >= bounds.start && row <= bounds.end && col >= 0 && col <= maxCol;
  }

  private isCellFilled(row: number, col: number): boolean {
    const cols = this.state.visibleColumns();
    const field = cols[col]?.field;
    if (!field) return false;
    const data = this.state.sourceData();
    const rowData = data[row];
    if (!rowData) return false;
    const def = this.state.columnDefMap().get(field);
    const value = def?.valueGetter
      ? def.valueGetter(rowData)
      : (rowData as Record<string, unknown>)[field];
    return value !== null && value !== undefined && value !== '';
  }

  private findLastNonEmptyCol(row: number, maxCol: number): number {
    for (let c = maxCol; c >= 0; c--) {
      if (this.isCellFilled(row, c)) return c;
    }
    return maxCol;
  }

  private edgeFromCell(
    from: { row: number; col: number },
    direction: 'up' | 'down' | 'left' | 'right',
  ): { row: number; col: number } {
    const { dRow, dCol } = this.directionVector(direction);
    const bounds = this.pageBounds();
    const maxCol = this.state.visibleColumns().length - 1;
    if (maxCol < 0) return from;

    const startFilled = this.isCellFilled(from.row, from.col);
    let row = from.row;
    let col = from.col;
    let nextRow = row + dRow;
    let nextCol = col + dCol;
    while (this.inBounds(nextRow, nextCol, bounds, maxCol)) {
      const filled = this.isCellFilled(nextRow, nextCol);
      if (startFilled) {
        if (!filled) break;
      } else if (filled) {
        row = nextRow;
        col = nextCol;
        break;
      }
      row = nextRow;
      col = nextCol;
      nextRow += dRow;
      nextCol += dCol;
    }
    return { row, col };
  }

  moveToNextEditableCell(): void {
    const focused = this.state.focusedCell();
    if (!focused) return;
    const cols = this.state.visibleColumns();
    let col = focused.col + 1;
    let row = focused.row;

    while (row < this.state.sourceData().length) {
      if (col >= cols.length) {
        col = 0;
        row++;
      }
      if (row >= this.state.sourceData().length) break;

      const def = this.state.columnDefMap().get(cols[col]?.field ?? '');
      if (def?.editable) {
        this.focusCell(row, col);
        return;
      }
      col++;
    }
  }

  // --- Fill Handle (Google Sheets style) — supports vertical and horizontal fills ---

  startFill(row: number, col: number): void {
    this.state.fillAnchor.set({ row, col });
    this.state.fillTarget.set({ row, col });
    this.state.isFilling.set(true);
  }

  /**
   * Extends the fill range. The dominant axis (the one with the largest delta
   * from the anchor) wins: vertical if |dRow| >= |dCol|, otherwise horizontal.
   * The fill is 1D — it's always locked to a single row or a single column.
   */
  extendFill(row: number, col: number): void {
    if (!this.state.isFilling()) return;
    const anchor = this.state.fillAnchor();
    if (!anchor) return;
    const dRow = Math.abs(row - anchor.row);
    const dCol = Math.abs(col - anchor.col);
    if (dRow >= dCol) {
      this.state.fillTarget.set({ row, col: anchor.col });
    } else {
      this.state.fillTarget.set({ row: anchor.row, col });
    }
  }

  endFill(): { anchor: { row: number; col: number }; target: { row: number; col: number } } | null {
    if (!this.state.isFilling()) return null;
    const anchor = this.state.fillAnchor();
    const target = this.state.fillTarget();
    this.state.isFilling.set(false);
    this.state.fillAnchor.set(null);
    this.state.fillTarget.set(null);
    if (!anchor || !target) return null;
    if (anchor.row === target.row && anchor.col === target.col) return null;
    return { anchor, target };
  }

  cancelFill(): void {
    this.state.isFilling.set(false);
    this.state.fillAnchor.set(null);
    this.state.fillTarget.set(null);
  }

  isCellInFillRange(row: number, col: number): boolean {
    const anchor = this.state.fillAnchor();
    const target = this.state.fillTarget();
    if (!anchor || !target) return false;
    if (row === anchor.row && col === anchor.col) return false; // skip anchor

    const vertical = target.col === anchor.col;
    if (vertical) {
      if (col !== anchor.col) return false;
      const minRow = Math.min(anchor.row, target.row);
      const maxRow = Math.max(anchor.row, target.row);
      return row >= minRow && row <= maxRow;
    }

    // Horizontal fill: single row, col range — skip non-editable columns and
    // type-incompatible columns so the highlight mirrors exactly which cells
    // will actually be written.
    if (row !== anchor.row) return false;
    const minCol = Math.min(anchor.col, target.col);
    const maxCol = Math.max(anchor.col, target.col);
    if (col < minCol || col > maxCol) return false;
    return this.isColEditable(col) && this.isColTypeCompatible(anchor.col, col);
  }

  /**
   * During a horizontal fill, cells that sit inside the drag bounding box but
   * belong to a non-editable column cannot receive the filled value. We expose
   * them here so the view can paint a red dashed outline — a visual cue that
   * the fill is skipping that column.
   */
  isCellInFillRejectRange(row: number, col: number): boolean {
    const anchor = this.state.fillAnchor();
    const target = this.state.fillTarget();
    if (!anchor || !target) return false;
    if (anchor.row === target.row && anchor.col === target.col) return false;

    const vertical = target.col === anchor.col;
    if (vertical) return false; // vertical fills stay on the anchor column

    if (row !== anchor.row) return false;
    const minCol = Math.min(anchor.col, target.col);
    const maxCol = Math.max(anchor.col, target.col);
    if (col < minCol || col > maxCol) return false;
    // Reject if non-editable OR editable but type-incompatible with anchor
    return !this.isColEditable(col) || !this.isColTypeCompatible(anchor.col, col);
  }

  private isColEditable(colIndex: number): boolean {
    const cols = this.state.visibleColumns();
    const colEntry = cols[colIndex];
    if (!colEntry) return false;
    const def = this.state.columnDefMap().get(colEntry.field);
    return def?.editable === true;
  }

  /**
   * Returns the effective editor type for a column index.
   * Falls back to 'text' when no explicit cellEditor is defined.
   */
  private getColEditorType(colIndex: number): string {
    const cols = this.state.visibleColumns();
    const colEntry = cols[colIndex];
    if (!colEntry) return 'text';
    const def = this.state.columnDefMap().get(colEntry.field);
    return def?.cellEditor ?? 'text';
  }

  /**
   * Checks whether the source column's editor type is compatible with the
   * target column's editor type for a horizontal fill operation.
   * text↔text, number↔number, select↔select, etc. — only same-type is allowed.
   */
  private isColTypeCompatible(sourceCol: number, targetCol: number): boolean {
    return this.getColEditorType(sourceCol) === this.getColEditorType(targetCol);
  }

  private moveBy(dRow: number, dCol: number): void {
    const focused = this.state.focusedCell();
    if (!focused) return;

    // Clamp to the global row range of the current page
    const pageStart = this.state.pageIndex() * this.state.pageSize();
    const pageEnd = pageStart + Math.max(0, this.state.visibleRowCount() - 1);
    const maxCol = this.state.visibleColumns().length - 1;
    const newRow = Math.max(pageStart, Math.min(pageEnd, focused.row + dRow));
    const newCol = Math.max(0, Math.min(maxCol, focused.col + dCol));

    this.focusCell(newRow, newCol, 'keyboard');
  }

  getNormalizedRange(): CellRange | null {
    const range = this.state.cellRange();
    if (!range) {
      const focused = this.state.focusedCell();
      if (!focused) return null;
      return { start: focused, end: focused };
    }
    return {
      start: {
        row: Math.min(range.start.row, range.end.row),
        col: Math.min(range.start.col, range.end.col),
      },
      end: {
        row: Math.max(range.start.row, range.end.row),
        col: Math.max(range.start.col, range.end.col),
      },
    };
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { CellError } from '../models/cell.model';

@Injectable()
export class CellValidationEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  /** Map<"rowIndex:field", CellError> */
  readonly cellErrors = signal<Map<string, CellError>>(new Map());

  /** Number of cells currently in error */
  readonly errorCount = computed(() => this.cellErrors().size);

  /**
   * Revalidate every cell for the given data slice.
   * Returns the number of cells that failed validation, matching the
   * Vue grid's `validateAll()` contract so consumers can branch on
   * `if (grid.validateAll() > 0) …` without re-querying `errorCount()`.
   */
  validateAll(data: T[]): number {
    const defMap = this.state.columnDefMap();
    const errors = new Map<string, CellError>();

    for (let rowIndex = 0; rowIndex < data.length; rowIndex++) {
      const row = data[rowIndex];
      for (const [field, def] of defMap) {
        if (!def.cellValidator) continue;
        const value = (row as Record<string, unknown>)[field];
        const error = def.cellValidator(value, row);
        if (error) {
          errors.set(`${rowIndex}:${field}`, error);
        }
      }
    }

    this.cellErrors.set(errors);
    return errors.size;
  }

  /** Revalidate a single cell */
  validateCell(rowIndex: number, field: string, value: unknown, row: T): void {
    const defMap = this.state.columnDefMap();
    const def = defMap.get(field);
    if (!def?.cellValidator) {
      // Remove any previous error if validator was removed
      this.removeCellError(rowIndex, field);
      return;
    }

    const error = def.cellValidator(value, row);
    const key = `${rowIndex}:${field}`;

    this.cellErrors.update((map) => {
      const next = new Map(map);
      if (error) {
        next.set(key, error);
      } else {
        next.delete(key);
      }
      return next;
    });
  }

  /** Get the error for a specific cell, or null */
  getCellError(rowIndex: number, field: string): CellError | null {
    return this.cellErrors().get(`${rowIndex}:${field}`) ?? null;
  }

  /** Check if a specific cell has an error */
  hasCellError(rowIndex: number, field: string): boolean {
    return this.cellErrors().has(`${rowIndex}:${field}`);
  }

  /** Clear all errors */
  clearAll(): void {
    this.cellErrors.set(new Map());
  }

  private removeCellError(rowIndex: number, field: string): void {
    const key = `${rowIndex}:${field}`;
    if (this.cellErrors().has(key)) {
      this.cellErrors.update((map) => {
        const next = new Map(map);
        next.delete(key);
        return next;
      });
    }
  }
}

import { Injectable, computed, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { CellRange } from '../models/cell.model';
import { GridEngine } from '../engine/grid-engine';
import { shiftFormulaRefs } from './formula/formula-shift';

export const PASTE_SKIP = Symbol('PASTE_SKIP');

export interface HistoryCellChange {
  rowIndex: number;
  field: string;
  before: unknown;
  after: unknown;
}

/**
 * Applies a set of cell-level mutations to sourceData and returns the list of
 * actual changes that occurred, so the caller (usually the history engine) can
 * record them. `PASTE_SKIP` return values are filtered out transparently.
 */
@Injectable()
export class ClipboardEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);
  private readonly gridEngine = inject<GridEngine<T>>(GridEngine);

  /** Derived by components (marching-ants outline). */
  readonly cutRange = computed(() => this.state.cutSource());

  /**
   * Maps every display row index inside `range` to its actual sourceData
   * index. Unknown indices (e.g. outside the current page) are skipped so
   * callers can safely iterate only over rows that exist in sourceData.
   */
  private resolveRangeSourceIndices(range: CellRange): number[] {
    const out: number[] = [];
    for (let r = range.start.row; r <= range.end.row; r++) {
      const srcIdx = this.gridEngine.displayIndexToSourceIndex(r);
      if (srcIdx >= 0) out.push(srcIdx);
    }
    return out;
  }

  /**
   * Like {@link resolveRangeSourceIndices} but also keeps each row's display
   * position. Needed by formula-aware fills, where the shift applied to
   * relative refs is driven by the *display* row delta (column axis is named,
   * so field references never rewrite on horizontal fill).
   */
  private resolveRangeWithDisplay(range: CellRange): { display: number; source: number }[] {
    const out: { display: number; source: number }[] = [];
    for (let r = range.start.row; r <= range.end.row; r++) {
      const srcIdx = this.gridEngine.displayIndexToSourceIndex(r);
      if (srcIdx >= 0) out.push({ display: r, source: srcIdx });
    }
    return out;
  }

  /**
   * Shifts the relative refs of a spreadsheet-style formula when the value
   * is being dropped on a different row/column during a fill operation.
   * Non-formula values (anything that doesn't start with `=`) are returned
   * as-is, so downstream coercion still runs over the raw string.
   */
  private shiftIfFormula(value: unknown, allowFormula: boolean, rowDelta: number, colDelta: number): unknown {
    if (!allowFormula) return value;
    if (typeof value !== 'string') return value;
    if (!value.trimStart().startsWith('=')) return value;
    if (rowDelta === 0 && colDelta === 0) return value;
    const fieldOrder = this.state.visibleColumns().map((c) => c.field);
    return shiftFormulaRefs(value, { rowDelta, colDelta, fieldOrder });
  }

  markCut(range: CellRange): void {
    this.state.cutSource.set(range);
  }

  clearCut(): void {
    this.state.cutSource.set(null);
  }

  // ── B21 — Series detection for fill handle ────────────────────────────

  private detectSeries(sourceValues: unknown[]): { type: 'number' | 'date'; step: number; base: number } | null {
    if (sourceValues.length < 2) return null;

    const allNumbers = sourceValues.every((v) => typeof v === 'number' && isFinite(v as number));
    if (allNumbers) {
      const nums = sourceValues as number[];
      const step = nums[1]! - nums[0]!;
      const isArithmetic = nums.every((v, i) => i === 0 || Math.abs(v - nums[i - 1]! - step) < 1e-9);
      if (isArithmetic) return { type: 'number', step, base: nums[nums.length - 1]! };
    }

    const parsedDates = sourceValues.map((v) => {
      if (v instanceof Date) return v.getTime();
      if (typeof v === 'string') { const t = Date.parse(v); return isNaN(t) ? null : t; }
      return null;
    });
    if (parsedDates.every((t) => t !== null)) {
      const timestamps = parsedDates as number[];
      const step = timestamps[1]! - timestamps[0]!;
      const isArithmetic = timestamps.every((t, i) => i === 0 || Math.abs(t - timestamps[i - 1]! - step) < 1);
      if (isArithmetic) return { type: 'date', step, base: timestamps[timestamps.length - 1]! };
    }
    return null;
  }

  private projectSeries(series: { type: 'number' | 'date'; step: number; base: number }, offset: number): unknown {
    if (series.type === 'number') return series.base + series.step * offset;
    return new Date(series.base + series.step * offset).toISOString().slice(0, 10);
  }

  /** Vertical fill: row 0 of the range is the source, subsequent rows are targets. */
  fillDown(range: CellRange): HistoryCellChange[] {
    if (range.start.row === range.end.row) return [];
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const changes: HistoryCellChange[] = [];
    const rows = this.resolveRangeWithDisplay(range);
    if (rows.length < 2) return [];
    const [source, ...targets] = rows;

    this.state.sourceData.update((data) => {
      const updated = [...data];
      const sourceRow = updated[source.source];
      if (!sourceRow) return updated;

      // B21: pre-compute series per column from the entire range's source rows.
      const seriesMap = new Map<string, ReturnType<typeof this.detectSeries>>();
      const allRows = [source, ...targets];
      for (let c = range.start.col; c <= range.end.col; c++) {
        const field = cols[c]?.field;
        if (!field) continue;
        const def = defMap.get(field);
        if (!def?.editable) continue;
        // Collect values from all-but-last rows as "source" values for series
        // detection. Using allRows.slice(0, -1) means [source, ...targets.slice(0, -1)]
        // so a range like [1, 2] → fill 5 rows detects step=1 → projects 3,4,5,6,7.
        const sourceRows = allRows.slice(0, -1);
        const vals = sourceRows.map(({ source: si }) => {
          const r = updated[si];
          if (!r) return undefined;
          return def.valueGetter ? def.valueGetter(r) : (r as Record<string, unknown>)[field];
        }).filter((v) => v !== undefined);
        seriesMap.set(field, this.detectSeries(vals));
      }

      for (const target of targets) {
        if (!updated[target.source]) continue;
        const rowCopy = { ...updated[target.source] } as Record<string, unknown>;
        let changed = false;
        const rowDelta = target.display - source.display;
        for (let c = range.start.col; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const sourceValue = def.valueGetter
            ? def.valueGetter(sourceRow)
            : (sourceRow as Record<string, unknown>)[field];
          const series = seriesMap.get(field) ?? null;
          const fillValue = series
            ? this.projectSeries(series, rowDelta)
            : this.shiftIfFormula(sourceValue, def.allowFormula === true, rowDelta, 0);
          const coerced = this.coerceAndValidate(field, fillValue, updated[target.source]);
          if (coerced === PASTE_SKIP) continue;
          const before = (updated[target.source] as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: target.source, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[target.source] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Horizontal fill: col 0 of the range is the source, subsequent cols are targets. */
  fillRight(range: CellRange): HistoryCellChange[] {
    if (range.start.col === range.end.col) return [];
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const sourceField = cols[range.start.col]?.field;
    if (!sourceField) return [];
    const sourceDef = defMap.get(sourceField);
    if (!sourceDef) return [];
    const changes: HistoryCellChange[] = [];

    const sourceIndices = this.resolveRangeSourceIndices(range);
    this.state.sourceData.update((data) => {
      const updated = [...data];
      for (const sourceIdx of sourceIndices) {
        const row = updated[sourceIdx];
        if (!row) continue;

        // B21: collect source values across all columns (except last) for series detection.
        const sourceColValues: unknown[] = [];
        for (let c = range.start.col; c < range.end.col; c++) {
          const f = cols[c]?.field;
          if (!f) break;
          const d = defMap.get(f);
          sourceColValues.push(d?.valueGetter ? d.valueGetter(row) : (row as Record<string, unknown>)[f]);
        }
        const series = this.detectSeries(sourceColValues);

        const sourceValue = sourceDef.valueGetter
          ? sourceDef.valueGetter(row)
          : (row as Record<string, unknown>)[sourceField];
        const rowCopy = { ...row } as Record<string, unknown>;
        let changed = false;
        for (let c = range.start.col + 1; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const colDelta = c - range.start.col;
          const fillValue = series
            ? this.projectSeries(series, colDelta)
            : this.shiftIfFormula(sourceValue, def.allowFormula === true, 0, colDelta);
          const coerced = this.coerceAndValidate(field, fillValue, row);
          if (coerced === PASTE_SKIP) continue;
          const before = (row as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[sourceIdx] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Ctrl+Enter: write `value` into every editable cell of `range`. */
  fillSelection(range: CellRange, value: unknown): HistoryCellChange[] {
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const changes: HistoryCellChange[] = [];
    const sourceIndices = this.resolveRangeSourceIndices(range);

    this.state.sourceData.update((data) => {
      const updated = [...data];
      for (const sourceIdx of sourceIndices) {
        const row = updated[sourceIdx];
        if (!row) continue;
        const rowCopy = { ...row } as Record<string, unknown>;
        let changed = false;
        for (let c = range.start.col; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const coerced = this.coerceAndValidate(field, value, row);
          if (coerced === PASTE_SKIP) continue;
          const before = (row as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[sourceIdx] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Clears every editable cell in `range` and returns the undo payload. */
  clearRange(range: CellRange): HistoryCellChange[] {
    const cols = this.state.visibleColumns();
    const defMap = this.state.columnDefMap();
    const changes: HistoryCellChange[] = [];
    const sourceIndices = this.resolveRangeSourceIndices(range);

    this.state.sourceData.update((data) => {
      const updated = [...data];
      for (const sourceIdx of sourceIndices) {
        const row = updated[sourceIdx];
        if (!row) continue;
        const rowCopy = { ...row } as Record<string, unknown>;
        let changed = false;
        for (let c = range.start.col; c <= range.end.col; c++) {
          const field = cols[c]?.field;
          if (!field) continue;
          const def = defMap.get(field);
          if (!def?.editable) continue;
          const coerced = this.coerceAndValidate(field, null, row);
          if (coerced === PASTE_SKIP) continue;
          const before = (row as Record<string, unknown>)[field];
          if (before === coerced) continue;
          rowCopy[field] = coerced;
          changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
          changed = true;
        }
        if (changed) updated[sourceIdx] = rowCopy as T;
      }
      return updated;
    });

    return changes;
  }

  /** Applies TSV `pasteRows` starting at `range.start`, returning actual changes.
   *  B20 — Excel-style tile: when the selection dimensions are integer multiples
   *  of the source block (or the source is 1×1), the source block is tiled to
   *  fill the whole selection. Otherwise pastes the block as-is. */
  applyPaste(range: CellRange, pasteRows: string[][]): HistoryCellChange[] {
    const cols = this.state.visibleColumns();
    const changes: HistoryCellChange[] = [];

    const selRows = range.end.row - range.start.row + 1;
    const selCols = range.end.col - range.start.col + 1;
    const srcRows = pasteRows.length;
    const srcCols = Math.max(...pasteRows.map((r) => r.length), 1);

    const tileRow = srcRows === 1 || selRows % srcRows === 0;
    const tileCol = srcCols === 1 || selCols % srcCols === 0;
    const shouldTile = tileRow && tileCol && (srcRows > 1 || srcCols > 1 || (pasteRows[0]?.length ?? 0) === 1);

    this.state.sourceData.update((data) => {
      const updated = [...data];

      if (shouldTile) {
        for (let dr = 0; dr < selRows; dr++) {
          const targetDisplayRow = range.start.row + dr;
          const sourceIdx = this.gridEngine.displayIndexToSourceIndex(targetDisplayRow);
          if (sourceIdx < 0) continue;
          const row = updated[sourceIdx];
          if (!row) continue;
          const pasteRow = pasteRows[dr % srcRows];
          if (!pasteRow) continue;
          const rowCopy = { ...row } as Record<string, unknown>;
          let changed = false;
          for (let dc = 0; dc < selCols; dc++) {
            const targetCol = range.start.col + dc;
            if (targetCol >= cols.length) break;
            const field = cols[targetCol]?.field;
            if (!field) continue;
            const cellVal = pasteRow[dc % srcCols] ?? '';
            const coerced = this.coerceAndValidate(field, cellVal, row);
            if (coerced === PASTE_SKIP) continue;
            const before = (row as Record<string, unknown>)[field];
            if (before === coerced) continue;
            rowCopy[field] = coerced;
            changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
            changed = true;
          }
          if (changed) updated[sourceIdx] = rowCopy as T;
        }
      } else {
        for (let ri = 0; ri < pasteRows.length; ri++) {
          const targetDisplayRow = range.start.row + ri;
          const sourceIdx = this.gridEngine.displayIndexToSourceIndex(targetDisplayRow);
          if (sourceIdx < 0) continue;
          const row = updated[sourceIdx];
          if (!row) continue;
          const rowCopy = { ...row } as Record<string, unknown>;
          let changed = false;
          for (let ci = 0; ci < pasteRows[ri].length; ci++) {
            const targetCol = range.start.col + ci;
            if (targetCol >= cols.length) break;
            const field = cols[targetCol]?.field;
            if (!field) continue;
            const coerced = this.coerceAndValidate(field, pasteRows[ri][ci], row);
            if (coerced === PASTE_SKIP) continue;
            const before = (row as Record<string, unknown>)[field];
            if (before === coerced) continue;
            rowCopy[field] = coerced;
            changes.push({ rowIndex: sourceIdx, field, before, after: coerced });
            changed = true;
          }
          if (changed) updated[sourceIdx] = rowCopy as T;
        }
      }

      return updated;
    });

    return changes;
  }

  /**
   * Reverses a previously-recorded list of changes by writing `before` back into
   * the cells. Used by the history engine for both undo and redo.
   */
  applyChanges(changes: HistoryCellChange[], direction: 'before' | 'after'): void {
    if (changes.length === 0) return;
    this.state.sourceData.update((data) => {
      const updated = [...data];
      // Group changes by rowIndex so each row is cloned once.
      const byRow = new Map<number, HistoryCellChange[]>();
      for (const change of changes) {
        const list = byRow.get(change.rowIndex) ?? [];
        list.push(change);
        byRow.set(change.rowIndex, list);
      }
      for (const [rowIndex, rowChanges] of byRow) {
        const row = updated[rowIndex];
        if (!row) continue;
        const rowCopy = { ...row } as Record<string, unknown>;
        for (const change of rowChanges) {
          rowCopy[change.field] = direction === 'before' ? change.before : change.after;
        }
        updated[rowIndex] = rowCopy as T;
      }
      return updated;
    });
  }

  /**
   * Coerces a raw value (string from TSV, unknown from fill, null for clears)
   * into the editor's expected type, running the field's validator when present.
   * Returns PASTE_SKIP when the column isn't editable or the value is rejected.
   */
  coerceAndValidate(field: string, rawValue: unknown, row: T): unknown {
    const def = this.state.columnDefMap().get(field);
    if (!def?.editable) return PASTE_SKIP;

    const editorType = def.cellEditor;

    if (rawValue === null) {
      let clearValue: unknown;
      switch (editorType) {
        case 'number':
          clearValue = null;
          break;
        case 'checkbox':
          clearValue = false;
          break;
        default:
          clearValue = '';
      }
      if (def.cellEditorValidator) {
        const result = def.cellEditorValidator(clearValue, row);
        if (result === false || typeof result === 'string') return PASTE_SKIP;
      }
      return clearValue;
    }

    let value: unknown = rawValue;

    if (editorType === 'number') {
      const num = Number(rawValue);
      if (isNaN(num)) return PASTE_SKIP;
      value = num;
    } else if (editorType === 'checkbox') {
      if (rawValue === 'true' || rawValue === true) {
        value = true;
      } else if (rawValue === 'false' || rawValue === false) {
        value = false;
      } else {
        return PASTE_SKIP;
      }
    } else if (
      (editorType === 'select' || editorType === 'custom') &&
      def.cellEditorOptions?.length
    ) {
      // Whitelist clipboard values against the declared allowed set. Applies
      // to both the built-in `select` editor and `custom` editors that expose
      // a constrained option list (combobox, pill-picker, …).
      const allowed = def.cellEditorOptions.map((o) => String(o.value));
      if (!allowed.includes(String(rawValue))) return PASTE_SKIP;
      value = rawValue;
    }

    if (def.cellEditorValidator) {
      const result = def.cellEditorValidator(value, row);
      if (result === false || typeof result === 'string') return PASTE_SKIP;
    }

    return value;
  }

  // ── B19 — RFC-4180 TSV escape / unescape ─────────────────────────────

  private escapeTsvCell(v: unknown): string {
    const s = v == null ? '' : String(v);
    if (s.includes('\t') || s.includes('\n') || s.includes('"')) {
      return '"' + s.replace(/"/g, '""') + '"';
    }
    return s;
  }

  /**
   * Parses a single TSV row string into cells, handling RFC-4180 quoted fields
   * that may contain embedded tabs, newlines, or double-quote pairs.
   */
  parseTsvRow(line: string): string[] {
    const cells: string[] = [];
    let i = 0;
    while (i <= line.length) {
      if (line[i] === '"') {
        i++;
        let cell = '';
        while (i < line.length) {
          if (line[i] === '"') {
            if (line[i + 1] === '"') {
              cell += '"';
              i += 2;
            } else {
              i++;
              break;
            }
          } else {
            cell += line[i++];
          }
        }
        cells.push(cell);
        if (line[i] === '\t') i++;
      } else {
        const end = line.indexOf('\t', i);
        if (end === -1) {
          cells.push(line.slice(i));
          break;
        } else {
          cells.push(line.slice(i, end));
          i = end + 1;
        }
      }
    }
    return cells;
  }

  /** TSV string for a range — used by copy / cut.
   *  B19: cells are RFC-4180 escaped so tab/newline/quote in values don't corrupt the TSV. */
  extractTsv(range: CellRange): string[][] {
    const cols = this.state.visibleColumns();
    const data = this.state.sourceData();
    const defMap = this.state.columnDefMap();
    const values: string[][] = [];

    for (let r = range.start.row; r <= range.end.row; r++) {
      const row = data[r];
      if (!row) continue;
      const rowValues: string[] = [];
      for (let c = range.start.col; c <= range.end.col; c++) {
        const field = cols[c]?.field;
        if (!field) {
          rowValues.push('');
          continue;
        }
        const def = defMap.get(field);
        const val = def?.valueGetter
          ? def.valueGetter(row)
          : (row as Record<string, unknown>)[field];
        rowValues.push(this.escapeTsvCell(val));
      }
      values.push(rowValues);
    }
    return values;
  }

  /**
   * Checks whether a cell sits on any edge of the current cut outline. Four
   * booleans rather than a single "isCut" so the view can paint only the edges
   * that face outward — which is what produces the Excel-like marching ants.
   */
  cutEdges(
    row: number,
    col: number
  ): { top: boolean; right: boolean; bottom: boolean; left: boolean; any: boolean } {
    const cut = this.state.cutSource();
    if (!cut) return { top: false, right: false, bottom: false, left: false, any: false };
    const minRow = Math.min(cut.start.row, cut.end.row);
    const maxRow = Math.max(cut.start.row, cut.end.row);
    const minCol = Math.min(cut.start.col, cut.end.col);
    const maxCol = Math.max(cut.start.col, cut.end.col);
    if (row < minRow || row > maxRow || col < minCol || col > maxCol) {
      return { top: false, right: false, bottom: false, left: false, any: false };
    }
    return {
      top: row === minRow,
      right: col === maxCol,
      bottom: row === maxRow,
      left: col === minCol,
      any: true,
    };
  }
}

import { Injectable, inject, NgZone } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { ColumnReorderEngine } from './column-reorder.engine';
import { HorizontalVirtualScrollEngine } from './horizontal-virtual-scroll.engine';

/** Minimum pixels of mouse movement before a drag is initiated */
const DRAG_THRESHOLD = 5;

/** Distance from edge in px at which auto-scroll activates */
const AUTO_SCROLL_ZONE = 60;

/** Max scroll speed in px/frame */
const AUTO_SCROLL_SPEED = 12;

@Injectable()
export class ColumnDragEngine {
  private readonly ngZone = inject(NgZone);
  private readonly state = inject(GridStateManager);
  private readonly reorderEngine = inject(ColumnReorderEngine);
  private readonly hvScrollEngine = inject(HorizontalVirtualScrollEngine);

  // --- Pending state (before threshold is met) ---
  private pending = false;
  private startX = 0;
  private startY = 0;
  private pendingSourceIndex = -1;
  private pendingHeaderRow: HTMLElement | null = null;

  // --- Active drag state (after threshold is met) ---
  private active = false;
  private originalIndex = -1;
  private headerRow: HTMLElement | null = null;
  private ghostEl: HTMLElement | null = null;
  private ghostOffsetX = 0;
  private ghostOffsetY = 0;

  // Full-height drop indicator
  private dropLineEl: HTMLElement | null = null;

  // Auto-scroll state
  private scrollEl: HTMLElement | null = null;
  private autoScrollRafId: number | null = null;
  private autoScrollDirection = 0; // -1 left, 0 none, 1 right

  private onMoveHandler = (e: MouseEvent) => this.onMouseMove(e);
  private onUpHandler = () => this.onMouseUp();

  /** Callback set by the header component to emit the reorder event */
  onReorder: ((previousIndex: number, currentIndex: number) => void) | null = null;

  /**
   * Called on mousedown on a header cell.
   * Does NOT preventDefault — this allows normal click/sort to work.
   * Only registers mousemove/mouseup listeners to detect drag.
   */
  startDrag(event: MouseEvent, sourceIndex: number, headerRow: HTMLElement): void {
    this.pending = true;
    this.startX = event.clientX;
    this.startY = event.clientY;
    this.pendingSourceIndex = sourceIndex;
    this.pendingHeaderRow = headerRow;

    this.ngZone.runOutsideAngular(() => {
      document.addEventListener('mousemove', this.onMoveHandler);
      document.addEventListener('mouseup', this.onUpHandler);
    });
  }

  private activateDrag(): void {
    this.pending = false;
    this.active = true;
    this.originalIndex = this.pendingSourceIndex;
    this.headerRow = this.pendingHeaderRow;

    document.body.style.cursor = 'grabbing';
    document.body.style.userSelect = 'none';

    const cols = this.state.unpinnedColumns();
    if (cols[this.originalIndex]) {
      this.ngZone.run(() => {
        this.state.draggingColumn.set(cols[this.originalIndex].field);
      });
    }

    this.createGhost();
  }

  private createGhost(): void {
    if (!this.headerRow) return;
    const headerCells = this.queryUnpinnedHeaderCells();
    // `originalIndex` is the absolute index in state.unpinnedColumns(); the
    // DOM only renders the virtualized window, so subtract its start offset.
    const localIndex = this.originalIndex - this.state.effectiveColumnRange().start;
    const sourceCell = headerCells[localIndex];
    if (!sourceCell) return;

    const rect = sourceCell.getBoundingClientRect();

    // Read the canonical width from state instead of the rect: when the
    // source cell happens to be the last rendered cell with `isLast=true`
    // (flex: 1 0 auto, no fixed width), the rect reflects flex stretching
    // and the ghost would span the entire scrollable width.
    const sourceCol = this.state.unpinnedColumns()[this.originalIndex];
    const width = sourceCol?.currentWidth ?? rect.width;

    // Clamp the click offset to the ghost's actual width so the cursor stays
    // over the ghost when the source was rendered wider than `currentWidth`.
    this.ghostOffsetX = Math.min(this.startX - rect.left, width);
    this.ghostOffsetY = this.startY - rect.top;

    const ghost = sourceCell.cloneNode(true) as HTMLElement;
    ghost.style.cssText = `
      position: fixed;
      top: ${rect.top}px;
      left: ${rect.left}px;
      width: ${width}px;
      height: ${rect.height}px;
      opacity: 0.92;
      z-index: 10000;
      pointer-events: none;
      box-shadow: 0 8px 24px rgba(0,0,0,0.22), 0 2px 8px rgba(0,0,0,0.12);
      border-radius: 6px;
      background: var(--color-background-primary, #fff);
      border: 2px solid var(--color-background-accent-inverse);
      transition: none;
    `;
    document.body.appendChild(ghost);
    this.ghostEl = ghost;

    sourceCell.style.opacity = '0.2';
  }

  private moveGhost(clientX: number, clientY: number): void {
    if (!this.ghostEl) return;
    this.ghostEl.style.left = `${clientX - this.ghostOffsetX}px`;
    this.ghostEl.style.top = `${clientY - this.ghostOffsetY}px`;
  }

  private removeGhost(): void {
    if (this.ghostEl) {
      this.ghostEl.remove();
      this.ghostEl = null;
    }
    if (this.headerRow) {
      const cells = this.queryUnpinnedHeaderCells();
      for (const cell of cells) {
        cell.style.opacity = '';
      }
    }
  }

  /** Returns the unpinned (i.e. reorderable) header cells in render order.
   * Filters out pinned-left/right cells which use `position: sticky` and
   * carry the `grid-header-cell-host--pinned` host class. */
  private queryUnpinnedHeaderCells(): HTMLElement[] {
    if (!this.headerRow) return [];
    return Array.from(
      this.headerRow.querySelectorAll<HTMLElement>(
        'ad-grid-header-cell:not(.grid-header-cell-host--pinned)',
      ),
    );
  }

  private onMouseMove(event: MouseEvent): void {
    if (this.pending && !this.active) {
      const dx = event.clientX - this.startX;
      const dy = event.clientY - this.startY;
      if (Math.abs(dx) + Math.abs(dy) < DRAG_THRESHOLD) return;
      this.activateDrag();
    }

    if (!this.active || !this.headerRow) return;

    this.moveGhost(event.clientX, event.clientY);
    this.updateAutoScroll(event.clientX);

    const headerCells = this.queryUnpinnedHeaderCells();
    const rangeStart = this.state.effectiveColumnRange().start;
    const cursorX = event.clientX;

    // Drop indices are absolute (relative to state.unpinnedColumns()), so
    // translate the local DOM index back to the absolute frame. While a
    // drag is active the virtualization engine forces `fullRange()`, so the
    // DOM holds every unpinned cell and start offset is 0 in practice — but
    // we keep the translation explicit in case the effect hasn't flushed.
    let dropIndex: number | null = null;
    for (let i = 0; i < headerCells.length; i++) {
      const rect = headerCells[i].getBoundingClientRect();
      const midX = rect.left + rect.width / 2;

      if (cursorX < midX) {
        dropIndex = rangeStart + i;
        break;
      }
    }

    // If cursor is past the last rendered cell, drop at the very end.
    if (dropIndex === null) {
      dropIndex = rangeStart + headerCells.length;
    }

    // Don't show indicator at the source column's own position or immediately after it
    if (dropIndex === this.originalIndex || dropIndex === this.originalIndex + 1) {
      dropIndex = null;
    }

    const current = this.state.dropIndicatorIndex();
    if (current !== dropIndex) {
      this.ngZone.run(() => {
        this.state.dropIndicatorIndex.set(dropIndex);
      });
    }

    // Position the full-height drop indicator line
    this.updateDropLine(dropIndex, headerCells);
  }

  private onMouseUp(): void {
    document.removeEventListener('mousemove', this.onMoveHandler);
    document.removeEventListener('mouseup', this.onUpHandler);

    if (!this.active) {
      this.cleanup();
      return;
    }

    document.body.style.cursor = '';
    document.body.style.userSelect = '';
    this.removeGhost();

    const prevIdx = this.originalIndex;
    const dropIdx = this.state.dropIndicatorIndex();

    // Auto-scroll moved the viewport while state.scrollLeft was frozen (see
    // HorizontalVirtualScrollEngine.onScroll). Push the real DOM scroll
    // position into state in the same tick as we clear draggingColumn —
    // otherwise the virtualization effect reruns with a stale scrollLeft and
    // renders a column range that doesn't match what the user is looking at.
    const scrollEl = this.scrollEl;
    this.ngZone.run(() => {
      if (scrollEl) {
        this.state.scrollLeft.set(scrollEl.scrollLeft);
        this.state.scrollViewportWidth.set(scrollEl.clientWidth);
      }
      this.state.draggingColumn.set(null);
      this.state.dropIndicatorIndex.set(null);
    });

    this.cleanup();

    if (dropIdx !== null && dropIdx !== prevIdx && dropIdx !== prevIdx + 1) {
      // Adjust target index: if dropping after the source, subtract 1
      // because the source will be removed first
      const targetIndex = dropIdx > prevIdx ? dropIdx - 1 : dropIdx;
      this.ngZone.run(() => {
        this.reorderEngine.reorderUnpinned(prevIdx, targetIndex);
        this.onReorder?.(prevIdx, targetIndex);
      });
    }
  }

  // ── Drop line (full-height indicator) ─────────────────────

  private updateDropLine(dropIndex: number | null, headerCells: HTMLElement[]): void {
    if (dropIndex === null) {
      this.removeDropLine();
      return;
    }

    // Translate the absolute drop index back to the local DOM index.
    const rangeStart = this.state.effectiveColumnRange().start;
    const localDropIndex = dropIndex - rangeStart;

    // Get the x position of the drop boundary
    let lineX: number;
    if (localDropIndex >= 0 && localDropIndex < headerCells.length) {
      const rect = headerCells[localDropIndex].getBoundingClientRect();
      lineX = rect.left;
    } else if (headerCells.length > 0) {
      const rect = headerCells[headerCells.length - 1].getBoundingClientRect();
      lineX = rect.right;
    } else {
      this.removeDropLine();
      return;
    }

    // The grid container itself is now the scroll viewport (no more nested
    // cdk-virtual-scroll-viewport). Use it as the reference rectangle.
    const grid = this.headerRow?.closest('.ad-grid');
    if (!grid) return;
    const gridRect = grid.getBoundingClientRect();

    if (!this.dropLineEl) {
      this.dropLineEl = document.createElement('div');
      this.dropLineEl.style.cssText = `
        position: fixed;
        width: 3px;
        background: var(--color-background-accent-inverse);
        z-index: 10001;
        pointer-events: none;
        border-radius: 2px;
      `;
      document.body.appendChild(this.dropLineEl);
    }

    this.dropLineEl.style.left = `${lineX - 1}px`;
    this.dropLineEl.style.top = `${gridRect.top}px`;
    this.dropLineEl.style.height = `${gridRect.height}px`;
  }

  private removeDropLine(): void {
    if (this.dropLineEl) {
      this.dropLineEl.remove();
      this.dropLineEl = null;
    }
  }

  // ── Auto-scroll helpers ──────────────────────────────────

  private findScrollElement(): HTMLElement | null {
    if (!this.headerRow) return null;
    // The actual scroll viewport is `.ad-grid__scroll` — the outer
    // `.ad-grid` is non-scrollable layout chrome. Reading scrollLeft on
    // the wrong element would always return 0 and feed a stale value into
    // the virtualization recompute on mouseup.
    return (this.headerRow.closest('.ad-grid__scroll') as HTMLElement | null) ?? null;
  }

  private updateAutoScroll(clientX: number): void {
    if (!this.scrollEl) {
      this.scrollEl = this.findScrollElement();
    }
    if (!this.scrollEl) return;

    const rect = this.scrollEl.getBoundingClientRect();
    const distFromLeft = clientX - rect.left;
    const distFromRight = rect.right - clientX;

    if (distFromLeft < AUTO_SCROLL_ZONE) {
      this.autoScrollDirection = -1;
    } else if (distFromRight < AUTO_SCROLL_ZONE) {
      this.autoScrollDirection = 1;
    } else {
      this.autoScrollDirection = 0;
    }

    if (this.autoScrollDirection !== 0 && this.autoScrollRafId === null) {
      this.startAutoScroll();
    } else if (this.autoScrollDirection === 0) {
      this.stopAutoScroll();
    }
  }

  private startAutoScroll(): void {
    const tick = () => {
      if (!this.scrollEl || this.autoScrollDirection === 0) {
        this.stopAutoScroll();
        return;
      }
      this.scrollEl.scrollLeft += this.autoScrollDirection * AUTO_SCROLL_SPEED;
      this.autoScrollRafId = requestAnimationFrame(tick);
    };
    this.autoScrollRafId = requestAnimationFrame(tick);
  }

  private stopAutoScroll(): void {
    if (this.autoScrollRafId !== null) {
      cancelAnimationFrame(this.autoScrollRafId);
      this.autoScrollRafId = null;
    }
    this.autoScrollDirection = 0;
  }

  private cleanup(): void {
    this.stopAutoScroll();
    this.removeDropLine();
    this.pending = false;
    this.active = false;
    this.originalIndex = -1;
    this.headerRow = null;
    this.pendingHeaderRow = null;
    this.ghostEl = null;
    this.scrollEl = null;
  }
}

import { inject, Injectable } from '@angular/core';
import { GridStateManager } from '../state/grid-state';

@Injectable()
export class ColumnReorderEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  reorder(previousIndex: number, newIndex: number): void {
    if (previousIndex === newIndex) return;

    this.state.columnStates.update((states) => {
      const reordered = [...states];
      const [moved] = reordered.splice(previousIndex, 1);
      reordered.splice(newIndex, 0, moved);
      return reordered.map((s, i) => ({ ...s, order: i }));
    });
  }

  /**
   * Reorder using indices relative to unpinned columns only.
   * Translates to global columnStates indices before applying.
   */
  reorderUnpinned(unpinnedPrevIndex: number, unpinnedNewIndex: number): void {
    if (unpinnedPrevIndex === unpinnedNewIndex) return;

    const states = this.state.columnStates();
    const sorted = [...states].sort((a, b) => a.order - b.order);
    const visible = sorted.filter((s) => s.visible);
    const unpinned = visible.filter((s) => !s.pinned);

    const prevField = unpinned[unpinnedPrevIndex]?.field;
    const nextField = unpinned[unpinnedNewIndex]?.field;
    if (!prevField || !nextField) return;

    const globalPrev = sorted.findIndex((s) => s.field === prevField);
    const globalNext = sorted.findIndex((s) => s.field === nextField);
    if (globalPrev === -1 || globalNext === -1) return;

    this.reorder(globalPrev, globalNext);
  }
}

import { Injectable, inject, signal, NgZone } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { ColumnResizeEvent } from '../models/column.model';

const MIN_COLUMN_WIDTH = 50;

@Injectable()
export class ColumnResizeEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);
  private readonly ngZone = inject(NgZone);

  /**
   * Timestamp (from `performance.now()`) of the last resize-end event.
   * Read by `grid-header-cell` to guard against a spurious click→sort
   * event firing immediately after a resize drag completes.
   */
  readonly lastResizeEndedAt = signal(0);

  private resizing = false;
  private resizeField: string | null = null;
  private startX = 0;
  private startWidth = 0;
  private invertDelta = false;

  private readonly onMouseMove = (event: MouseEvent): void => {
    if (!this.resizing || !this.resizeField) return;
    const rawDelta = event.clientX - this.startX;
    const delta = this.invertDelta ? -rawDelta : rawDelta;
    const def = this.state.columnDefMap().get(this.resizeField);
    const min = def?.minWidth ? parseInt(def.minWidth, 10) : MIN_COLUMN_WIDTH;
    const max = def?.maxWidth ? parseInt(def.maxWidth, 10) : Infinity;
    const newWidth = Math.max(min, Math.min(max, this.startWidth + delta));
    this.state.updateColumnState(this.resizeField, { currentWidth: newWidth });
  };

  private readonly onMouseUp = (): void => {
    if (!this.resizing) return;
    this.resizing = false;
    document.removeEventListener('mousemove', this.onMouseMove);
    document.removeEventListener('mouseup', this.onMouseUp);
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
    // Record the end timestamp so grid-header-cell can suppress the
    // click→sort event that fires in the same event loop tick.
    this.lastResizeEndedAt.set(performance.now());
  };

  startResize(field: string, event: MouseEvent): void {
    event.preventDefault();
    event.stopPropagation();

    const colState = this.state.columnStates().find((c) => c.field === field);
    if (!colState) return;

    this.resizing = true;
    this.resizeField = field;
    this.startX = event.clientX;
    this.startWidth = colState.currentWidth;
    this.invertDelta = colState.pinned === 'end';

    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';

    this.ngZone.runOutsideAngular(() => {
      document.addEventListener('mousemove', this.onMouseMove);
      document.addEventListener('mouseup', this.onMouseUp);
    });
  }

  getResizeEvent(field: string, previousWidth: number): ColumnResizeEvent {
    const colState = this.state.columnStates().find((c) => c.field === field);
    return {
      field,
      previousWidth,
      newWidth: colState?.currentWidth ?? previousWidth,
    };
  }
}

import { computed, effect, inject, Injectable, signal } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { GridEngine } from '../engine/grid-engine';

@Injectable()
export class ExpandableRowEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);
  /**
   * The grid pipeline — used by `pruneStalePending` to drop pending ids
   * whose row is no longer present (e.g. removed by a server-side
   * refresh / filter change while the row was still being measured).
   */
  private readonly gridEngine = inject<GridEngine<T>>(GridEngine, { optional: true });

  /**
   * Measured extra heights keyed by string `rowKey` (usually `rowId`).
   * Backed by a Map, but every write bumps `measureVersion` — a signal —
   * so `VerticalVirtualScrollEngine`'s layout effect re-runs and
   * rebuilds offsets whenever a detail row is (re)measured.
   *
   * **Why a counter and not a `signal<Map>`** : the Map mutates in place
   * for O(1) writes on a per-row basis; a signal<Map> would force
   * `Set.from(...)` or a new Map per measurement, which is allocation
   * pressure for nothing — the consumer only cares "did anything change",
   * not "what changed where". The counter answers that question for free.
   */
  private readonly measuredRowHeights = new Map<string, number>();
  private readonly measureVersion = signal(0);

  constructor() {
    // Drop pending ids whose row is no longer in `displayRows`. Without
    // this, a pending row removed mid-flight (server refresh / filter
    // change) would leak into `pendingExpansion` forever — the
    // measurement zone could not find the row and would never promote.
    if (this.gridEngine) {
      effect(
        () => {
          const rows = this.gridEngine!.displayRows();
          this.pruneStalePending(rows);
        },
        { allowSignalWrites: true },
      );
    }
  }

  /**
   * Records the measured height of a detail row identified by `rowKey`.
   * Bumps `measureVersion` so the virtual scroll engine re-runs its
   * offset rebuild — without it, the scroll engine reads stale heights
   * from the Map and the scrollbar bounces when the user scrolls past
   * an expanded row.
   *
   * @param rowKey  The row identifier (value of `rowIdField` for that row).
   * @param height  Full rendered height in pixels of the detail row element.
   */
  measureRow(rowKey: string, height: number): void {
    const prev = this.measuredRowHeights.get(rowKey);
    if (prev === height) return;
    this.measuredRowHeights.set(rowKey, height);
    this.measureVersion.update((v) => v + 1);
  }

  /**
   * Returns the last measured height for `rowKey`, or `undefined` when no
   * measurement has been recorded yet. Reading this OUTSIDE of a reactive
   * context skips dep tracking; engines must explicitly call
   * `trackMeasurements()` if they want to rebuild on measurement changes.
   */
  getExtraHeightForKey(rowKey: string): number | undefined {
    return this.measuredRowHeights.get(rowKey);
  }

  /**
   * Reactive dep — read once at the top of an `effect()` / `computed()`
   * that depends on row measurements. Updates whenever `measureRow` writes
   * a NEW height for any row. Returns the current version as a sentinel.
   */
  trackMeasurements(): number {
    return this.measureVersion();
  }

  readonly hasExpandedRows = computed(() => this.state.expandedRowIds().size > 0);

  /**
   * 2-phase toggle. Expand goes via `pendingExpansion` so the measurement
   * zone can size the detail row off-screen BEFORE the visible body mounts
   * it. Collapse is direct — no measurement needed.
   *
   * If the row is currently pending (user clicked expand and then clicked
   * again before measurement landed), we remove it from pending so it
   * never transitions to expanded.
   */
  toggleRow(rowId: unknown): void {
    // Already visibly expanded → collapse path.
    if (this.state.expandedRowIds().has(rowId)) {
      this.state.expandedRowIds.update((ids) => {
        const next = new Set(ids);
        next.delete(rowId);
        return next;
      });
      // Defensive: also drop from pending if somehow present.
      if (this.state.pendingExpansion().has(rowId)) {
        this.state.pendingExpansion.update((ids) => {
          const next = new Set(ids);
          next.delete(rowId);
          return next;
        });
      }
      return;
    }
    // Pending measurement → user wants to cancel the expansion.
    if (this.state.pendingExpansion().has(rowId)) {
      this.state.pendingExpansion.update((ids) => {
        const next = new Set(ids);
        next.delete(rowId);
        return next;
      });
      return;
    }
    // Not expanded and not pending → start the 2-phase expansion.
    this.state.pendingExpansion.update((ids) => {
      const next = new Set(ids);
      next.add(rowId);
      return next;
    });
  }

  /**
   * Imperative API. Adds to pending if not already pending or expanded.
   * Promotion is driven by the measurement zone.
   */
  expandRow(rowId: unknown): void {
    if (this.state.expandedRowIds().has(rowId)) return;
    if (this.state.pendingExpansion().has(rowId)) return;
    this.state.pendingExpansion.update((ids) => {
      const next = new Set(ids);
      next.add(rowId);
      return next;
    });
  }

  /**
   * Direct collapse — drop from both sets so a pending-but-not-yet-promoted
   * row is also cancelled.
   */
  collapseRow(rowId: unknown): void {
    if (this.state.expandedRowIds().has(rowId)) {
      this.state.expandedRowIds.update((ids) => {
        const next = new Set(ids);
        next.delete(rowId);
        return next;
      });
    }
    if (this.state.pendingExpansion().has(rowId)) {
      this.state.pendingExpansion.update((ids) => {
        const next = new Set(ids);
        next.delete(rowId);
        return next;
      });
    }
  }

  collapseAll(): void {
    this.state.expandedRowIds.set(new Set());
    this.state.pendingExpansion.set(new Set());
  }

  /**
   * Called by the measurement zone once a hidden detail row has reported
   * its height via ResizeObserver. Atomically removes the id from
   * `pendingExpansion` and adds it to `expandedRowIds` — the visible body
   * template now mounts the detail row, and because the height was already
   * cached via `measureRow` just before, the virtual-scroll engine
   * rebuilds offsets with the correct value on the FIRST visible render.
   *
   * Safe to call when the row was already cancelled (the pending check
   * exits early so we don't accidentally re-expand a row the user just
   * collapsed mid-measurement).
   */
  promoteFromPending(rowId: unknown): void {
    if (!this.state.pendingExpansion().has(rowId)) return;
    this.state.pendingExpansion.update((ids) => {
      const next = new Set(ids);
      next.delete(rowId);
      return next;
    });
    this.state.expandedRowIds.update((ids) => {
      const next = new Set(ids);
      next.add(rowId);
      return next;
    });
  }

  /**
   * Visible-expansion check. Returns `true` ONLY for rows that have been
   * promoted (i.e. measured + mounted in the visible layout). Pending
   * rows are intentionally NOT reported as expanded — that's how the
   * visible body template avoids rendering a detail row in parallel
   * with the one in the measurement zone.
   */
  isRowExpanded(rowId: unknown): boolean {
    return this.state.expandedRowIds().has(rowId);
  }

  /** True when the row's detail is currently being measured off-screen. */
  isRowPending(rowId: unknown): boolean {
    return this.state.pendingExpansion().has(rowId);
  }

  /**
   * Removes pending ids whose row data is no longer present in
   * `displayRows()` — this keeps the measurement zone from spinning on
   * an id whose row was filtered/paginated away mid-measurement.
   */
  private pruneStalePending(rows: ReadonlyArray<{ type: string; data?: T }>): void {
    const pending = this.state.pendingExpansion();
    if (pending.size === 0) return;
    const idField = this.state.rowIdField();
    const present = new Set<unknown>();
    for (const row of rows) {
      if (row.type !== 'data' || !row.data) continue;
      const id = (row.data as Record<string, unknown>)[idField];
      if (id !== undefined) present.add(id);
    }
    let changed = false;
    const next = new Set<unknown>();
    pending.forEach((id) => {
      if (present.has(id)) {
        next.add(id);
      } else {
        changed = true;
      }
    });
    if (changed) this.state.pendingExpansion.set(next);
  }
}

import { inject, Injectable } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { ColumnStateEntry, ColumnDef } from '../models/column.model';

export interface ExportOptions {
  filename?: string;
  separator?: string;
  includeHeaders?: boolean;
  columns?: string[];
}

@Injectable()
export class ExportEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  // ── helpers ─────────────────────────────────────────────────────────────

  private escapeCsvValue(value: string, separator: string): string {
    if (value.includes(separator) || value.includes('"') || value.includes('\n')) {
      return `"${value.replace(/"/g, '""')}"`;
    }
    return value;
  }

  private buildCsvRow(
    row: T,
    cols: ColumnStateEntry[],
    defMap: Map<string, ColumnDef<T>>,
    separator: string,
  ): string {
    return cols
      .map((col) => {
        const def = defMap.get(col.field);
        let value: unknown;
        if (def?.valueGetter) {
          value = def.valueGetter(row);
        } else {
          value = (row as Record<string, unknown>)[col.field];
        }
        if (def?.valueFormatter) {
          return this.escapeCsvValue(def.valueFormatter(value, row), separator);
        }
        return this.escapeCsvValue(String(value ?? ''), separator);
      })
      .join(separator);
  }

  private downloadBlob(filename: string, blob: Blob): void {
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    link.style.display = 'none';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }

  private downloadFile(filename: string, content: string, mimeType: string): void {
    this.downloadBlob(filename, new Blob([content], { type: mimeType }));
  }

  // ── streaming helpers (B18) ──────────────────────────────────────────────

  private async exportCsvStreaming(
    data: T[],
    cols: ColumnStateEntry[],
    defMap: Map<string, ColumnDef<T>>,
    filename: string,
    separator: string,
    includeHeaders: boolean,
  ): Promise<void> {
    const encoder = new TextEncoder();
    const ts = new TransformStream<Uint8Array, Uint8Array>();
    const writer = ts.writable.getWriter();

    if (includeHeaders) {
      const headerRow =
        cols
          .map((col) => this.escapeCsvValue(defMap.get(col.field)?.headerName ?? col.field, separator))
          .join(separator) + '\n';
      await writer.write(encoder.encode(headerRow));
    }

    const CHUNK = 1_000;
    for (let i = 0; i < data.length; i += CHUNK) {
      const chunk =
        data
          .slice(i, i + CHUNK)
          .map((row) => this.buildCsvRow(row, cols, defMap, separator))
          .join('\n') + '\n';
      await writer.write(encoder.encode(chunk));
    }

    await writer.close();
    const blob = await new Response(ts.readable).blob();
    this.downloadBlob(`${filename}.csv`, blob);
  }

  private async exportJsonStreaming(
    data: T[],
    fields: string[],
    defMap: Map<string, ColumnDef<T>>,
    filename: string,
  ): Promise<void> {
    const encoder = new TextEncoder();
    const ts = new TransformStream<Uint8Array, Uint8Array>();
    const writer = ts.writable.getWriter();

    await writer.write(encoder.encode('[\n'));

    const CHUNK = 1_000;
    for (let i = 0; i < data.length; i += CHUNK) {
      const slice = data.slice(i, i + CHUNK);
      const isLast = i + CHUNK >= data.length;
      const rows = slice.map((row) => {
        const obj: Record<string, unknown> = {};
        for (const field of fields) {
          const def = defMap.get(field);
          obj[field] = def?.valueGetter
            ? def.valueGetter(row)
            : (row as Record<string, unknown>)[field];
        }
        return obj;
      });
      const chunk =
        rows
          .map((obj, idx) => '  ' + JSON.stringify(obj) + (isLast && idx === rows.length - 1 ? '' : ','))
          .join('\n') + '\n';
      await writer.write(encoder.encode(chunk));
    }

    await writer.write(encoder.encode(']'));
    await writer.close();
    const blob = await new Response(ts.readable).blob();
    this.downloadBlob(`${filename}.json`, blob);
  }

  // ── public API ───────────────────────────────────────────────────────────

  exportCsv(data: T[], options: ExportOptions = {}): void {
    const {
      filename = 'export',
      separator = ',',
      includeHeaders = true,
      columns,
    } = options;

    const cols = columns
      ? this.state.visibleColumns().filter((c) => columns.includes(c.field))
      : this.state.visibleColumns();

    const defMap = this.state.columnDefMap();

    // B18: stream when available, synchronous fallback otherwise.
    if (typeof TransformStream !== 'undefined') {
      void this.exportCsvStreaming(data, cols, defMap, filename, separator, includeHeaders);
      return;
    }

    const lines: string[] = [];
    if (includeHeaders) {
      lines.push(
        cols
          .map((col) => this.escapeCsvValue(defMap.get(col.field)?.headerName ?? col.field, separator))
          .join(separator),
      );
    }
    for (const row of data) {
      lines.push(this.buildCsvRow(row, cols, defMap, separator));
    }
    this.downloadFile(`${filename}.csv`, lines.join('\n'), 'text/csv;charset=utf-8;');
  }

  exportJson(data: T[], options: { filename?: string; columns?: string[] } = {}): void {
    const { filename = 'export', columns } = options;

    const cols = columns
      ? this.state.visibleColumns().filter((c) => columns.includes(c.field))
      : this.state.visibleColumns();

    const fields = cols.map((c) => c.field);
    const defMap = this.state.columnDefMap();

    // B18: stream when available, synchronous fallback otherwise.
    if (typeof TransformStream !== 'undefined') {
      void this.exportJsonStreaming(data, fields, defMap, filename);
      return;
    }

    const exportData = data.map((row) => {
      const obj: Record<string, unknown> = {};
      for (const field of fields) {
        const def = defMap.get(field);
        obj[field] = def?.valueGetter
          ? def.valueGetter(row)
          : (row as Record<string, unknown>)[field];
      }
      return obj;
    });
    this.downloadFile(`${filename}.json`, JSON.stringify(exportData, null, 2), 'application/json;charset=utf-8;');
  }
}

import { Injectable, Signal, computed, inject, signal } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { ColumnDef } from '../models/column.model';
import {
  DEFAULT_OPERATORS,
  DEFAULT_OPERATOR_PER_TYPE,
  FilterChangeReason,
  FilterColumnDescriptor,
  FilterCondition,
  FilterDataType,
  FilterEvent,
  FilterModel,
  FilterOperator,
  FilterValue,
  OPERATOR_LABELS,
  RANGE_OPERATORS,
  VALUELESS_OPERATORS,
  generateConditionId,
  isConditionComplete,
} from '../models/filter.model';

type PreparedCondition<T> = { cond: FilterCondition; col: ColumnDef<T> | undefined; type: FilterDataType };

type Predicate = (cell: unknown, value: FilterValue) => boolean;

@Injectable()
export class FilterEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  /** Latest mutation, used by the grid shell to emit `filterChange` once. */
  private readonly lastChange = signal<FilterEvent | null>(null);

  readonly conditions: Signal<FilterCondition[]> = computed(
    () => this.state.filterModel().conditions
  );

  readonly hasActiveFilters = computed(
    () =>
      this.conditions().length > 0 ||
      Object.values(this.state.quickFilters()).some((v) => v != null && v !== ''),
  );

  readonly lastEvent = this.lastChange.asReadonly();

  // ------------------------------------------------------------------
  // Mutations
  // ------------------------------------------------------------------

  /** Replaces the whole model in one go. Used by the drawer's Apply button. */
  setModel(model: FilterModel, reason: FilterChangeReason = 'replace'): void {
    this.state.filterModel.set({ conditions: [...model.conditions] });
    this.state.pageIndex.set(0);
    this.notify(reason, null);
  }

  addCondition(condition: FilterCondition): void {
    this.state.filterModel.update((m) => ({
      conditions: [...m.conditions, condition],
    }));
    this.state.pageIndex.set(0);
    this.notify('add', condition);
  }

  updateCondition(id: string, patch: Partial<FilterCondition>): void {
    let updated: FilterCondition | null = null;
    this.state.filterModel.update((m) => ({
      conditions: m.conditions.map((c) => {
        if (c.id !== id) return c;
        const next = { ...c, ...patch, value: { ...c.value, ...(patch.value ?? {}) } };
        updated = next;
        return next;
      }),
    }));
    this.state.pageIndex.set(0);
    if (updated) this.notify('update', updated);
  }

  removeCondition(id: string): void {
    const removed = this.state.filterModel().conditions.find((c) => c.id === id) ?? null;
    this.state.filterModel.update((m) => ({
      conditions: m.conditions.filter((c) => c.id !== id),
    }));
    this.state.pageIndex.set(0);
    this.notify('remove', removed);
  }

  reorderConditions(fromIndex: number, toIndex: number): void {
    this.state.filterModel.update((m) => {
      if (fromIndex === toIndex) return m;
      const next = [...m.conditions];
      const [item] = next.splice(fromIndex, 1);
      if (!item) return m;
      next.splice(toIndex, 0, item);
      return { conditions: next };
    });
    this.state.pageIndex.set(0);
    this.notify('reorder', null);
  }

  clearAll(): void {
    if (this.state.filterModel().conditions.length === 0) return;
    this.state.filterModel.set({ conditions: [] });
    this.state.pageIndex.set(0);
    this.notify('clear', null);
  }

  /** Convenience: drop all conditions that target a given field. */
  removeByField(field: string): void {
    const before = this.state.filterModel().conditions;
    const after = before.filter((c) => c.field !== field);
    if (after.length === before.length) return;
    this.state.filterModel.set({ conditions: after });
    this.state.pageIndex.set(0);
    this.notify('replace', null);
  }

  /**
   * Quick filters — per-column inline inputs (rendered by the
   * `<ad-grid-quick-filter-row>` component above the body). Independent
   * of the builder model: composed at evaluation time with AND semantics.
   * Set an empty / nullish value to clear the entry.
   */
  setQuickFilter(field: string, value: string | null | undefined): void {
    this.state.quickFilters.update((cur) => {
      const next = { ...cur };
      if (value == null || value === '') {
        delete next[field];
      } else {
        next[field] = value;
      }
      return next;
    });
    this.state.pageIndex.set(0);
  }

  /** Returns the current quick-filter value for the given column, or `''`. */
  getQuickFilter(field: string): string {
    return this.state.quickFilters()[field] ?? '';
  }

  /** Clears every quick-filter input in one go. */
  clearQuickFilters(): void {
    if (Object.keys(this.state.quickFilters()).length === 0) return;
    this.state.quickFilters.set({});
    this.state.pageIndex.set(0);
  }

  /**
   * Drops conditions whose value is not yet complete. Called when a filter
   * builder is dismissed: a row the user added but never filled in must not
   * linger in the model as a phantom active filter.
   */
  dropIncompleteConditions(): void {
    const defMap = this.state.columnDefMap();
    const before = this.state.filterModel().conditions;
    const after = before.filter((c) => this.isComplete(c, defMap.get(c.field)));
    if (after.length === before.length) return;
    this.state.filterModel.set({ conditions: after });
    this.state.pageIndex.set(0);
    this.notify('replace', null);
  }

  // ------------------------------------------------------------------
  // Evaluation
  // ------------------------------------------------------------------

  /**
   * Evaluates the current model against the provided data.
   * In `server` filterMode the grid delegates filtering to the consumer — returns input as-is.
   *
   * Quick filters (per-column inline inputs) and builder conditions live in
   * independent state slots. They are composed here at evaluation time: a
   * row survives iff (every quick filter passes) AND (the builder model
   * passes). Quick filters always AND together — there is no combinator
   * picker on the inline row. This matches the Vue grid's behaviour.
   */
  filterData(data: T[]): T[] {
    if (this.state.filterMode() === 'server') return data;

    const defMap = this.state.columnDefMap();
    const conditions = this.state.filterModel().conditions.filter((c) =>
      this.isComplete(c, defMap.get(c.field))
    );

    const quickFilters = this.state.quickFilters();
    const quickFields = Object.keys(quickFilters).filter((f) => {
      const v = quickFilters[f];
      return v != null && v !== '';
    });

    if (conditions.length === 0 && quickFields.length === 0) return data;

    const prepared: PreparedCondition<T>[] = conditions.map((c) => ({
      cond: c,
      col: defMap.get(c.field),
      type: resolveFilterType(defMap.get(c.field)),
    }));

    return data.filter((row) => {
      // Quick filters first — bail out as soon as one fails (cheap AND).
      for (const field of quickFields) {
        const col = defMap.get(field);
        const raw = col?.valueGetter
          ? col.valueGetter(row)
          : (row as Record<string, unknown>)[field];
        const needle = String(quickFilters[field]).toLowerCase();
        if (!String(raw ?? '').toLowerCase().includes(needle)) return false;
      }
      if (prepared.length === 0) return true;
      let pass = this.matchRow(row, prepared[0]);
      for (let i = 1; i < prepared.length; i++) {
        const result = this.matchRow(row, prepared[i]);
        pass = prepared[i].cond.combinator === 'and' ? pass && result : pass || result;
      }
      return pass;
    });
  }

  private isComplete(condition: FilterCondition, col: ColumnDef<T> | undefined): boolean {
    if (resolveFilterType(col) === 'custom') {
      const fn = col?.filterIsComplete;
      return fn
        ? fn(condition.value)
        : condition.value.value != null && condition.value.value !== '';
    }
    return isConditionComplete(condition);
  }

  private matchRow(row: T, item: PreparedCondition<T>): boolean {
    if (item.type === 'custom') {
      const fn = item.col?.filterPredicate;
      return fn ? fn(row, item.cond.value) : true;
    }
    return matchOne(row, item.cond, item.col, item.type);
  }

  // ------------------------------------------------------------------
  // Helpers
  // ------------------------------------------------------------------

  /** Returns a human-readable label for a condition ("Status equals En stock"). */
  toLabel(condition: FilterCondition): string {
    const def = this.state.columnDefMap().get(condition.field);
    const col = def?.headerName ?? condition.field;
    const op = OPERATOR_LABELS[condition.operator] ?? condition.operator;

    if (VALUELESS_OPERATORS.has(condition.operator)) {
      return `${col} ${op}`;
    }
    const value = formatValue(condition.value.value, def);
    if (RANGE_OPERATORS.has(condition.operator)) {
      const to = formatValue(condition.value.valueTo, def);
      return `${col} ${op} ${value} – ${to}`;
    }
    return `${col} ${op} ${value}`;
  }

  /** Returns the filter data type inferred for a column. */
  getFilterType(field: string): FilterDataType {
    return resolveFilterType(this.state.columnDefMap().get(field));
  }

  /**
   * Builds the column descriptors consumed by the filter builder UI.
   *
   * All `filterable` columns are included, even those that ship a custom
   * `filterTemplate`. The custom template drives the inline header filter
   * row (quick per-column UI), while the builder — rendered in the toolbar
   * drawer and in the column-menu overlay — always uses the generic editors.
   * The two mechanisms are complementary and can coexist on the same column.
   */
  describeFilterableColumns(): FilterColumnDescriptor[] {
    const defs = this.state.columnDefs();
    return defs.filter((d) => d.filterable).map((d) => this.describeColumn(d));
  }

  describeColumn(def: ColumnDef<T>): FilterColumnDescriptor {
    if (def.filterComponent) {
      return {
        field: def.field,
        headerName: def.headerName ?? def.field,
        filterType: 'custom',
        operators: [],
        defaultOperator: 'equals',
        filterComponent: def.filterComponent,
        filterIsComplete: def.filterIsComplete,
      };
    }
    const type = resolveFilterType(def);
    const operators =
      def.filterOperators && def.filterOperators.length > 0
        ? def.filterOperators
        : DEFAULT_OPERATORS[type];
    const defaultOp = def.defaultFilterOperator ?? DEFAULT_OPERATOR_PER_TYPE[type];
    return {
      field: def.field,
      headerName: def.headerName ?? def.field,
      filterType: type,
      operators,
      defaultOperator: operators.includes(defaultOp) ? defaultOp : operators[0],
      options: def.filterOptions ?? inferOptionsFromData(this.state.sourceData(), def, type),
    };
  }

  /** Factory for new conditions created by the UI. */
  makeCondition(
    field: string,
    isFirst: boolean,
    overrides: Partial<FilterCondition> = {}
  ): FilterCondition {
    const def = this.state.columnDefMap().get(field);
    const descriptor = def ? this.describeColumn(def) : null;
    return {
      id: generateConditionId(),
      combinator: isFirst ? 'and' : 'and',
      field,
      operator: descriptor?.defaultOperator ?? 'contains',
      value: {},
      ...overrides,
    };
  }

  // ------------------------------------------------------------------
  // Internal
  // ------------------------------------------------------------------

  private notify(reason: FilterChangeReason, condition: FilterCondition | null): void {
    this.lastChange.set({
      model: { conditions: this.state.filterModel().conditions.slice() },
      condition,
      reason,
    });
  }
}

// --------------------------------------------------------------------
// Pure helpers
// --------------------------------------------------------------------

function resolveFilterType<T>(def: ColumnDef<T> | undefined): FilterDataType {
  if (!def) return 'text';
  if (def.filterType) return def.filterType;
  switch (def.cellEditor) {
    case 'number':
      return 'number';
    case 'date':
      return 'date';
    case 'select':
      return 'set';
    case 'checkbox':
    case 'toggle':
      return 'boolean';
    default:
      return 'text';
  }
}

function matchOne<T>(
  row: T,
  condition: FilterCondition,
  col: ColumnDef<T> | undefined,
  type: FilterDataType
): boolean {
  const raw = col?.valueGetter
    ? col.valueGetter(row)
    : (row as Record<string, unknown>)[condition.field];

  const predicate = PREDICATES[type]?.[condition.operator];
  if (!predicate) return true;
  return predicate(raw, condition.value);
}

function formatValue<T>(value: unknown, def: ColumnDef<T> | undefined): string {
  if (value == null || value === '') return '';
  if (Array.isArray(value)) {
    return value.map((v) => formatSingleOption(v, def)).join(', ');
  }
  return formatSingleOption(value, def);
}

function formatSingleOption<T>(value: unknown, def: ColumnDef<T> | undefined): string {
  if (def?.filterOptions) {
    const opt = def.filterOptions.find((o) => String(o.value) === String(value));
    if (opt) return String(opt.label);
  }
  return String(value);
}

function inferOptionsFromData<T>(
  data: T[],
  def: ColumnDef<T>,
  type: FilterDataType
): { value: unknown; label: string }[] | undefined {
  if (type !== 'set') return undefined;
  const seen = new Set<string>();
  const out: { value: unknown; label: string }[] = [];
  for (const row of data) {
    const v = def.valueGetter ? def.valueGetter(row) : (row as Record<string, unknown>)[def.field];
    if (v == null) continue;
    const key = String(v);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({ value: v, label: key });
    if (out.length >= 200) break;
  }
  return out;
}

// --------------------------------------------------------------------
// Predicate table — dispatched by (filterType, operator)
// --------------------------------------------------------------------

const textContains: Predicate = (cell, { value }) =>
  String(cell ?? '')
    .toLowerCase()
    .includes(String(value ?? '').toLowerCase());

const textNotContains: Predicate = (cell, v) => !textContains(cell, v);

const textEquals: Predicate = (cell, { value }) =>
  String(cell ?? '').toLowerCase() === String(value ?? '').toLowerCase();

const textNotEquals: Predicate = (cell, v) => !textEquals(cell, v);

const textStartsWith: Predicate = (cell, { value }) =>
  String(cell ?? '')
    .toLowerCase()
    .startsWith(String(value ?? '').toLowerCase());

const textEndsWith: Predicate = (cell, { value }) =>
  String(cell ?? '')
    .toLowerCase()
    .endsWith(String(value ?? '').toLowerCase());

const blank: Predicate = (cell) => cell == null || cell === '';
const notBlank: Predicate = (cell) => !blank(cell, { value: undefined });

const numEquals: Predicate = (cell, { value }) => toNum(cell) === toNum(value);
const numNotEquals: Predicate = (cell, v) => !numEquals(cell, v);
const numGt: Predicate = (cell, { value }) => toNum(cell) > toNum(value);
const numGte: Predicate = (cell, { value }) => toNum(cell) >= toNum(value);
const numLt: Predicate = (cell, { value }) => toNum(cell) < toNum(value);
const numLte: Predicate = (cell, { value }) => toNum(cell) <= toNum(value);
const numBetween: Predicate = (cell, { value, valueTo }) => {
  const n = toNum(cell);
  return n >= toNum(value) && n <= toNum(valueTo);
};

const dateEquals: Predicate = (cell, { value }) => toTime(cell) === toTime(value);
const dateNotEquals: Predicate = (cell, v) => !dateEquals(cell, v);
const dateGt: Predicate = (cell, { value }) => toTime(cell) > toTime(value);
const dateGte: Predicate = (cell, { value }) => toTime(cell) >= toTime(value);
const dateLt: Predicate = (cell, { value }) => toTime(cell) < toTime(value);
const dateLte: Predicate = (cell, { value }) => toTime(cell) <= toTime(value);
const dateBetween: Predicate = (cell, { value, valueTo }) => {
  const t = toTime(cell);
  return t >= toTime(value) && t <= toTime(valueTo);
};

const setIn: Predicate = (cell, { value }) => {
  const arr = Array.isArray(value) ? value : [value];
  if (arr.length === 0) return true;
  return arr.some((v) => String(v) === String(cell));
};
const setNotIn: Predicate = (cell, v) => !setIn(cell, v);

const boolEquals: Predicate = (cell, { value }) => {
  const expected = value === true || value === 'true' || value === 1;
  const actual = cell === true || cell === 'true' || cell === 1;
  return expected === actual;
};

function toNum(v: unknown): number {
  const n = typeof v === 'number' ? v : Number(v);
  return Number.isFinite(n) ? n : NaN;
}

function toTime(v: unknown): number {
  if (v instanceof Date) return v.getTime();
  if (typeof v === 'number') return v;
  if (typeof v === 'string') {
    const parsed = Date.parse(v);
    return Number.isFinite(parsed) ? parsed : NaN;
  }
  return NaN;
}

const PREDICATES: Record<FilterDataType, Partial<Record<FilterOperator, Predicate>>> = {
  text: {
    contains: textContains,
    notContains: textNotContains,
    equals: textEquals,
    notEquals: textNotEquals,
    startsWith: textStartsWith,
    endsWith: textEndsWith,
    blank,
    notBlank,
  },
  number: {
    equals: numEquals,
    notEquals: numNotEquals,
    gt: numGt,
    gte: numGte,
    lt: numLt,
    lte: numLte,
    between: numBetween,
    blank,
    notBlank,
  },
  date: {
    equals: dateEquals,
    notEquals: dateNotEquals,
    gt: dateGt,
    gte: dateGte,
    lt: dateLt,
    lte: dateLte,
    between: dateBetween,
    blank,
    notBlank,
  },
  set: {
    in: setIn,
    notIn: setNotIn,
    blank,
    notBlank,
  },
  boolean: {
    equals: boolEquals,
    blank,
    notBlank,
  },
  // custom filters are evaluated via ColumnDef.filterPredicate — no predicates here.
  custom: {},
};

