import { Injectable, computed, signal } from '@angular/core';
import { ColumnDef, ColumnStateEntry, SortDirection } from '../models/column.model';
import { SortDef } from '../models/sort.model';
import { CellCoord, CellEditState } from '../models/cell.model';
import { GridDensity, GroupEntry } from '../models/grid-events.model';
import { FilterModel, FilterMode } from '../models/filter.model';
import { LoadingStrategy } from '../models/pagination.model';

const DEFAULT_COLUMN_WIDTH = 150;

@Injectable()
export class GridStateManager<T = unknown> {
  // --- Source Data ---
  readonly sourceData = signal<T[]>([]);
  readonly totalItems = signal<number>(0);

  // --- Mode ---
  readonly mode = signal<'client' | 'server'>('client');

  // --- Group Mode ('client' = default GroupEngine pipeline; 'server' = ServerGroupEngine) ---
  readonly groupMode = signal<'client' | 'server'>('client');

  // --- Filter Mode (independent of mode — allows server pagination + client filtering) ---
  readonly filterMode = signal<FilterMode>('client');

  // --- Loading Strategy ---
  readonly loadingStrategy = signal<LoadingStrategy>('pagination');

  // --- Columns ---
  readonly columnDefs = signal<ColumnDef<T>[]>([]);
  readonly columnStates = signal<ColumnStateEntry[]>([]);

  // --- Sort ---
  readonly activeSorts = signal<SortDef[]>([]);

  // --- Group ---
  readonly groupColumns = signal<GroupEntry[]>([]);
  readonly expandedGroups = signal<Set<string>>(new Set());

  // --- Filter ---
  /**
   * Unified filter state: single source of truth for the multi-condition
   * builder. The tag-bar displays a derived view via `FilterEngine.toLabel()`.
   */
  readonly filterModel = signal<FilterModel>({ conditions: [] });

  /**
   * Per-column inline "quick filter" values. Independent of the builder
   * model — the FilterEngine composes both at evaluation time. Shape is
   * `{ [field]: rawInput }` where the raw input is whatever the inline
   * input committed (string for the default text input). Matches the Vue
   * grid's `quickFilters` state slot.
   */
  readonly quickFilters = signal<Record<string, string>>({});

  // --- Pagination ---
  /** `false` disables paging entirely — `paginatedData` returns the full
   * filtered set instead of slicing by `pageSize`. */
  readonly paginationEnabled = signal<boolean>(true);
  readonly pageIndex = signal<number>(0);
  readonly pageSize = signal<number>(25);
  readonly visibleRowCount = signal<number>(0);

  // --- Scroll ---
  readonly scrollLeft = signal<number>(0);
  readonly scrollTop = signal<number>(0);
  readonly scrollViewportWidth = signal<number>(0);
  readonly scrollViewportHeight = signal<number>(0);
  readonly scrollContentTotalWidth = signal<number>(0);

  // --- Horizontal virtual scroll ---
  readonly horizontalVirtualScrollEnabled = signal<boolean>(false);
  readonly visibleColumnRange = signal<{ start: number; end: number }>({ start: 0, end: 0 });

  // --- Vertical virtual scroll (custom, replaces cdk-virtual-scroll-viewport) ---
  /** Range of display-row indices currently mounted in the DOM. */
  readonly visibleRowRange = signal<{ start: number; end: number }>({ start: 0, end: 0 });
  /** Pixel offset of the first rendered row from the top of the body content. */
  readonly topSpacerHeight = signal<number>(0);
  /** Pixel offset between the last rendered row and the bottom of the body content. */
  readonly bottomSpacerHeight = signal<number>(0);
  /** Total height of all display rows (data + group, includes expanded detail). */
  readonly totalRowsHeight = signal<number>(0);

  // --- UI ---
  readonly isLoading = signal<boolean>(false);
  readonly rowHeight = signal<number>(48);
  readonly density = signal<GridDensity>('default');

  // --- Pending mutations ---
  /** Fast lookup set: `"rowId::field"` keys. Set by the root grid component. */
  readonly pendingCellLookup = signal<Set<string>>(new Set());
  /** Fast lookup set of pending row IDs. Set by the root grid component. */
  readonly pendingRowLookup = signal<Set<string | number>>(new Set());

  // --- Row Selection ---
  readonly selectedRowIds = signal<Set<unknown>>(new Set());
  readonly excludedRowIds = signal<Set<unknown>>(new Set());
  readonly selectAllMode = signal<'none' | 'page' | 'all'>('none');

  // --- Cell Selection ---
  readonly focusedCell = signal<CellCoord | null>(null);
  readonly selectedCell = signal<CellCoord | null>(null);
  readonly cellRange = signal<{ start: CellCoord; end: CellCoord } | null>(null);
  readonly isDragging = signal<boolean>(false);
  readonly focusSource = signal<'click' | 'keyboard' | null>(null);

  // --- Fill Down ---
  readonly isFilling = signal<boolean>(false);
  readonly fillAnchor = signal<CellCoord | null>(null);
  readonly fillTarget = signal<CellCoord | null>(null);

  // --- Cut (Ctrl+X) source — drives the marching-ants outline in view ---
  readonly cutSource = signal<{ start: CellCoord; end: CellCoord } | null>(null);

  // --- Expandable Rows ---
  readonly expandedRowIds = signal<Set<unknown>>(new Set());
  /**
   * Two-phase expansion: when the user toggles a row to expand, the id is
   * first added to `pendingExpansion`. A hidden measurement zone renders the
   * detail row off-screen, its ResizeObserver measures the height, and the
   * engine then PROMOTES the row from `pendingExpansion` into
   * `expandedRowIds` — at which point the visible body template mounts the
   * detail row with its height already cached, so the vertical virtual-scroll
   * engine rebuilds offsets with the correct value on the very first visible
   * render. No layout shift, no scrollbar bounce.
   *
   * `isRowExpanded(id)` returns `true` ONLY once the row is in
   * `expandedRowIds` (i.e. promoted) so the visible template never renders
   * a detail row twice (once in the measurement zone, once in the layout).
   */
  readonly pendingExpansion = signal<Set<unknown>>(new Set());
  readonly rowIdField = signal<string>('id');

  // --- Cell selection toggle ---
  readonly multiCellSelectionEnabled = signal<boolean>(true);

  // --- Selection Mode (mutual exclusion between row and cell selection) ---
  readonly activeSelectionMode = signal<'rows' | 'cells' | 'none'>('none');

  // --- Column Drag ---
  readonly draggingColumn = signal<string | null>(null);
  readonly dropIndicatorIndex = signal<number | null>(null);

  // --- Cell Edit ---
  readonly cellEditState = signal<CellEditState>({
    editingCell: null,
    originalValue: undefined,
    draftValue: undefined,
    validationError: null,
  });

  /** `true` while the user is editing a formula inside the top formula bar
   *  (outside any cell). Consumed by `FormulaEngine.isFormulaEditActive`
   *  so headers show column-letter badges during bar-driven edits too. */
  readonly formulaBarEditingActive = signal<boolean>(false);

  // --- Computed: visible columns (pinned-start first, unpinned middle, pinned-end last) ---
  readonly visibleColumns = computed(() => {
    const cols = this.columnStates()
      .filter((col) => col.visible)
      .sort((a, b) => a.order - b.order);
    const pinnedLeft = cols.filter((c) => c.pinned === 'start');
    const unpinned = cols.filter((c) => !c.pinned);
    const pinnedRight = cols.filter((c) => c.pinned === 'end');
    return [...pinnedLeft, ...unpinned, ...pinnedRight];
  });

  // --- Computed: column subsets for 3-panel layout ---
  readonly pinnedLeftColumns = computed(() =>
    this.visibleColumns().filter((c) => c.pinned === 'start')
  );

  readonly unpinnedColumns = computed(() => this.visibleColumns().filter((c) => !c.pinned));

  readonly pinnedRightColumns = computed(() =>
    this.visibleColumns().filter((c) => c.pinned === 'end')
  );

  readonly pinnedLeftWidth = computed(() =>
    this.pinnedLeftColumns().reduce((sum, c) => sum + c.currentWidth, 0)
  );

  readonly pinnedRightWidth = computed(() =>
    this.pinnedRightColumns().reduce((sum, c) => sum + c.currentWidth, 0)
  );

  /**
   * Cumulative `left` offset (px) for each pinned-left column, in render
   * order. Consumers add their own utility-cell prefix (checkbox/expand) and
   * pass the result to `position: sticky; left: <offset>px`.
   * Returns an array of length `pinnedLeftColumns().length`.
   */
  readonly pinnedLeftCumulativeOffsets = computed(() => {
    const cols = this.pinnedLeftColumns();
    const out = new Array<number>(cols.length);
    let off = 0;
    for (let i = 0; i < cols.length; i++) {
      out[i] = off;
      off += cols[i].currentWidth;
    }
    return out;
  });

  /**
   * Cumulative `right` offset (px) for each pinned-right column, in render
   * order. The first column from the right (visually leftmost in the
   * pinned-right group) has the largest `right` offset.
   */
  readonly pinnedRightCumulativeOffsets = computed(() => {
    const cols = this.pinnedRightColumns();
    const out = new Array<number>(cols.length);
    let off = 0;
    for (let i = cols.length - 1; i >= 0; i--) {
      out[i] = off;
      off += cols[i].currentWidth;
    }
    return out;
  });

  readonly unpinnedWidth = computed(() =>
    this.unpinnedColumns().reduce((sum, c) => sum + c.currentWidth, 0)
  );

  /**
   * Unpinned columns actually rendered in data rows. When horizontal virtual scroll
   * is disabled, this is the full set; when enabled, it's the slice inside the
   * current visibleColumnRange. Header and filter row keep rendering the full set —
   * only row cells are virtualized.
   */
  /**
   * Effective column range with edit-mode widening: keeps the column being edited
   * inside the rendered window so the editor never gets torn down mid-edit.
   */
  readonly effectiveColumnRange = computed(() => {
    const raw = this.visibleColumnRange();
    const editing = this.cellEditState().editingCell;
    if (!editing) return raw;
    const pinnedLeftCount = this.pinnedLeftColumns().length;
    const unpinnedIdx = editing.col - pinnedLeftCount;
    const total = this.unpinnedColumns().length;
    if (unpinnedIdx < 0 || unpinnedIdx >= total) return raw;
    return {
      start: Math.min(raw.start, unpinnedIdx),
      end: Math.max(raw.end, unpinnedIdx + 1),
    };
  });

  readonly renderedUnpinnedColumns = computed(() => {
    const all = this.unpinnedColumns();
    if (!this.horizontalVirtualScrollEnabled()) return all;
    const { start, end } = this.effectiveColumnRange();
    if (end <= start || end > all.length) return all;
    return all.slice(start, end);
  });

  readonly leadingColumnSpacer = computed(() => {
    if (!this.horizontalVirtualScrollEnabled()) return 0;
    const start = this.effectiveColumnRange().start;
    const cols = this.unpinnedColumns();
    let w = 0;
    for (let i = 0; i < start && i < cols.length; i++) w += cols[i].currentWidth;
    return w;
  });

  readonly trailingColumnSpacer = computed(() => {
    if (!this.horizontalVirtualScrollEnabled()) return 0;
    const end = this.effectiveColumnRange().end;
    const cols = this.unpinnedColumns();
    let w = 0;
    for (let i = end; i < cols.length; i++) w += cols[i].currentWidth;
    return w;
  });

  // --- Computed: column defs map (for fast lookup) ---
  readonly columnDefMap = computed(() => {
    const map = new Map<string, ColumnDef<T>>();
    for (const def of this.columnDefs()) {
      map.set(def.field, def);
    }
    return map;
  });

  /** `true` when at least one column declares `allowFormula: true`. */
  readonly hasFormulaColumns = computed(() =>
    this.columnDefs().some((d) => d.allowFormula === true),
  );

  // --- Computed: grid-template-columns CSS ---
  readonly gridTemplateColumns = computed(() => {
    return this.visibleColumns()
      .map((col) => `${col.currentWidth}px`)
      .join(' ');
  });

  // --- Computed: total content width ---
  readonly totalContentWidth = computed(() => {
    return this.visibleColumns().reduce((sum, col) => sum + col.currentWidth, 0);
  });

  // --- Computed: total pages ---
  readonly totalPages = computed(() => {
    const total = this.mode() === 'server' ? this.totalItems() : this.sourceData().length;
    return Math.max(1, Math.ceil(total / this.pageSize()));
  });

  // --- Computed: has more data to load (infinite scroll) ---
  readonly hasMore = computed(() => this.sourceData().length < this.totalItems());

  // --- Initialize columns from ColumnDefs ---
  initColumns(defs: ColumnDef<T>[]): void {
    this.columnDefs.set(defs);
    this.columnStates.set(
      defs.map((def, index) => ({
        field: def.field,
        currentWidth: this.resolveWidth(def),
        order: index,
        visible: def.visible !== false,
        sort: null as SortDirection,
        sortIndex: null,
        // Defensive normalize: `ColumnDef.pinned` accepts Vue's
        // `'left' | 'right'` aliases. The directive boundary normalizes,
        // but programmatic callers may pass defs straight through.
        pinned: normalizePinned(def.pinned),
        searchVisible: def.searchVisible ?? false,
      }))
    );
  }

  // --- Update a single column state ---
  updateColumnState(field: string, updates: Partial<ColumnStateEntry>): void {
    this.columnStates.update((states) =>
      states.map((state) => (state.field === field ? { ...state, ...updates } : state))
    );
  }

  private resolveWidth(def: ColumnDef<T>): number {
    if (def.width) {
      return parseInt(def.width, 10) || DEFAULT_COLUMN_WIDTH;
    }
    return DEFAULT_COLUMN_WIDTH;
  }
}

/**
 * Map the Vue-flavoured aliases (`'left' | 'right'`) onto Angular's
 * canonical `'start' | 'end'` pinned values. Other values pass through.
 */
function normalizePinned(
  v: 'start' | 'end' | 'left' | 'right' | null | undefined,
): 'start' | 'end' | null {
  if (v === 'left') return 'start';
  if (v === 'right') return 'end';
  return v ?? null;
}

import { Injectable, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { GroupRow, DisplayRow } from '../models/display-row.model';
import { GroupEntry } from '../models/grid-events.model';

@Injectable()
export class GroupEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  addGroup(field: string): void {
    const current = this.state.groupColumns();
    if (current.some((g) => g.field === field)) return;
    this.state.groupColumns.set([...current, { field, sortDirection: 'asc' }]);
    this.state.pageIndex.set(0);
  }

  removeGroup(field: string): void {
    this.state.groupColumns.update((cols) => cols.filter((g) => g.field !== field));
    this.state.pageIndex.set(0);
  }

  applyGroups(groups: GroupEntry[]): void {
    this.state.groupColumns.set(groups);
  }

  clearGroups(): void {
    this.state.groupColumns.set([]);
    this.state.expandedGroups.set(new Set());
  }

  toggleGroupExpand(groupKey: string): void {
    this.state.expandedGroups.update((set) => {
      const next = new Set(set);
      if (next.has(groupKey)) {
        next.delete(groupKey);
      } else {
        next.add(groupKey);
      }
      return next;
    });
  }

  isGroupExpanded(groupKey: string): boolean {
    return this.state.expandedGroups().has(groupKey);
  }

  groupData(data: T[]): DisplayRow<T>[] {
    const groupEntries = this.state.groupColumns();
    if (groupEntries.length === 0) return [];

    const rootGroups = this.buildGroups(data, groupEntries, 0, null, '');
    return this.flattenGroups(rootGroups);
  }

  private buildGroups(
    data: T[],
    entries: GroupEntry[],
    depth: number,
    parent: GroupRow<T> | null,
    parentKey: string,
  ): GroupRow<T>[] {
    if (depth >= entries.length) return [];

    const entry = entries[depth];
    const field = entry.field;
    const defMap = this.state.columnDefMap();
    const def = defMap.get(field);

    const groups = new Map<string, T[]>();
    for (const row of data) {
      const rawValue = def?.valueGetter
        ? def.valueGetter(row)
        : (row as Record<string, unknown>)[field];
      const key = String(rawValue ?? '');
      if (!groups.has(key)) groups.set(key, []);
      groups.get(key)!.push(row);
    }

    const result: GroupRow<T>[] = [];
    for (const [value, rows] of groups) {
      const groupKey = parentKey ? `${parentKey}|${field}:${value}` : `${field}:${value}`;
      const displayValue = def?.valueFormatter
        ? def.valueFormatter(value, rows[0])
        : value;

      const groupRow: GroupRow<T> = {
        type: 'group',
        field,
        value,
        displayValue: `${def?.headerName ?? field}: ${displayValue}`,
        depth,
        count: rows.length,
        expanded: this.state.expandedGroups().has(groupKey),
        groupKey,
        children: [],
        parent,
      };

      if (depth + 1 < entries.length) {
        groupRow.children = this.buildGroups(rows, entries, depth + 1, groupRow, groupKey);
      } else {
        groupRow.children = rows;
      }

      result.push(groupRow);
    }

    // Sort groups by their sort direction
    const sortDir = entry.sortDirection === 'desc' ? -1 : 1;
    result.sort((a, b) => {
      const aVal = String(a.value);
      const bVal = String(b.value);
      const numA = Number(aVal);
      const numB = Number(bVal);
      if (!isNaN(numA) && !isNaN(numB)) {
        return (numA - numB) * sortDir;
      }
      return aVal.localeCompare(bVal) * sortDir;
    });

    return result;
  }

  private flattenGroups(groups: GroupRow<T>[]): DisplayRow<T>[] {
    const result: DisplayRow<T>[] = [];
    let dataIndex = 0;

    const flatten = (groupList: GroupRow<T>[]): void => {
      for (const group of groupList) {
        result.push({ type: 'group', group });

        if (group.expanded) {
          const childGroups = group.children.filter(
            (c): c is GroupRow<T> => typeof c === 'object' && c !== null && 'type' in c && (c as GroupRow<T>).type === 'group'
          );
          const childData = group.children.filter(
            (c): c is T => !(typeof c === 'object' && c !== null && 'type' in c && (c as GroupRow<T>).type === 'group')
          );

          if (childGroups.length > 0) {
            flatten(childGroups);
          }

          for (const data of childData) {
            result.push({
              type: 'data',
              data,
              index: dataIndex++,
              depth: group.depth + 1,
            });
          }
        }
      }
    };

    flatten(groups);
    return result;
  }
}

import { Injectable, computed, inject, signal } from '@angular/core';
import { ClipboardEngine, HistoryCellChange } from './clipboard.engine';

export type HistoryOpType = 'edit' | 'paste' | 'cut' | 'fill' | 'delete' | 'fill-down' | 'fill-right' | 'fill-selection';

export interface HistoryOp {
  type: HistoryOpType;
  changes: HistoryCellChange[];
  timestamp: number;
}

const MAX_HISTORY = 50;
const STORAGE_PREFIX = 'adeo-grid-history:';

@Injectable()
export class HistoryEngine<T = unknown> {
  private readonly clipboard = inject<ClipboardEngine<T>>(ClipboardEngine);

  private readonly past = signal<HistoryOp[]>([]);
  private readonly future = signal<HistoryOp[]>([]);
  private storageKey: string | null = null;

  readonly canUndo = computed(() => this.past().length > 0);
  readonly canRedo = computed(() => this.future().length > 0);

  /**
   * Binds a persistence key: all record/undo/redo calls will mirror the stacks
   * to localStorage, and past state is restored on bind. Pass null to detach.
   */
  attach(gridId: string | null): void {
    this.storageKey = gridId ? `${STORAGE_PREFIX}${gridId}` : null;
    if (!this.storageKey) {
      this.past.set([]);
      this.future.set([]);
      return;
    }
    this.restore();
  }

  /** Records a new mutation. Clears the redo stack (standard undo semantics). */
  record(type: HistoryOpType, changes: HistoryCellChange[]): void {
    if (changes.length === 0) return;
    const op: HistoryOp = { type, changes, timestamp: Date.now() };
    this.past.update((stack) => {
      const next = [...stack, op];
      return next.length > MAX_HISTORY ? next.slice(next.length - MAX_HISTORY) : next;
    });
    this.future.set([]);
    this.persist();
  }

  undo(): HistoryOp | null {
    const stack = this.past();
    if (stack.length === 0) return null;
    const op = stack[stack.length - 1];
    this.clipboard.applyChanges(op.changes, 'before');
    this.past.set(stack.slice(0, -1));
    this.future.update((f) => [...f, op]);
    this.persist();
    return op;
  }

  redo(): HistoryOp | null {
    const stack = this.future();
    if (stack.length === 0) return null;
    const op = stack[stack.length - 1];
    this.clipboard.applyChanges(op.changes, 'after');
    this.future.set(stack.slice(0, -1));
    this.past.update((p) => [...p, op]);
    this.persist();
    return op;
  }

  clear(): void {
    this.past.set([]);
    this.future.set([]);
    if (this.storageKey) {
      try {
        localStorage.removeItem(this.storageKey);
      } catch {
        // Storage unavailable (private mode, quota) — non-fatal.
      }
    }
  }

  private persist(): void {
    if (!this.storageKey) return;
    try {
      const payload = JSON.stringify({
        past: this.past(),
        future: this.future(),
      });
      localStorage.setItem(this.storageKey, payload);
    } catch {
      // Quota exceeded or storage disabled — we silently drop persistence.
    }
  }

  private restore(): void {
    if (!this.storageKey) return;
    try {
      const raw = localStorage.getItem(this.storageKey);
      if (!raw) {
        this.past.set([]);
        this.future.set([]);
        return;
      }
      const parsed = JSON.parse(raw) as { past?: HistoryOp[]; future?: HistoryOp[] };
      this.past.set(Array.isArray(parsed.past) ? parsed.past : []);
      this.future.set(Array.isArray(parsed.future) ? parsed.future : []);
    } catch {
      this.past.set([]);
      this.future.set([]);
    }
  }
}

import { Injectable, effect, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';

const H_BUFFER_PX = 300;
const MIN_COLUMNS_FOR_VIRTUALIZATION = 20;

@Injectable()
export class HorizontalVirtualScrollEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  /** Cumulative left offsets of unpinned columns. Length = unpinnedColumns.length + 1. */
  private offsets: number[] = [0];

  constructor() {
    effect(
      () => {
        // React to column width/order/visibility changes and flag toggling.
        this.state.unpinnedColumns();
        const enabled = this.state.horizontalVirtualScrollEnabled();
        this.rebuildOffsets();

        if (!enabled) {
          this.fullRange();
          return;
        }

        // Column drag temporarily needs every unpinned cell in the DOM so the
        // drag engine can measure drop targets. We must return BEFORE reading
        // scrollLeft / scrollViewportWidth — otherwise auto-scroll would feed
        // scroll events back into this effect on every frame and thrash the
        // DOM (mount/unmount cycle at 60 fps → browser freeze).
        if (this.state.draggingColumn() !== null) {
          this.fullRange();
          return;
        }

        this.recompute(this.state.scrollLeft(), this.state.scrollViewportWidth());
      },
      { allowSignalWrites: true }
    );
  }

  /** Called by grid.ts when the body viewport scrolls or resizes. */
  onScroll(scrollLeft: number, viewportWidth: number): void {
    // Skip all signal writes while a column is being dragged — auto-scroll
    // pushes a scroll event every frame and any write that flows into the
    // virtualization effect would tear the DOM down and re-render during the
    // drag.
    if (this.state.draggingColumn() !== null) return;

    this.state.scrollLeft.set(scrollLeft);
    this.state.scrollViewportWidth.set(viewportWidth);
    if (!this.state.horizontalVirtualScrollEnabled()) return;
    this.recompute(scrollLeft, viewportWidth);
  }

  rebuildOffsets(): void {
    const cols = this.state.unpinnedColumns();
    const next = new Array<number>(cols.length + 1);
    next[0] = 0;
    for (let i = 0; i < cols.length; i++) {
      next[i + 1] = next[i] + cols[i].currentWidth;
    }
    this.offsets = next;
    this.state.scrollContentTotalWidth.set(next[next.length - 1] ?? 0);
  }

  private recompute(scrollLeft: number, viewportWidth: number): void {
    const total = this.state.unpinnedColumns().length;
    if (total === 0) {
      this.setRange(0, 0);
      return;
    }
    if (total < MIN_COLUMNS_FOR_VIRTUALIZATION || viewportWidth <= 0) {
      this.setRange(0, total);
      return;
    }

    const viewStart = Math.max(0, scrollLeft - H_BUFFER_PX);
    const viewEnd = scrollLeft + viewportWidth + H_BUFFER_PX;

    const start = this.findIndexAt(viewStart);
    const end = Math.min(total, this.findIndexAt(viewEnd) + 1);
    this.setRange(Math.max(0, start), Math.max(start + 1, end));
  }

  /** Binary search: returns the largest index i such that offsets[i] <= x. */
  private findIndexAt(x: number): number {
    const offsets = this.offsets;
    let lo = 0;
    let hi = offsets.length - 1;
    while (lo < hi) {
      const mid = (lo + hi + 1) >>> 1;
      if (offsets[mid] <= x) lo = mid;
      else hi = mid - 1;
    }
    return lo;
  }

  private fullRange(): void {
    const total = this.state.unpinnedColumns().length;
    this.setRange(0, total);
  }

  private setRange(start: number, end: number): void {
    const current = this.state.visibleColumnRange();
    if (current.start === start && current.end === end) return;
    this.state.visibleColumnRange.set({ start, end });
  }
}

import { Injectable, inject, computed, signal, DestroyRef, NgZone } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { LoadMoreEvent } from '../models/pagination.model';

const DEFAULT_SCROLL_THRESHOLD = 200;

@Injectable()
export class InfiniteScrollEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);
  private readonly destroyRef = inject(DestroyRef);
  private readonly ngZone = inject(NgZone);

  private scrollListener: (() => void) | null = null;
  private scrollElement: HTMLElement | null = null;
  private loadMoreCallback: ((event: LoadMoreEvent) => void) | null = null;

  readonly scrollThreshold = signal<number>(DEFAULT_SCROLL_THRESHOLD);

  readonly hasMore = computed(() => this.state.hasMore());

  readonly isActive = computed(() => this.state.loadingStrategy() === 'infinite-scroll');

  attach(
    scrollElement: HTMLElement,
    onLoadMore: (event: LoadMoreEvent) => void
  ): void {
    this.detach();
    this.scrollElement = scrollElement;
    this.loadMoreCallback = onLoadMore;

    const listener = (): void => {
      this.checkScrollPosition();
    };

    this.ngZone.runOutsideAngular(() => {
      scrollElement.addEventListener('scroll', listener, { passive: true });
    });

    this.scrollListener = (): void => {
      scrollElement.removeEventListener('scroll', listener);
    };

    this.destroyRef.onDestroy(() => this.detach());
  }

  detach(): void {
    if (this.scrollListener) {
      this.scrollListener();
      this.scrollListener = null;
    }
    this.scrollElement = null;
    this.loadMoreCallback = null;
  }

  private checkScrollPosition(): void {
    if (!this.scrollElement || !this.loadMoreCallback) return;
    if (!this.isActive()) return;
    if (this.state.isLoading()) return;
    if (!this.hasMore()) return;

    const el = this.scrollElement;
    const distanceFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;

    if (distanceFromBottom <= this.scrollThreshold()) {
      this.ngZone.run(() => {
        this.loadMoreCallback!({
          offset: this.state.sourceData().length,
          limit: this.state.pageSize(),
        });
      });
    }
  }

  /**
   * Reset scroll state — called when sort/filter changes require
   * reloading from offset 0.
   */
  reset(onLoadMore: (event: LoadMoreEvent) => void): void {
    if (this.scrollElement) {
      this.scrollElement.scrollTop = 0;
    }
    onLoadMore({ offset: 0, limit: this.state.pageSize() });
  }
}

import { Injectable, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { CellEditEvent, CellEditCancelEvent } from '../models/cell.model';
import { CellEditorType } from '../models/column.model';
import { HistoryEngine } from './history.engine';
import { GridEngine } from '../engine/grid-engine';
import { FormulaEngine } from './formula/formula.engine';
import { a1ToLongForm } from './formula/formula-ref-mapper';

@Injectable()
export class InlineEditEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);
  private readonly history = inject<HistoryEngine<T>>(HistoryEngine);
  private readonly gridEngine = inject<GridEngine<T>>(GridEngine);
  // Optional — tests that do not set up the formula provider keep working.
  private readonly formulaEngine = inject<FormulaEngine<T> | null>(FormulaEngine, {
    optional: true,
  });

  startEdit(rowIndex: number, field: string): void {
    const defMap = this.state.columnDefMap();
    const def = defMap.get(field);
    if (!def?.editable) return;

    const colIndex = this.state.visibleColumns().findIndex((c) => c.field === field);
    if (colIndex < 0) return;

    const sourceIndex = this.gridEngine.displayIndexToSourceIndex(rowIndex);
    const row = sourceIndex >= 0 ? this.state.sourceData()[sourceIndex] : undefined;
    if (!row) return;

    const value = def.valueGetter ? def.valueGetter(row) : (row as Record<string, unknown>)[field];
    // Formula-enabled cells open with the A1 surface form so the user edits
    // column letters, not the `REF(COLUMN("…"),ROW(…))` storage.
    let draftValue: unknown = value;
    if (def.allowFormula && this.formulaEngine) {
      const rowId = (row as Record<string, unknown>)[this.state.rowIdField()] as
        | string
        | number
        | undefined;
      if (rowId !== undefined && rowId !== null) {
        const a1 = this.formulaEngine.displayFormula({ rowId, field });
        if (a1 !== undefined) draftValue = a1;
      }
    }

    this.state.cellEditState.set({
      editingCell: { row: rowIndex, col: colIndex },
      originalValue: value,
      draftValue,
      validationError: null,
    });
  }

  /**
   * Excel-style "typing-to-edit": starts the editor with the cell value replaced
   * by the character the user just typed. For non-text editors (select / date /
   * checkbox / number) we coerce: the character is kept if it's compatible with
   * the editor, otherwise the editor opens on a cleared value.
   */
  startEditWithChar(rowIndex: number, field: string, char: string): void {
    const defMap = this.state.columnDefMap();
    const def = defMap.get(field);
    if (!def?.editable) return;

    const colIndex = this.state.visibleColumns().findIndex((c) => c.field === field);
    if (colIndex < 0) return;

    const sourceIndex = this.gridEngine.displayIndexToSourceIndex(rowIndex);
    const row = sourceIndex >= 0 ? this.state.sourceData()[sourceIndex] : undefined;
    if (!row) return;

    const currentValue = def.valueGetter
      ? def.valueGetter(row)
      : (row as Record<string, unknown>)[field];
    const editorType = def.cellEditor ?? this.resolveEditorType(field, currentValue);

    let draftValue: unknown = char;
    switch (editorType) {
      case 'number': {
        const n = Number(char);
        draftValue = Number.isNaN(n) ? '' : n;
        break;
      }
      case 'checkbox':
        // A character press toggles the checkbox to true — closest Excel-equivalent
        // (Excel doesn't have checkbox cells but booleans flip on typing).
        draftValue = true;
        break;
      case 'select':
      case 'date':
        // These editors have picker UIs; typing just opens them with an empty draft.
        draftValue = '';
        break;
      default:
        draftValue = char;
    }

    this.state.cellEditState.set({
      editingCell: { row: rowIndex, col: colIndex },
      originalValue: currentValue,
      draftValue,
      validationError: null,
    });
  }

  updateDraft(value: unknown): void {
    this.state.cellEditState.update((s) => ({ ...s, draftValue: value }));
  }

  commitEdit(): CellEditEvent<T> | null {
    const editState = this.state.cellEditState();
    if (!editState.editingCell) return null;

    const { row: rowIndex, col: colIndex } = editState.editingCell;
    const visibleCols = this.state.visibleColumns();
    const field = visibleCols[colIndex]?.field;
    if (!field) return null;

    const def = this.state.columnDefMap().get(field);
    const sourceIndex = this.gridEngine.displayIndexToSourceIndex(rowIndex);
    if (sourceIndex < 0) return null;
    let row = this.state.sourceData()[sourceIndex];
    if (!row) return null;

    // Validation
    if (def?.cellEditorValidator) {
      const result = def.cellEditorValidator(editState.draftValue, row);
      if (result === false) {
        this.state.cellEditState.update((s) => ({
          ...s,
          validationError: 'Invalid value',
        }));
        return null;
      }
      if (typeof result === 'string') {
        this.state.cellEditState.update((s) => ({
          ...s,
          validationError: result,
        }));
        return null;
      }
    }

    // Formula drafts are authored in A1 — normalise to REF long-form before
    // persisting, so sourceData always holds storage form (shift, paste and
    // syncFromSource all rely on it).
    const storedDraftValue =
      def?.allowFormula === true &&
      typeof editState.draftValue === 'string' &&
      editState.draftValue.trimStart().startsWith('=')
        ? this.a1DraftToStorage(editState.draftValue)
        : editState.draftValue;

    // Always update data immutably so signals detect the change, regardless
    // of client/server mode. Consumers can still re-fetch/override via output.
    this.state.sourceData.update((data) => {
      const updated = [...data];
      updated[sourceIndex] = { ...updated[sourceIndex], [field]: storedDraftValue } as T;
      return updated;
    });
    // Re-read the updated row for the event
    row = this.state.sourceData()[sourceIndex];

    // Route formula-capable cells through the formula engine. The raw
    // formula string is kept in the source data (inline storage mode) and
    // the rendering layer reads the evaluated value via `valueAt(addr)`.
    // Non-formula cells still trigger `invalidate` so dependents recompute.
    this.updateFormulaEngine(
      def?.allowFormula === true,
      row,
      field,
      storedDraftValue,
      editState.originalValue
    );

    const event: CellEditEvent<T> = {
      row,
      rowIndex: sourceIndex,
      field,
      oldValue: editState.originalValue,
      newValue: storedDraftValue,
    };

    if (event.oldValue !== event.newValue) {
      this.history.record('edit', [
        { rowIndex: sourceIndex, field, before: event.oldValue, after: event.newValue },
      ]);
    }

    this.state.cellEditState.set({
      editingCell: null,
      originalValue: undefined,
      draftValue: undefined,
      validationError: null,
    });

    return event;
  }

  cancelEdit(): CellEditCancelEvent | null {
    const editState = this.state.cellEditState();
    if (!editState.editingCell) return null;

    const { row: rowIndex, col: colIndex } = editState.editingCell;
    const field = this.state.visibleColumns()[colIndex]?.field;

    this.state.cellEditState.set({
      editingCell: null,
      originalValue: undefined,
      draftValue: undefined,
      validationError: null,
    });

    return field ? { rowIndex, field, originalValue: editState.originalValue } : null;
  }

  isEditing(rowIndex: number, colIndex: number): boolean {
    const editState = this.state.cellEditState();
    return editState.editingCell?.row === rowIndex && editState.editingCell?.col === colIndex;
  }

  /**
   * Convert an A1-surface formula draft to REF long-form storage. Strings
   * that do not start with `=` are returned untouched — callers should
   * only invoke this on values they already know to be formulas.
   */
  private a1DraftToStorage(draft: string): string {
    const rowIds = this.state.sourceData().map((row) => {
      const r = row as Record<string, unknown>;
      return (r[this.state.rowIdField()] as string | number | undefined) ?? '';
    });
    const fields = this.state.visibleColumns().map((c) => c.field);
    return a1ToLongForm(draft, { fields, rowIds });
  }

  resolveEditorType(field: string, value: unknown): CellEditorType {
    const def = this.state.columnDefMap().get(field);
    if (def?.cellEditor) return def.cellEditor;

    // Auto-detect
    if (def?.cellEditorOptions?.length) return 'select';
    if (typeof value === 'boolean') return 'checkbox';
    if (typeof value === 'number') return 'number';
    if (value instanceof Date) return 'date';
    return 'text';
  }

  /**
   * Route a cell-edit commit through the formula engine when appropriate:
   *  - `allowFormula` column + new value starts with `=` → register formula.
   *  - `allowFormula` column + old value was a formula but new one isn't
   *    → remove the stored formula (reverts to a plain literal).
   *  - Any cell change → invalidate dependents so their cached value
   *    refreshes (no-op when the engine has zero dependents on this cell).
   */
  private updateFormulaEngine(
    allowFormula: boolean,
    row: T,
    field: string,
    newValue: unknown,
    oldValue: unknown
  ): void {
    const engine = this.formulaEngine;
    if (!engine) return;

    const rowId = (row as Record<string, unknown>)[this.state.rowIdField()] as
      | string
      | number
      | undefined;
    if (rowId === undefined) return;
    const addr = { rowId, field };

    const isFormula = (v: unknown): v is string =>
      typeof v === 'string' && v.trimStart().startsWith('=');

    if (allowFormula && isFormula(newValue)) {
      engine.set(addr, newValue);
    } else if (allowFormula && isFormula(oldValue) && !isFormula(newValue)) {
      engine.remove(addr);
    }

    engine.invalidate(addr);
  }
}

import { Injectable, inject } from '@angular/core';
import { CellSelectionEngine } from './cell-selection.engine';
import { InlineEditEngine } from './inline-edit.engine';
import { GridStateManager } from '../state/grid-state';

/**
 * Actions that require grid-level orchestration (event emission, clipboard
 * system access, async, UI refocus). The keyboard engine can run pure
 * navigation locally, but bounces these back to the host component.
 */
export interface KeyboardActions {
  copy: () => void;
  paste: () => void;
  cut: () => void;
  deleteRange: () => void;
  undo: () => void;
  redo: () => void;
  fillDown: () => void;
  fillRight: () => void;
  startEdit: (row: number, col: number, initialChar?: string) => void;
}

@Injectable()
export class KeyboardEngine<T = unknown> {
  private readonly cellSelection = inject<CellSelectionEngine<T>>(CellSelectionEngine);
  private readonly inlineEdit = inject<InlineEditEngine<T>>(InlineEditEngine);
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  private actions: KeyboardActions | null = null;

  registerActions(actions: KeyboardActions): void {
    this.actions = actions;
  }

  handleKeydown(event: KeyboardEvent): void {
    // Edit-mode keys are handled by AdGridAngularComponent.handleEditModeKeydown;
    // this engine only owns navigation + shortcuts in non-editing state.
    if (this.state.cellEditState().editingCell !== null) return;

    const focused = this.state.focusedCell();
    if (!focused) return;

    if (this.dispatch(event, focused)) {
      event.preventDefault();
    }
  }

  /** Returns true when the event was handled (so the caller should preventDefault). */
  private dispatch(event: KeyboardEvent, focused: { row: number; col: number }): boolean {
    const mod = event.ctrlKey || event.metaKey;
    const shift = event.shiftKey;
    const alt = event.altKey;
    const key = event.key;

    // ---- Clipboard / history shortcuts --------------------------------------
    if (mod && !shift && !alt) {
      switch (key.toLowerCase()) {
        case 'c':
          this.actions?.copy();
          return true;
        case 'v':
          this.actions?.paste();
          return true;
        case 'x':
          this.actions?.cut();
          return true;
        case 'z':
          this.actions?.undo();
          return true;
        case 'y':
          this.actions?.redo();
          return true;
        case 'a':
          this.cellSelection.selectAll();
          return true;
        case 'd':
          this.actions?.fillDown();
          return true;
        case 'r':
          this.actions?.fillRight();
          return true;
      }
    }
    if (mod && shift && !alt && key.toLowerCase() === 'z') {
      this.actions?.redo();
      return true;
    }

    // ---- Whole row / column selection ---------------------------------------
    if (key === ' ') {
      if (mod && shift) {
        this.cellSelection.selectAll();
        return true;
      }
      if (mod) {
        this.cellSelection.selectColumn(focused.col);
        return true;
      }
      if (shift) {
        this.cellSelection.selectRow(focused.row);
        return true;
      }
    }

    // ---- Delete / Backspace: clear cells ------------------------------------
    if (key === 'Delete' || key === 'Backspace') {
      this.actions?.deleteRange();
      return true;
    }

    // ---- Arrow keys ---------------------------------------------------------
    if (key === 'ArrowUp' || key === 'ArrowDown' || key === 'ArrowLeft' || key === 'ArrowRight') {
      return this.handleArrow(key, { mod, shift });
    }

    // ---- Home / End / PageUp / PageDown -------------------------------------
    if (key === 'Home') {
      if (mod && shift) this.cellSelection.extendRangeToGridStart();
      else if (mod) this.cellSelection.moveToGridStart();
      else if (shift) this.cellSelection.extendRangeToRowStart();
      else this.cellSelection.moveToRowStart();
      return true;
    }
    if (key === 'End') {
      if (mod && shift) this.cellSelection.extendRangeToGridEnd();
      else if (mod) this.cellSelection.moveToGridEnd();
      else if (shift) this.cellSelection.extendRangeToRowEnd();
      else this.cellSelection.moveToRowEnd();
      return true;
    }
    if (key === 'PageUp') {
      if (shift) this.cellSelection.extendRangeByPage('up');
      else this.cellSelection.movePage('up');
      return true;
    }
    if (key === 'PageDown') {
      if (shift) this.cellSelection.extendRangeByPage('down');
      else this.cellSelection.movePage('down');
      return true;
    }

    // ---- Tab / Enter / F2 / Escape ------------------------------------------
    if (key === 'Tab') {
      if (shift) this.cellSelection.moveLeft();
      else this.cellSelection.moveRight();
      return true;
    }
    if (key === 'Enter') {
      const col = this.state.visibleColumns()[focused.col];
      const def = col ? this.state.columnDefMap().get(col.field) : undefined;
      if (def?.editable) {
        this.actions?.startEdit(focused.row, focused.col);
        return true;
      }
      if (shift) this.cellSelection.moveUp();
      else this.cellSelection.moveDown();
      return true;
    }
    if (key === 'F2') {
      this.actions?.startEdit(focused.row, focused.col);
      return true;
    }
    if (key === 'Escape') {
      this.cellSelection.clearFocus();
      return true;
    }

    // ---- Typing-to-edit -----------------------------------------------------
    if (!mod && !alt && this.isPrintableKey(event)) {
      this.actions?.startEdit(focused.row, focused.col, key);
      return true;
    }

    return false;
  }

  private handleArrow(
    key: 'ArrowUp' | 'ArrowDown' | 'ArrowLeft' | 'ArrowRight',
    mods: { mod: boolean; shift: boolean },
  ): boolean {
    const dir = key === 'ArrowUp' ? 'up' : key === 'ArrowDown' ? 'down' : key === 'ArrowLeft' ? 'left' : 'right';

    if (mods.mod && mods.shift) {
      this.cellSelection.extendRangeJumpToEdge(dir);
      return true;
    }
    if (mods.mod) {
      this.cellSelection.jumpToEdge(dir);
      return true;
    }
    if (mods.shift) {
      const dRow = dir === 'up' ? -1 : dir === 'down' ? 1 : 0;
      const dCol = dir === 'left' ? -1 : dir === 'right' ? 1 : 0;
      this.cellSelection.extendRangeBy(dRow, dCol);
      return true;
    }

    switch (dir) {
      case 'up':
        this.cellSelection.moveUp();
        break;
      case 'down':
        this.cellSelection.moveDown();
        break;
      case 'left':
        this.cellSelection.moveLeft();
        break;
      case 'right':
        this.cellSelection.moveRight();
        break;
    }
    return true;
  }

  /**
   * A key press is "printable" when it represents exactly one character that
   * the user intends as input — excluding named keys like F1, Home, Arrow*,
   * etc. Also excludes IME composition events (event.isComposing).
   */
  private isPrintableKey(event: KeyboardEvent): boolean {
    if (event.isComposing) return false;
    if (event.key.length !== 1) return false;
    // Guard against NUL / control characters slipping through on some layouts.
    const code = event.key.charCodeAt(0);
    return code >= 32 && code !== 127;
  }
}

