import { Injectable, inject, signal, computed } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { GroupEntry } from '../models/grid-events.model';
import { DisplayRow, GroupRow } from '../models/display-row.model';

// ---------------------------------------------------------------------------
// Public contract types
// ---------------------------------------------------------------------------

export interface GroupSummary {
  /** Raw group value (the distinct field value). */
  value: unknown;
  /** Total number of rows in this group on the server. */
  count: number;
}

export interface ServerGroupingOptions<T = unknown> {
  /**
   * Fetch the list of distinct group values + counts for the given fields.
   * Called when group fields change.
   */
  fetchGroups: (fields: string[]) => Promise<GroupSummary[]>;

  /**
   * Fetch a slice of rows for a specific group value.
   * `start` and `end` are zero-based indices within the group.
   */
  fetchGroupRows: (
    field: string,
    value: unknown,
    start: number,
    end: number,
  ) => Promise<T[]>;

  /** Page size for lazy-loading rows within an expanded group. Default: 100. */
  pageSize?: number;
}

interface GroupCache<T> {
  rows: Array<T | null>;
  total: number;
  loaded: number;
  /** Pages already fetched or in-flight. */
  fetchedPages: Set<number>;
}

// ---------------------------------------------------------------------------
// Engine
// ---------------------------------------------------------------------------

@Injectable()
export class ServerGroupEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  // ── Configuration ────────────────────────────────────────────────────────

  /** Options provided by the consumer. When null, the engine is inactive. */
  private options: ServerGroupingOptions<T> | null = null;

  configure(opts: ServerGroupingOptions<T> | null): void {
    this.options = opts;
    if (!opts) {
      this.groupSummaries.set([]);
      this.expandedKeys.set(new Set());
      this.loadedGroups.set(new Map());
    }
  }

  // ── Local state ─────────────────────────────────────────────────────────

  /** Group field stack (mirrors `state.groupColumns` but owns server semantics). */
  readonly groupFields = computed<string[]>(() =>
    this.state.groupColumns().map((g) => g.field),
  );

  /** Whether the engine is active (options configured + at least one field). */
  readonly active = computed(
    () => this.options !== null && this.groupFields().length > 0,
  );

  /** Server-provided group summaries (value + count). */
  readonly groupSummaries = signal<GroupSummary[]>([]);

  /** Set of group keys that are currently expanded. */
  readonly expandedKeys = signal<Set<string>>(new Set());

  /** Loaded row caches per group key. */
  readonly loadedGroups = signal<Map<string, GroupCache<T>>>(new Map());

  /** Set of group keys where a fetch is in flight. */
  readonly loadingGroups = signal<Set<string>>(new Set());

  /** `true` when the summary-level fetch is in flight. */
  readonly isFetchingSummaries = signal(false);

  /** `true` when any group-level fetch is in flight. */
  readonly isLoading = computed(
    () =>
      this.isFetchingSummaries() ||
      this.loadingGroups().size > 0,
  );

  private _pageSize(): number {
    return this.options?.pageSize ?? 100;
  }

  // ── Group field management (mirrors GroupEngine API) ─────────────────────

  addGroup(field: string): void {
    const current = this.state.groupColumns();
    if (current.some((g) => g.field === field)) return;
    this.state.groupColumns.set([...current, { field, sortDirection: 'asc' }]);
    this.fetchGroupSummaries();
  }

  removeGroup(field: string): void {
    this.state.groupColumns.update((cols) => cols.filter((g) => g.field !== field));
    // Clean expanded state for this field.
    this.expandedKeys.update((keys) => {
      const next = new Set(keys);
      for (const key of next) {
        if (key.includes(`${field}::`)) next.delete(key);
      }
      return next;
    });
    this.fetchGroupSummaries();
  }

  clearGroups(): void {
    this.state.groupColumns.set([]);
    this.groupSummaries.set([]);
    this.expandedKeys.set(new Set());
    this.loadedGroups.set(new Map());
  }

  applyGroups(groups: GroupEntry[]): void {
    this.state.groupColumns.set(groups);
    this.fetchGroupSummaries();
  }

  // ── Summary fetch ────────────────────────────────────────────────────────

  async fetchGroupSummaries(): Promise<void> {
    const opts = this.options;
    const fields = this.groupFields();
    if (!opts || fields.length === 0) {
      this.groupSummaries.set([]);
      return;
    }

    this.isFetchingSummaries.set(true);
    try {
      const summaries = await opts.fetchGroups(fields);
      this.groupSummaries.set(summaries);
      // Reset expand / cache state on new summary fetch.
      this.expandedKeys.set(new Set());
      this.loadedGroups.set(new Map());
    } finally {
      this.isFetchingSummaries.set(false);
    }
  }

  // ── Expand / collapse ────────────────────────────────────────────────────

  toggleGroupExpand(groupKey: string): void {
    this.expandedKeys.update((keys) => {
      const next = new Set(keys);
      if (next.has(groupKey)) {
        next.delete(groupKey);
      } else {
        next.add(groupKey);
        // Trigger initial row fetch for this group if not cached.
        const field = this.groupFields()[0];
        const summary = this.groupSummaries().find(
          (s) => this._buildKey(field!, s.value) === groupKey,
        );
        if (summary && field && !this.loadedGroups().has(groupKey)) {
          this.expandGroupServer(groupKey, field, summary.value, summary.count, 0);
        }
      }
      return next;
    });
  }

  isGroupExpanded(groupKey: string): boolean {
    return this.expandedKeys().has(groupKey);
  }

  // ── Server fetch of rows within an expanded group ────────────────────────

  /**
   * Fetches page `page` of rows for `groupKey`. No-op if already fetched or
   * no options are configured.
   */
  async expandGroupServer(
    groupKey: string,
    field: string,
    value: unknown,
    total: number,
    page: number,
  ): Promise<void> {
    const opts = this.options;
    if (!opts) return;

    // Initialise the cache entry if needed.
    const existingMap = this.loadedGroups();
    let cache = existingMap.get(groupKey);
    if (!cache) {
      cache = { rows: [], total, loaded: 0, fetchedPages: new Set() };
      const next = new Map(existingMap);
      next.set(groupKey, cache);
      this.loadedGroups.set(next);
    }

    if (cache.fetchedPages.has(page)) return;
    cache.fetchedPages.add(page);

    const ps = this._pageSize();
    const start = page * ps;
    const end = Math.min(start + ps, total);

    this.loadingGroups.update((s) => new Set([...s, groupKey]));

    try {
      const fetched = await opts.fetchGroupRows(field, value, start, end);
      this.loadedGroups.update((map) => {
        const updated = new Map(map);
        const existing = updated.get(groupKey);
        if (!existing) return updated;
        const rows = [...existing.rows];
        // Ensure array is long enough.
        while (rows.length < end) rows.push(null);
        for (let i = 0; i < fetched.length; i++) {
          rows[start + i] = fetched[i] ?? null;
        }
        updated.set(groupKey, {
          ...existing,
          rows,
          loaded: rows.filter((r) => r !== null).length,
        });
        return updated;
      });
    } finally {
      this.loadingGroups.update((s) => {
        const next = new Set(s);
        next.delete(groupKey);
        return next;
      });
    }
  }

  // ── Flat renderable rows ─────────────────────────────────────────────────

  /**
   * Flat list of rows ready for virtual scroll, typed as `DisplayRow<T>[]` so
   * `GridEngine.displayRows` can consume it without a cast.
   *
   * - Group header rows become `{ type: 'group', group: GroupRow<T> }`.
   * - Loaded data rows become `{ type: 'data', data: T, index: number, depth: 1 }`.
   * - Skeleton/placeholder rows become `{ type: 'data', data: skeletonSentinel, ... }`
   *   where `skeletonSentinel` is a plain object that carries `__adgSkeleton: true`
   *   and the offset metadata needed by `onVisibleRangeChange`.
   */
  readonly flatRows = computed<DisplayRow<T>[]>(() => {
    if (!this.active()) return [];

    const fields = this.groupFields();
    const field = fields[0];
    if (!field) return [];

    const def = this.state.columnDefMap().get(field);
    const headerName = def?.headerName ?? field;
    const result: DisplayRow<T>[] = [];
    const summaries = this.groupSummaries();
    const expandedSet = this.expandedKeys();
    const loadedMap = this.loadedGroups();
    let dataIndex = 0;

    for (const summary of summaries) {
      const key = this._buildKey(field, summary.value);
      const isExpanded = expandedSet.has(key);

      // Build a GroupRow<T> for the group header.
      const groupRow: GroupRow<T> = {
        type: 'group',
        field,
        value: summary.value,
        displayValue: `${headerName}: ${String(summary.value ?? '')}`,
        depth: 0,
        count: summary.count,
        expanded: isExpanded,
        groupKey: key,
        children: [],
        parent: null,
      };

      result.push({ type: 'group', group: groupRow });

      if (!isExpanded) continue;

      const cache = loadedMap.get(key);
      if (!cache) {
        // Cache not ready — emit all-skeleton placeholder rows.
        for (let i = 0; i < summary.count; i++) {
          result.push({
            type: 'data',
            data: {
              __adgSkeleton: true,
              __adgGroupKey: key,
              __adgOffsetInGroup: i,
            } as unknown as T,
            index: dataIndex++,
            depth: 1,
          });
        }
        continue;
      }

      for (let i = 0; i < cache.total; i++) {
        const row = cache.rows[i];
        if (row !== null && row !== undefined) {
          result.push({ type: 'data', data: row, index: dataIndex++, depth: 1 });
        } else {
          result.push({
            type: 'data',
            data: {
              __adgSkeleton: true,
              __adgGroupKey: key,
              __adgOffsetInGroup: i,
            } as unknown as T,
            index: dataIndex++,
            depth: 1,
          });
        }
      }
    }

    return result;
  });

  // ── Lazy-load trigger ────────────────────────────────────────────────────

  /**
   * Called by the grid body when the visible range changes. Detects skeleton
   * rows inside expanded groups and fetches their pages on demand.
   */
  onVisibleRangeChange(startIdx: number, endIdx: number): void {
    const rows = this.flatRows();
    const ps = this._pageSize();
    const field = this.groupFields()[0];
    if (!field) return;

    for (let i = startIdx; i < endIdx && i < rows.length; i++) {
      const displayRow = rows[i];
      if (!displayRow || displayRow.type !== 'data') continue;
      const data = displayRow.data as Record<string, unknown>;
      if (!data || !data['__adgSkeleton'] || !data['__adgGroupKey']) continue;
      const key = String(data['__adgGroupKey']);
      const offset = Number(data['__adgOffsetInGroup'] ?? 0);
      const page = Math.floor(offset / ps);
      const summary = this.groupSummaries().find(
        (s) => this._buildKey(field, s.value) === key,
      );
      if (summary) {
        this.expandGroupServer(key, field, summary.value, summary.count, page);
      }
    }
  }

  // ── Private helpers ──────────────────────────────────────────────────────

  private _buildKey(field: string, value: unknown): string {
    return `${field}::${String(value ?? '')}`;
  }
}

import { Injectable, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { SortDef } from '../models/sort.model';
import { SortDirection } from '../models/column.model';

@Injectable()
export class SortEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  toggleSort(field: string, isMultiSort: boolean): void {
    const currentSorts = this.state.activeSorts();
    const existing = currentSorts.find((s) => s.field === field);

    let nextDirection: SortDirection;
    if (!existing) {
      nextDirection = 'asc';
    } else if (existing.direction === 'asc') {
      nextDirection = 'desc';
    } else {
      nextDirection = null;
    }

    let newSorts: SortDef[];
    if (isMultiSort) {
      if (nextDirection === null) {
        newSorts = currentSorts.filter((s) => s.field !== field);
      } else if (existing) {
        newSorts = currentSorts.map((s) =>
          s.field === field ? { ...s, direction: nextDirection! } : s
        );
      } else {
        newSorts = [...currentSorts, { field, direction: nextDirection, priority: currentSorts.length }];
      }
    } else {
      newSorts = nextDirection ? [{ field, direction: nextDirection, priority: 0 }] : [];
    }

    this.state.activeSorts.set(newSorts);
    this.syncColumnSortState(newSorts);
  }

  setSort(field: string, direction: SortDirection): void {
    const newSorts: SortDef[] = direction
      ? [{ field, direction, priority: 0 }]
      : [];
    this.state.activeSorts.set(newSorts);
    this.syncColumnSortState(newSorts);
  }

  clearSort(): void {
    this.state.activeSorts.set([]);
    this.syncColumnSortState([]);
  }

  sortData(data: T[]): T[] {
    const sorts = this.state.activeSorts();
    if (sorts.length === 0) return data;

    const defMap = this.state.columnDefMap();

    return [...data].sort((a, b) => {
      for (const sort of sorts) {
        const def = defMap.get(sort.field);
        if (def?.sortComparator) {
          const result = def.sortComparator(a, b);
          if (result !== 0) return sort.direction === 'asc' ? result : -result;
          continue;
        }

        const valA = this.getValue(a, sort.field, def);
        const valB = this.getValue(b, sort.field, def);
        const result = this.defaultCompare(valA, valB);
        if (result !== 0) return sort.direction === 'asc' ? result : -result;
      }
      return 0;
    });
  }

  private syncColumnSortState(sorts: SortDef[]): void {
    this.state.columnStates.update((states) =>
      states.map((state) => {
        const sortDef = sorts.find((s) => s.field === state.field);
        return {
          ...state,
          sort: sortDef?.direction ?? null,
          sortIndex: sortDef ? sorts.indexOf(sortDef) : null,
        };
      })
    );
  }

  private getValue(row: T, field: string, def?: { valueGetter?: (row: T) => unknown }): unknown {
    if (def?.valueGetter) return def.valueGetter(row);
    return (row as Record<string, unknown>)[field];
  }

  private defaultCompare(a: unknown, b: unknown): number {
    if (a == null && b == null) return 0;
    if (a == null) return -1;
    if (b == null) return 1;
    if (typeof a === 'string' && typeof b === 'string') {
      return a.localeCompare(b);
    }
    if (typeof a === 'number' && typeof b === 'number') {
      return a - b;
    }
    return String(a).localeCompare(String(b));
  }
}

import { inject, Injectable } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { SortDirection } from '../models/column.model';
import { SortDef } from '../models/sort.model';
import { FilterCondition, generateConditionId } from '../models/filter.model';

export interface PersistedGridState {
  columns: Array<{
    field: string;
    currentWidth: number;
    order: number;
    visible: boolean;
    pinned: 'start' | 'end' | null;
  }>;
  sorts: SortDef[];
  /** Serialised filter conditions. `id` is regenerated on restore. */
  filters?: Array<Omit<FilterCondition, 'id'>>;
}

@Injectable()
export class StatePersistenceEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  save(storageKey: string): void {
    const persisted: PersistedGridState = {
      columns: this.state.columnStates().map((col) => ({
        field: col.field,
        currentWidth: col.currentWidth,
        order: col.order,
        visible: col.visible,
        pinned: col.pinned,
      })),
      sorts: this.state.activeSorts(),
      filters: this.state.filterModel().conditions.map((condition) => {
        const { id, ...rest } = condition;
        void id;
        return rest;
      }),
    };

    try {
      localStorage.setItem(storageKey, JSON.stringify(persisted));
    } catch {
      // localStorage may be unavailable or full
    }
  }

  restore(storageKey: string): boolean {
    try {
      const raw = localStorage.getItem(storageKey);
      if (!raw) return false;

      const persisted: PersistedGridState = JSON.parse(raw);
      if (!persisted.columns?.length) return false;

      this.state.columnStates.update((currentStates) => {
        return currentStates.map((col) => {
          const saved = persisted.columns.find((s) => s.field === col.field);
          if (!saved) return col;
          return {
            ...col,
            currentWidth: saved.currentWidth,
            order: saved.order,
            visible: saved.visible,
            pinned: saved.pinned,
          };
        });
      });

      if (persisted.sorts?.length) {
        this.state.activeSorts.set(persisted.sorts);
        this.state.columnStates.update((states) =>
          states.map((s) => {
            const sortDef = persisted.sorts.find((sd) => sd.field === s.field);
            return sortDef
              ? {
                  ...s,
                  sort: sortDef.direction as SortDirection,
                  sortIndex: persisted.sorts.indexOf(sortDef),
                }
              : { ...s, sort: null as SortDirection, sortIndex: null };
          })
        );
      }

      if (persisted.filters?.length) {
        this.state.filterModel.set({
          conditions: persisted.filters.map((f) => ({ ...f, id: generateConditionId() })),
        });
      }

      return true;
    } catch {
      return false;
    }
  }

  clear(storageKey: string): void {
    try {
      localStorage.removeItem(storageKey);
    } catch {
      // localStorage may be unavailable
    }
  }
}

import { inject, Injectable } from '@angular/core';
import { GridStateManager } from '../state/grid-state';

export interface TreeNodeConfig {
  childrenField: string;
  hasChildrenField?: string;
  expandedByDefault?: boolean;
}

export interface TreeDisplayRow<T = unknown> {
  type: 'data';
  data: T;
  index: number;
  depth: number;
  hasChildren: boolean;
  expanded: boolean;
  nodeKey: string;
}

@Injectable()
export class TreeEngine<T = unknown> {
  private readonly state = inject<GridStateManager<T>>(GridStateManager);

  flatten(
    data: T[],
    config: TreeNodeConfig,
    expandedNodes: Set<string>,
    idField: string
  ): TreeDisplayRow<T>[] {
    const rows: TreeDisplayRow<T>[] = [];
    let index = 0;

    const walk = (items: T[], depth: number, parentKey: string): void => {
      for (const item of items) {
        const record = item as Record<string, unknown>;
        const id = String(record[idField] ?? index);
        const nodeKey = parentKey ? `${parentKey}/${id}` : id;
        const children = (record[config.childrenField] as T[] | undefined) ?? [];
        const hasChildren = config.hasChildrenField
          ? Boolean(record[config.hasChildrenField])
          : children.length > 0;
        // B22 — expandedByDefault: treat the node as expanded when the flag is
        // true and the node has not been explicitly toggled (i.e. not in
        // expandedNodes). A node that the user has collapsed after an
        // "expand-all" would need to be tracked separately by the host; our
        // convention (matching the Vue engine) is that absent-from-set means
        // "never toggled", so expandedByDefault === true implies expanded.
        const expanded = expandedNodes.has(nodeKey) || (config.expandedByDefault === true);

        rows.push({
          type: 'data',
          data: item,
          index: index++,
          depth,
          hasChildren,
          expanded,
          nodeKey,
        });

        if (hasChildren && expanded) {
          walk(children, depth + 1, nodeKey);
        }
      }
    };

    walk(data, 0, '');
    return rows;
  }

  toggleNode(nodeKey: string): void {
    this.state.expandedRowIds.update((set) => {
      const next = new Set(set);
      if (next.has(nodeKey)) {
        next.delete(nodeKey);
      } else {
        next.add(nodeKey);
      }
      return next;
    });
  }

  expandAll(data: T[], config: TreeNodeConfig, idField: string): void {
    const keys = new Set<string>();

    const walk = (items: T[], parentKey: string): void => {
      for (const item of items) {
        const record = item as Record<string, unknown>;
        const id = String(record[idField] ?? '');
        const nodeKey = parentKey ? `${parentKey}/${id}` : id;
        const children = (record[config.childrenField] as T[] | undefined) ?? [];
        if (children.length > 0) {
          keys.add(nodeKey);
          walk(children, nodeKey);
        }
      }
    };

    walk(data, '');
    this.state.expandedRowIds.set(keys as Set<unknown>);
  }

  collapseAll(): void {
    this.state.expandedRowIds.set(new Set());
  }
}

import { Injectable, effect, inject } from '@angular/core';
import { GridStateManager } from '../state/grid-state';
import { GridEngine } from '../engine/grid-engine';
import { ExpandableRowEngine } from './expandable-row.engine';

const V_BUFFER_PX = 200;
const FALLBACK_VIEWPORT_PX = 600;

/**
 * Custom vertical virtualization that replaces `cdk-virtual-scroll-viewport`.
 *
 * Why custom: CDK's strategy positions visible rows via `transform: translateY`
 * on the content wrapper. `transform` creates a containing block that traps
 * any `position: sticky` descendant, which breaks sticky pinned cells inside
 * data rows. We replace the transform with a height-based top-spacer so the
 * scroll container stays the sticky containing block.
 *
 * The engine is fully signal-driven — two reactive effects run independently:
 * - **Layout effect**: rebuilds the cumulative offset cache whenever the row
 *   layout (count, density, expanded set) changes. Cheap O(n) write.
 * - **Range effect**: re-computes the visible window whenever scrollTop /
 *   viewportHeight / totalRowsHeight changes. O(log n) binary search.
 *
 * Detail-row heights come from a single source of truth: the off-screen
 * pre-measurement performed by `<ad-grid-measurement-zone>` writes into
 * `ExpandableRowEngine.measuredRowHeights` (id-keyed). The visible-layout
 * `<ad-grid-detail-row>` keeps that cache fresh via its own `ResizeObserver`.
 * The engine NEVER observes row DOM directly — an earlier attempt with an
 * index-keyed map produced scroll bounce because virtualization slides
 * recycle DOM across indices, so a freshly observed element fires RO with the
 * NEW index but reflects the OLD row's height, producing spurious deltas.
 * Browser-level scroll anchoring (CSS `overflow-anchor: auto` on the viewport
 * + each row) preserves the visible content's pixel position when the top
 * spacer changes — no JS scroll compensation is needed.
 */
@Injectable()
export class VerticalVirtualScrollEngine {
  private readonly state = inject(GridStateManager);
  private readonly engine = inject(GridEngine);
  /** Optional — only present when the grid provides `ExpandableRowEngine`. */
  private readonly expandableRowEngine = inject(ExpandableRowEngine, { optional: true });

  /** Cumulative top offsets — length = displayRows.length + 1. */
  private offsets: number[] = [0];

  constructor() {
    // Layout: rebuild offsets when row composition changes — including
    // detail-row measurements. `trackMeasurements()` is the bridge that
    // re-runs this effect when a detail row's ResizeObserver lands a new
    // height.
    effect(
      () => {
        this.engine.displayRows();
        this.state.rowHeight();
        this.state.expandedRowIds();
        this.expandableRowEngine?.trackMeasurements();
        this.rebuildOffsets();
      },
      { allowSignalWrites: true },
    );

    // Range: react to scroll/viewport changes and offset rebuilds.
    effect(
      () => {
        this.state.scrollTop();
        this.state.scrollViewportHeight();
        this.state.totalRowsHeight();
        this.recompute();
      },
      { allowSignalWrites: true },
    );
  }

  /** Called by the grid container's scroll handler. Setters drive the range
   * effect; we don't recompute synchronously so a scroll burst collapses to
   * a single recompute per change-detection tick. */
  onScroll(scrollTop: number, viewportHeight: number): void {
    if (this.state.scrollTop() !== scrollTop) this.state.scrollTop.set(scrollTop);
    if (this.state.scrollViewportHeight() !== viewportHeight) {
      this.state.scrollViewportHeight.set(viewportHeight);
    }
  }

  /** Sync read for templates / scroll-into-view: physical height of a single
   * row, derived from the cumulative offset cache so it always reflects the
   * last `rebuildOffsets` result (including detail-row measurements). */
  getRowHeight(index: number): number {
    const a = this.offsets[index];
    const b = this.offsets[index + 1];
    if (a === undefined || b === undefined) return this.state.rowHeight();
    return b - a;
  }

  private rebuildOffsets(): void {
    const rows = this.engine.displayRows();
    const base = this.state.rowHeight();
    const idField = this.state.rowIdField();
    const expandedIds = this.state.expandedRowIds();
    const next = new Array<number>(rows.length + 1);
    next[0] = 0;
    for (let i = 0; i < rows.length; i++) {
      let extra = 0;
      // Only expanded data rows contribute extra height. The measurement
      // comes from `ExpandableRowEngine.measuredRowHeights`, populated by
      // either the off-screen measurement zone (before promotion) or the
      // visible detail row's own ResizeObserver. Keyed by row id — slides
      // don't invalidate it.
      if (this.expandableRowEngine) {
        const row = rows[i];
        if (row && row.type === 'data') {
          const rowIdValue = (row.data as Record<string, unknown>)[idField];
          if (expandedIds.has(rowIdValue)) {
            const rowKey = String(rowIdValue ?? i);
            const keyExtra = this.expandableRowEngine.getExtraHeightForKey(rowKey);
            if (keyExtra !== undefined) extra = keyExtra;
          }
        }
      }
      next[i + 1] = next[i] + base + extra;
    }
    this.offsets = next;
    const total = next[next.length - 1] ?? 0;
    if (this.state.totalRowsHeight() !== total) this.state.totalRowsHeight.set(total);
  }

  private recompute(): void {
    const total = this.engine.displayRows().length;
    if (total === 0) {
      this.applyRange(0, 0, 0, 0);
      return;
    }

    const scrollTop = this.state.scrollTop();
    // Use a reasonable fallback when the layout hasn't measured the viewport
    // yet (initial render). The range will refine itself once the real
    // viewport height comes in via the scroll handler / ResizeObserver.
    let viewportHeight = this.state.scrollViewportHeight();
    if (viewportHeight <= 0) viewportHeight = FALLBACK_VIEWPORT_PX;

    const viewStart = Math.max(0, scrollTop - V_BUFFER_PX);
    const viewEnd = scrollTop + viewportHeight + V_BUFFER_PX;
    const start = Math.max(0, this.findIndexAt(viewStart));
    const end = Math.min(total, this.findIndexAt(viewEnd) + 1);
    const top = this.offsets[start] ?? 0;
    const bottom = (this.offsets[total] ?? 0) - (this.offsets[end] ?? 0);
    this.applyRange(start, Math.max(start + 1, end), top, Math.max(0, bottom));
  }

  /** Largest index i such that offsets[i] <= x. */
  private findIndexAt(x: number): number {
    const offsets = this.offsets;
    let lo = 0;
    let hi = offsets.length - 1;
    while (lo < hi) {
      const mid = (lo + hi + 1) >>> 1;
      if (offsets[mid] <= x) lo = mid;
      else hi = mid - 1;
    }
    return lo;
  }

  private applyRange(start: number, end: number, top: number, bottom: number): void {
    const cur = this.state.visibleRowRange();
    if (cur.start !== start || cur.end !== end) {
      this.state.visibleRowRange.set({ start, end });
    }
    if (this.state.topSpacerHeight() !== top) this.state.topSpacerHeight.set(top);
    if (this.state.bottomSpacerHeight() !== bottom) this.state.bottomSpacerHeight.set(bottom);
  }

  scrollOffsetForIndex(index: number): number {
    const i = Math.max(0, Math.min(index, this.offsets.length - 1));
    return this.offsets[i] ?? 0;
  }
}

