import {
  CellAddress,
  FormulaError,
  FormulaEvalContext,
  FormulaFunctionRegistry,
  FormulaValue,
  firstError,
  toNumber,
  toStringValue,
} from '../../models/formula.model';
import { BinaryOp, FormulaAst } from './formula-ast';

/**
 * Evaluate a parsed formula. Never throws: every internal exception is
 * converted to a `#VALUE!` / `#REF!` / `#NAME?` value so the caller can
 * safely store the result without wrapping in try/catch.
 */
export function evaluate(
  ast: FormulaAst,
  functions: FormulaFunctionRegistry,
  ctx: FormulaEvalContext
): FormulaValue {
  try {
    const v = evalNode(ast, functions, ctx);
    // Range values escaping to the top are not renderable — surface as #VALUE!.
    if (Array.isArray(v)) return { kind: 'error', error: '#VALUE!' };
    return v;
  } catch (err) {
    if (err instanceof EvalError) {
      return { kind: 'error', error: err.code };
    }
    return { kind: 'error', error: '#VALUE!' };
  }
}

// A "range result" is a flat row-major list of values; it is never a top-level
// result, only an intermediate value that `call` may expand. Represented as an
// array to keep the hot path allocation-free when ranges are not used.
type EvalResult = FormulaValue | FormulaValue[];

class EvalError extends Error {
  constructor(readonly code: FormulaError) {
    super(code);
  }
}

function fail(code: FormulaError): never {
  throw new EvalError(code);
}

function evalNode(
  node: FormulaAst,
  functions: FormulaFunctionRegistry,
  ctx: FormulaEvalContext
): EvalResult {
  switch (node.kind) {
    case 'number':
      return { kind: 'number', value: node.value };
    case 'string':
      return { kind: 'string', value: node.value };
    case 'boolean':
      return { kind: 'boolean', value: node.value };
    case 'ref':
      return resolveRef(node.resolved, ctx);
    case 'range':
      return resolveRange(node.resolved, ctx);
    case 'unary':
      return evalUnary(node.op, evalNode(node.operand, functions, ctx));
    case 'binary':
      return evalBinary(
        node.op,
        evalNode(node.left, functions, ctx),
        evalNode(node.right, functions, ctx)
      );
    case 'call':
      return evalCall(node.name, node.args, functions, ctx);
  }
}

function resolveRef(resolved: CellAddress | undefined, ctx: FormulaEvalContext): FormulaValue {
  if (!resolved) {
    // Un-resolved references surface #REF!. The ref-mapper (Phase 1) is
    // responsible for attaching `resolved` after parsing; Phase 0 tests
    // rely on direct evaluator invocations with synthetic inputs.
    return { kind: 'error', error: '#REF!' };
  }
  return ctx.resolveRef(resolved) ?? { kind: 'empty' };
}

function resolveRange(
  resolved: ReadonlyArray<CellAddress | undefined> | undefined,
  ctx: FormulaEvalContext
): EvalResult {
  if (!resolved) return fail('#REF!');
  const out: FormulaValue[] = new Array(resolved.length);
  for (let i = 0; i < resolved.length; i++) {
    const target = resolved[i];
    out[i] = target ? ctx.resolveRef(target) : { kind: 'error', error: '#REF!' };
  }
  return out;
}

// ─── Unary ──────────────────────────────────────────────────────────────────

function evalUnary(op: '+' | '-', operand: EvalResult): FormulaValue {
  if (Array.isArray(operand)) return { kind: 'error', error: '#VALUE!' };
  if (operand.kind === 'error') return operand;
  const n = toNumber(operand);
  if (typeof n === 'string') return { kind: 'error', error: n };
  return { kind: 'number', value: op === '+' ? n : -n };
}

// ─── Binary ─────────────────────────────────────────────────────────────────

function evalBinary(op: BinaryOp, left: EvalResult, right: EvalResult): FormulaValue {
  if (Array.isArray(left) || Array.isArray(right)) {
    return { kind: 'error', error: '#VALUE!' };
  }
  const err = firstError([left, right]);
  if (err) return { kind: 'error', error: err };

  switch (op) {
    case '+':
    case '-':
    case '*':
    case '/':
    case '^':
      return arith(op, left, right);
    case '&':
      return concat(left, right);
    case '=':
    case '<>':
    case '<':
    case '>':
    case '<=':
    case '>=':
      return compare(op, left, right);
  }
}

function arith(op: '+' | '-' | '*' | '/' | '^', a: FormulaValue, b: FormulaValue): FormulaValue {
  const l = toNumber(a);
  if (typeof l === 'string') return { kind: 'error', error: l };
  const r = toNumber(b);
  if (typeof r === 'string') return { kind: 'error', error: r };

  let result: number;
  switch (op) {
    case '+':
      result = l + r;
      break;
    case '-':
      result = l - r;
      break;
    case '*':
      result = l * r;
      break;
    case '/':
      if (r === 0) return { kind: 'error', error: '#DIV/0!' };
      result = l / r;
      break;
    case '^':
      result = Math.pow(l, r);
      break;
  }
  if (!Number.isFinite(result)) return { kind: 'error', error: '#NUM!' };
  return { kind: 'number', value: result };
}

function concat(a: FormulaValue, b: FormulaValue): FormulaValue {
  const l = toStringValue(a);
  if (typeof l !== 'string') return { kind: 'error', error: l };
  const r = toStringValue(b);
  if (typeof r !== 'string') return { kind: 'error', error: r };
  return { kind: 'string', value: l + r };
}

function compare(
  op: '=' | '<>' | '<' | '>' | '<=' | '>=',
  a: FormulaValue,
  b: FormulaValue
): FormulaValue {
  const ord = compareValues(a, b);
  if (ord === null) return { kind: 'error', error: '#VALUE!' };
  let result: boolean;
  switch (op) {
    case '=':
      result = ord === 0;
      break;
    case '<>':
      result = ord !== 0;
      break;
    case '<':
      result = ord < 0;
      break;
    case '>':
      result = ord > 0;
      break;
    case '<=':
      result = ord <= 0;
      break;
    case '>=':
      result = ord >= 0;
      break;
  }
  return { kind: 'boolean', value: result };
}

/**
 * Excel comparison rules (simplified):
 *   - Numbers compare numerically, ties broken as equal.
 *   - Strings compare case-insensitively, lexicographically.
 *   - Booleans: FALSE < TRUE.
 *   - Cross-type comparison orders are: number < string < boolean.
 *   - `empty` coerces to 0 / "" / FALSE depending on the other side.
 *
 * Returns null when comparison is meaningless (e.g. against an error, though
 * we already filter those out beforehand).
 */
function compareValues(a: FormulaValue, b: FormulaValue): number | null {
  if (a.kind === 'error' || b.kind === 'error') return null;

  const aRank = typeRank(a);
  const bRank = typeRank(b);
  if (aRank !== bRank) return aRank - bRank;

  switch (a.kind) {
    case 'number': {
      const bn = b as Extract<FormulaValue, { kind: 'number' }>;
      return a.value === bn.value ? 0 : a.value < bn.value ? -1 : 1;
    }
    case 'string': {
      const bs = b as Extract<FormulaValue, { kind: 'string' }>;
      const la = a.value.toLowerCase();
      const lb = bs.value.toLowerCase();
      return la === lb ? 0 : la < lb ? -1 : 1;
    }
    case 'boolean': {
      const bb = b as Extract<FormulaValue, { kind: 'boolean' }>;
      const na = a.value ? 1 : 0;
      const nb = bb.value ? 1 : 0;
      return na - nb;
    }
    case 'empty':
      return 0;
  }
  // Unreachable: errors are filtered at the top of the function.
  return null;
}

function typeRank(v: FormulaValue): number {
  switch (v.kind) {
    case 'empty':
    case 'number':
      return 0;
    case 'string':
      return 1;
    case 'boolean':
      return 2;
    case 'error':
      return 3;
  }
}

// ─── Function call ──────────────────────────────────────────────────────────

function evalCall(
  name: string,
  astArgs: readonly FormulaAst[],
  functions: FormulaFunctionRegistry,
  ctx: FormulaEvalContext
): FormulaValue {
  const impl = functions[name];
  if (!impl) return { kind: 'error', error: '#NAME?' };

  const rawArgs = astArgs.map((arg) => evalNode(arg, functions, ctx));

  // Range handling: flatten or reject depending on declaration.
  const args: FormulaValue[] = [];
  for (const r of rawArgs) {
    if (Array.isArray(r)) {
      if (!impl.acceptsRange) return { kind: 'error', error: '#VALUE!' };
      args.push(...r);
    } else {
      args.push(r);
    }
  }

  // Arity check
  if (!arityMatches(impl.arity, args.length)) {
    return { kind: 'error', error: '#N/A' };
  }

  // Propagate first error in arguments for functions that don't opt into
  // handling them (IFERROR is the only built-in that opts in).
  if (!arityAllowsErrorShortCircuit(name)) {
    const err = firstError(args);
    if (err) return { kind: 'error', error: err };
  }

  try {
    return impl.evaluate(args, ctx);
  } catch (err) {
    if (err instanceof EvalError) return { kind: 'error', error: err.code };
    return { kind: 'error', error: '#VALUE!' };
  }
}

function arityMatches(arity: FormulaArityLike, actual: number): boolean {
  if (typeof arity === 'number') return arity === actual;
  if (arity === 'variadic') return true;
  const [min, max] = arity;
  return actual >= min && actual <= max;
}

type FormulaArityLike = number | 'variadic' | readonly [number, number];

/**
 * Built-in functions that expect to see error values as arguments (so they
 * can react to them instead of short-circuiting). `IFERROR` is the canonical
 * case. Everything else follows Excel's "first error wins" rule.
 */
function arityAllowsErrorShortCircuit(name: string): boolean {
  return name === 'IFERROR' || name === 'IFS' || name === 'IF';
}

export type NodeKey = string;

export class FormulaDag {
  /** Forward edges: node → set of nodes it depends on. */
  private readonly forward = new Map<NodeKey, Set<NodeKey>>();
  /** Reverse edges: node → set of nodes that depend on it. */
  private readonly reverse = new Map<NodeKey, Set<NodeKey>>();

  /** Replaces every outgoing edge of `node` with the given `deps`. */
  setDependencies(node: NodeKey, deps: Iterable<NodeKey>): void {
    this.clearForward(node);
    const next = new Set<NodeKey>();
    for (const d of deps) {
      if (d === node) continue; // self-loop is handled via cycle detection
      next.add(d);
      let back = this.reverse.get(d);
      if (!back) {
        back = new Set();
        this.reverse.set(d, back);
      }
      back.add(node);
    }
    if (next.size > 0) this.forward.set(node, next);
  }

  /** Removes every edge touching `node` (both directions). */
  remove(node: NodeKey): void {
    this.clearForward(node);
    const dependents = this.reverse.get(node);
    if (dependents) {
      for (const dep of dependents) {
        this.forward.get(dep)?.delete(node);
        if (this.forward.get(dep)?.size === 0) this.forward.delete(dep);
      }
      this.reverse.delete(node);
    }
  }

  /** Direct dependencies of `node` (what `node` needs). */
  dependenciesOf(node: NodeKey): ReadonlySet<NodeKey> {
    return this.forward.get(node) ?? EMPTY_SET;
  }

  /** Direct dependents of `node` (who needs `node`). */
  dependentsOf(node: NodeKey): ReadonlySet<NodeKey> {
    return this.reverse.get(node) ?? EMPTY_SET;
  }

  /**
   * Returns the **membership** of the cycle containing `start`, or `null`
   * when no cycle is reachable. Uses an iterative DFS with a path stack to
   * stay linear and avoid recursion blow-ups for long chains.
   */
  detectCycle(start: NodeKey): ReadonlySet<NodeKey> | null {
    // Self-loop special case
    if (this.forward.get(start)?.has(start)) {
      return new Set([start]);
    }

    const colour = new Map<NodeKey, 'grey' | 'black'>();
    const parent = new Map<NodeKey, NodeKey>();
    const stack: Array<{ node: NodeKey; iter: Iterator<NodeKey> }> = [];

    const pushNode = (node: NodeKey): void => {
      colour.set(node, 'grey');
      stack.push({ node, iter: (this.forward.get(node) ?? EMPTY_SET).values() });
    };

    pushNode(start);

    while (stack.length > 0) {
      const top = stack[stack.length - 1];
      const { value: dep, done } = top.iter.next();
      if (done) {
        colour.set(top.node, 'black');
        stack.pop();
        continue;
      }
      if (colour.get(dep) === 'grey') {
        // Found a back-edge. Walk the parent chain from `top.node` back to
        // `dep` to reconstruct the cycle members.
        const members = new Set<NodeKey>([dep]);
        let cursor: NodeKey | undefined = top.node;
        while (cursor && cursor !== dep) {
          members.add(cursor);
          cursor = parent.get(cursor);
        }
        return members;
      }
      if (!colour.has(dep)) {
        parent.set(dep, top.node);
        pushNode(dep);
      }
    }
    return null;
  }

  /**
   * Kahn-style topological order over the descendants of `roots` (inclusive).
   * Guaranteed to be deterministic for a given insertion order. If the sub-
   * graph contains a cycle, nodes inside the cycle are returned **after** the
   * acyclic prefix in arbitrary order — the engine is expected to mark them
   * as `#CYCLE!` via `detectCycle` beforehand, so ordering does not matter.
   */
  topoFrom(roots: Iterable<NodeKey>): NodeKey[] {
    // 1. Collect every descendant reachable via reverse edges.
    const reachable = new Set<NodeKey>();
    const stack: NodeKey[] = [];
    for (const r of roots) {
      if (!reachable.has(r)) {
        reachable.add(r);
        stack.push(r);
      }
    }
    while (stack.length > 0) {
      const node = stack.pop()!;
      for (const dep of this.reverse.get(node) ?? EMPTY_SET) {
        if (!reachable.has(dep)) {
          reachable.add(dep);
          stack.push(dep);
        }
      }
    }

    // 2. Kahn: compute in-degrees restricted to `reachable`, then drain.
    const inDegree = new Map<NodeKey, number>();
    for (const node of reachable) inDegree.set(node, 0);
    for (const node of reachable) {
      for (const dep of this.forward.get(node) ?? EMPTY_SET) {
        if (reachable.has(dep)) {
          inDegree.set(node, (inDegree.get(node) ?? 0) + 1);
        }
      }
    }
    const queue: NodeKey[] = [];
    for (const [node, deg] of inDegree) {
      if (deg === 0) queue.push(node);
    }
    const ordered: NodeKey[] = [];
    while (queue.length > 0) {
      const node = queue.shift()!;
      ordered.push(node);
      for (const dependent of this.reverse.get(node) ?? EMPTY_SET) {
        if (!reachable.has(dependent)) continue;
        const nextDeg = (inDegree.get(dependent) ?? 0) - 1;
        inDegree.set(dependent, nextDeg);
        if (nextDeg === 0) queue.push(dependent);
      }
    }

    // Any remaining reachable nodes belong to cycles — append them so
    // callers that rely on "every descendant appears once" still work.
    if (ordered.length < reachable.size) {
      for (const node of reachable) {
        if (!ordered.includes(node)) ordered.push(node);
      }
    }
    return ordered;
  }

  /** Empties every edge — used when the grid is reset. */
  clear(): void {
    this.forward.clear();
    this.reverse.clear();
  }

  private clearForward(node: NodeKey): void {
    const prev = this.forward.get(node);
    if (!prev) return;
    for (const dep of prev) {
      const back = this.reverse.get(dep);
      back?.delete(node);
      if (back && back.size === 0) this.reverse.delete(dep);
    }
    this.forward.delete(node);
  }
}

const EMPTY_SET: ReadonlySet<NodeKey> = new Set();

import {
  BinaryOp,
  FormulaAst,
  StructuredRef,
  UnaryOp,
} from './formula-ast';

export type ParserLocale = 'en' | 'fr';

export interface ParseOptions {
  readonly locale?: ParserLocale;
  /** Maximum parse depth, guarding against pathological nesting. */
  readonly maxDepth?: number;
}

export class FormulaParseError extends Error {
  constructor(
    message: string,
    /** 0-based column in the source string. */
    readonly position: number,
  ) {
    super(message);
    this.name = 'FormulaParseError';
  }
}

// ─── Token types ────────────────────────────────────────────────────────────

type TokenType =
  | 'number'
  | 'string'
  | 'bool'
  | 'ident'
  | 'lparen'
  | 'rparen'
  | 'comma'
  | 'colon'
  | 'op'
  | 'eof';

interface Token {
  readonly type: TokenType;
  readonly value: string;
  readonly position: number;
}

// ─── Public entry point ─────────────────────────────────────────────────────

/**
 * Parse a formula source string into an AST. Accepts either form with or
 * without a leading `=`. Throws `FormulaParseError` on malformed input —
 * callers should translate that into a `#PARSE!` error value.
 */
export function parseFormula(source: string, options: ParseOptions = {}): FormulaAst {
  const locale = options.locale ?? 'en';
  const maxDepth = options.maxDepth ?? 256;
  const body = source.startsWith('=') ? source.slice(1) : source;
  const tokens = tokenize(body, locale);
  const parser = new RecursiveDescent(tokens, maxDepth);
  const ast = parser.parseExpression();
  parser.expect('eof');
  return ast;
}

// ─── Tokenizer ──────────────────────────────────────────────────────────────

function tokenize(source: string, locale: ParserLocale): Token[] {
  const tokens: Token[] = [];
  const argSeparator = locale === 'fr' ? ';' : ',';
  let i = 0;
  const len = source.length;

  while (i < len) {
    const ch = source[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i++;
      continue;
    }

    if (ch === '(') {
      tokens.push({ type: 'lparen', value: '(', position: i });
      i++;
      continue;
    }
    if (ch === ')') {
      tokens.push({ type: 'rparen', value: ')', position: i });
      i++;
      continue;
    }
    if (ch === argSeparator) {
      tokens.push({ type: 'comma', value: argSeparator, position: i });
      i++;
      continue;
    }
    if (ch === ':') {
      tokens.push({ type: 'colon', value: ':', position: i });
      i++;
      continue;
    }

    const twoChar = source.slice(i, i + 2);
    if (twoChar === '<=' || twoChar === '>=' || twoChar === '<>') {
      tokens.push({ type: 'op', value: twoChar, position: i });
      i += 2;
      continue;
    }
    if ('+-*/^&=<>'.includes(ch)) {
      tokens.push({ type: 'op', value: ch, position: i });
      i++;
      continue;
    }

    if (ch === '"') {
      const parsed = scanQuotedString(source, i);
      tokens.push({ type: 'string', value: parsed.value, position: i });
      i = parsed.end;
      continue;
    }

    if (isDigit(ch) || (ch === '.' && isDigit(source[i + 1] ?? ''))) {
      const start = i;
      let seenDot = ch === '.';
      let seenExp = false;
      i++;
      while (i < len) {
        const c = source[i];
        if (isDigit(c)) {
          i++;
          continue;
        }
        if (c === '.' && !seenDot && !seenExp) {
          seenDot = true;
          i++;
          continue;
        }
        if ((c === 'e' || c === 'E') && !seenExp) {
          seenExp = true;
          i++;
          if (source[i] === '+' || source[i] === '-') i++;
          continue;
        }
        break;
      }
      tokens.push({ type: 'number', value: source.slice(start, i), position: start });
      continue;
    }

    if (isAlpha(ch) || ch === '_') {
      const start = i;
      while (i < len && (isAlpha(source[i]) || isDigit(source[i]) || source[i] === '_' || source[i] === '.')) {
        i++;
      }
      const value = source.slice(start, i);
      const upper = value.toUpperCase();
      if (upper === 'TRUE' || upper === 'FALSE') {
        tokens.push({ type: 'bool', value: upper, position: start });
      } else {
        tokens.push({ type: 'ident', value, position: start });
      }
      continue;
    }

    throw new FormulaParseError(`Unexpected character "${ch}"`, i);
  }

  tokens.push({ type: 'eof', value: '', position: len });
  return tokens;
}

/** Consume a `"…"` literal, treating `""` as an escaped quote. */
function scanQuotedString(source: string, start: number): { value: string; end: number } {
  let i = start + 1;
  let value = '';
  const len = source.length;
  while (i < len) {
    if (source[i] === '"') {
      if (source[i + 1] === '"') {
        value += '"';
        i += 2;
        continue;
      }
      return { value, end: i + 1 };
    }
    value += source[i];
    i++;
  }
  throw new FormulaParseError('Unterminated string literal', start);
}

function isDigit(ch: string): boolean {
  return ch >= '0' && ch <= '9';
}

function isAlpha(ch: string): boolean {
  return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
}

// ─── Parser ─────────────────────────────────────────────────────────────────

class RecursiveDescent {
  private cursor = 0;
  private depth = 0;

  constructor(
    private readonly tokens: Token[],
    private readonly maxDepth: number,
  ) {}

  parseExpression(): FormulaAst {
    return this.guarded(() => this.parseComparison());
  }

  expect(type: TokenType): Token {
    const tok = this.peek();
    if (tok.type !== type) {
      throw new FormulaParseError(`Expected ${type}, got ${tok.type} "${tok.value}"`, tok.position);
    }
    this.cursor++;
    return tok;
  }

  private parseComparison(): FormulaAst {
    let left = this.parseConcat();
    while (true) {
      const op = this.peekOp();
      if (op !== '=' && op !== '<>' && op !== '<' && op !== '<=' && op !== '>' && op !== '>=') break;
      this.cursor++;
      const right = this.parseConcat();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  private parseConcat(): FormulaAst {
    let left = this.parseAdditive();
    while (this.peekOp() === '&') {
      this.cursor++;
      const right = this.parseAdditive();
      left = { kind: 'binary', op: '&', left, right };
    }
    return left;
  }

  private parseAdditive(): FormulaAst {
    let left = this.parseMultiplicative();
    while (true) {
      const op = this.peekOp();
      if (op !== '+' && op !== '-') break;
      this.cursor++;
      const right = this.parseMultiplicative();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  private parseMultiplicative(): FormulaAst {
    let left = this.parsePower();
    while (true) {
      const op = this.peekOp();
      if (op !== '*' && op !== '/') break;
      this.cursor++;
      const right = this.parsePower();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  /** `^` is right-associative in Excel. */
  private parsePower(): FormulaAst {
    const left = this.parseUnary();
    if (this.peekOp() === '^') {
      this.cursor++;
      const right = this.parsePower();
      return { kind: 'binary', op: '^', left, right };
    }
    return left;
  }

  private parseUnary(): FormulaAst {
    const op = this.peekOp();
    if (op === '+' || op === '-') {
      this.cursor++;
      return { kind: 'unary', op: op as UnaryOp, operand: this.parseUnary() };
    }
    return this.parsePrimary();
  }

  private parsePrimary(): FormulaAst {
    const tok = this.peek();
    switch (tok.type) {
      case 'number':
        this.cursor++;
        return { kind: 'number', value: Number(tok.value) };
      case 'string':
        this.cursor++;
        return { kind: 'string', value: tok.value };
      case 'bool':
        this.cursor++;
        return { kind: 'boolean', value: tok.value === 'TRUE' };
      case 'ident':
        return this.parseIdentExpression();
      case 'lparen': {
        this.cursor++;
        const inner = this.parseExpression();
        this.expect('rparen');
        return inner;
      }
      default:
        throw new FormulaParseError(`Unexpected token "${tok.value}"`, tok.position);
    }
  }

  /**
   * An ident followed by `(` is either the `REF(COLUMN(...),ROW(...))`
   * ref primitive (possibly chained as a range), or a regular function call.
   */
  private parseIdentExpression(): FormulaAst {
    const ident = this.expect('ident');
    const upper = ident.value.toUpperCase();
    if (upper === 'REF' && this.peek().type === 'lparen') {
      const ref = this.parseRefPrimitive(ident.position);
      if (this.peek().type === 'colon') {
        this.cursor++;
        const endIdent = this.expect('ident');
        if (endIdent.value.toUpperCase() !== 'REF' || this.peek().type !== 'lparen') {
          throw new FormulaParseError('Expected `REF(` after `:` in range', endIdent.position);
        }
        const endRef = this.parseRefPrimitive(endIdent.position);
        return { kind: 'range', start: ref, end: endRef };
      }
      return { kind: 'ref', ref };
    }
    // Regular function call.
    this.expect('lparen');
    const args: FormulaAst[] = [];
    if (this.peek().type !== 'rparen') {
      args.push(this.parseExpression());
      while (this.peek().type === 'comma') {
        this.cursor++;
        args.push(this.parseExpression());
      }
    }
    this.expect('rparen');
    return { kind: 'call', name: upper, args };
  }

  /**
   * Parse `REF(COLUMN("field")[,ROW(N) [,"$C"|"$R"|"$CR"]])` starting from
   * just after the `REF` ident. Returns the `StructuredRef`. A missing
   * `ROW(...)` arg marks the ref as same-row (resolves against the host
   * cell's row at evaluation time).
   */
  private parseRefPrimitive(position: number): StructuredRef {
    this.expect('lparen');

    const colIdent = this.expect('ident');
    if (colIdent.value.toUpperCase() !== 'COLUMN') {
      throw new FormulaParseError('Expected `COLUMN(` inside REF', colIdent.position);
    }
    this.expect('lparen');
    const fieldTok = this.expect('string');
    this.expect('rparen');

    // Same-row form: `REF(COLUMN("field"))` — no ROW arg.
    if (this.peek().type === 'rparen') {
      this.cursor++;
      void position;
      return {
        field: fieldTok.value,
        row: 0,
        absField: false,
        absRow: false,
        sameRow: true,
      };
    }

    this.expect('comma');

    const rowIdent = this.expect('ident');
    if (rowIdent.value.toUpperCase() !== 'ROW') {
      throw new FormulaParseError('Expected `ROW(` inside REF', rowIdent.position);
    }
    this.expect('lparen');
    const rowTok = this.expect('number');
    this.expect('rparen');

    const row = Number(rowTok.value);
    if (!Number.isFinite(row) || row < 1 || !Number.isInteger(row)) {
      throw new FormulaParseError('ROW must be a positive integer', rowTok.position);
    }

    let absField = false;
    let absRow = false;
    if (this.peek().type === 'comma') {
      this.cursor++;
      const lockTok = this.expect('string');
      const lock = lockTok.value;
      if (lock !== '$C' && lock !== '$R' && lock !== '$CR' && lock !== '') {
        throw new FormulaParseError(
          `Invalid REF lock marker: "${lock}" (expected "$C", "$R", or "$CR")`,
          lockTok.position,
        );
      }
      absField = lock === '$C' || lock === '$CR';
      absRow = lock === '$R' || lock === '$CR';
    }

    this.expect('rparen');

    void position;
    return { field: fieldTok.value, row, absField, absRow };
  }

  private peek(): Token {
    return this.tokens[this.cursor];
  }

  private peekOp(): BinaryOp | null {
    const tok = this.tokens[this.cursor];
    if (tok?.type !== 'op') return null;
    return tok.value as BinaryOp;
  }

  private guarded<T>(fn: () => T): T {
    if (++this.depth > this.maxDepth) {
      throw new FormulaParseError(`Formula exceeds max depth (${this.maxDepth})`, this.peek().position);
    }
    try {
      return fn();
    } finally {
      this.depth--;
    }
  }
}

export const FORMULA_REF_PALETTE_SIZE = 8;

export class FormulaRefPalette {
  private readonly slots = new Map<string, number>();
  private nextSlot = 0;

  /** Returns a stable palette index (0..N-1) for the given ref key. */
  indexFor(key: string): number {
    let slot = this.slots.get(key);
    if (slot !== undefined) return slot;
    slot = this.nextSlot % FORMULA_REF_PALETTE_SIZE;
    this.slots.set(key, slot);
    this.nextSlot++;
    return slot;
  }

  clear(): void {
    this.slots.clear();
    this.nextSlot = 0;
  }
}

/** CSS custom-property reference for a given palette index. */
export function paletteColorVar(index: number): string {
  return `var(--ad-grid-ref-color-${index % FORMULA_REF_PALETTE_SIZE})`;
}

import {
  BinaryOp,
  FormulaAst,
  StructuredRef,
  UnaryOp,
} from './formula-ast';

export type ParserLocale = 'en' | 'fr';

export interface ParseOptions {
  readonly locale?: ParserLocale;
  /** Maximum parse depth, guarding against pathological nesting. */
  readonly maxDepth?: number;
}

export class FormulaParseError extends Error {
  constructor(
    message: string,
    /** 0-based column in the source string. */
    readonly position: number,
  ) {
    super(message);
    this.name = 'FormulaParseError';
  }
}

// ─── Token types ────────────────────────────────────────────────────────────

type TokenType =
  | 'number'
  | 'string'
  | 'bool'
  | 'ident'
  | 'lparen'
  | 'rparen'
  | 'comma'
  | 'colon'
  | 'op'
  | 'eof';

interface Token {
  readonly type: TokenType;
  readonly value: string;
  readonly position: number;
}

// ─── Public entry point ─────────────────────────────────────────────────────

/**
 * Parse a formula source string into an AST. Accepts either form with or
 * without a leading `=`. Throws `FormulaParseError` on malformed input —
 * callers should translate that into a `#PARSE!` error value.
 */
export function parseFormula(source: string, options: ParseOptions = {}): FormulaAst {
  const locale = options.locale ?? 'en';
  const maxDepth = options.maxDepth ?? 256;
  const body = source.startsWith('=') ? source.slice(1) : source;
  const tokens = tokenize(body, locale);
  const parser = new RecursiveDescent(tokens, maxDepth);
  const ast = parser.parseExpression();
  parser.expect('eof');
  return ast;
}

// ─── Tokenizer ──────────────────────────────────────────────────────────────

function tokenize(source: string, locale: ParserLocale): Token[] {
  const tokens: Token[] = [];
  const argSeparator = locale === 'fr' ? ';' : ',';
  let i = 0;
  const len = source.length;

  while (i < len) {
    const ch = source[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i++;
      continue;
    }

    if (ch === '(') {
      tokens.push({ type: 'lparen', value: '(', position: i });
      i++;
      continue;
    }
    if (ch === ')') {
      tokens.push({ type: 'rparen', value: ')', position: i });
      i++;
      continue;
    }
    if (ch === argSeparator) {
      tokens.push({ type: 'comma', value: argSeparator, position: i });
      i++;
      continue;
    }
    if (ch === ':') {
      tokens.push({ type: 'colon', value: ':', position: i });
      i++;
      continue;
    }

    const twoChar = source.slice(i, i + 2);
    if (twoChar === '<=' || twoChar === '>=' || twoChar === '<>') {
      tokens.push({ type: 'op', value: twoChar, position: i });
      i += 2;
      continue;
    }
    if ('+-*/^&=<>'.includes(ch)) {
      tokens.push({ type: 'op', value: ch, position: i });
      i++;
      continue;
    }

    if (ch === '"') {
      const parsed = scanQuotedString(source, i);
      tokens.push({ type: 'string', value: parsed.value, position: i });
      i = parsed.end;
      continue;
    }

    if (isDigit(ch) || (ch === '.' && isDigit(source[i + 1] ?? ''))) {
      const start = i;
      let seenDot = ch === '.';
      let seenExp = false;
      i++;
      while (i < len) {
        const c = source[i];
        if (isDigit(c)) {
          i++;
          continue;
        }
        if (c === '.' && !seenDot && !seenExp) {
          seenDot = true;
          i++;
          continue;
        }
        if ((c === 'e' || c === 'E') && !seenExp) {
          seenExp = true;
          i++;
          if (source[i] === '+' || source[i] === '-') i++;
          continue;
        }
        break;
      }
      tokens.push({ type: 'number', value: source.slice(start, i), position: start });
      continue;
    }

    if (isAlpha(ch) || ch === '_') {
      const start = i;
      while (i < len && (isAlpha(source[i]) || isDigit(source[i]) || source[i] === '_' || source[i] === '.')) {
        i++;
      }
      const value = source.slice(start, i);
      const upper = value.toUpperCase();
      if (upper === 'TRUE' || upper === 'FALSE') {
        tokens.push({ type: 'bool', value: upper, position: start });
      } else {
        tokens.push({ type: 'ident', value, position: start });
      }
      continue;
    }

    throw new FormulaParseError(`Unexpected character "${ch}"`, i);
  }

  tokens.push({ type: 'eof', value: '', position: len });
  return tokens;
}

/** Consume a `"…"` literal, treating `""` as an escaped quote. */
function scanQuotedString(source: string, start: number): { value: string; end: number } {
  let i = start + 1;
  let value = '';
  const len = source.length;
  while (i < len) {
    if (source[i] === '"') {
      if (source[i + 1] === '"') {
        value += '"';
        i += 2;
        continue;
      }
      return { value, end: i + 1 };
    }
    value += source[i];
    i++;
  }
  throw new FormulaParseError('Unterminated string literal', start);
}

function isDigit(ch: string): boolean {
  return ch >= '0' && ch <= '9';
}

function isAlpha(ch: string): boolean {
  return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
}

// ─── Parser ─────────────────────────────────────────────────────────────────

class RecursiveDescent {
  private cursor = 0;
  private depth = 0;

  constructor(
    private readonly tokens: Token[],
    private readonly maxDepth: number,
  ) {}

  parseExpression(): FormulaAst {
    return this.guarded(() => this.parseComparison());
  }

  expect(type: TokenType): Token {
    const tok = this.peek();
    if (tok.type !== type) {
      throw new FormulaParseError(`Expected ${type}, got ${tok.type} "${tok.value}"`, tok.position);
    }
    this.cursor++;
    return tok;
  }

  private parseComparison(): FormulaAst {
    let left = this.parseConcat();
    while (true) {
      const op = this.peekOp();
      if (op !== '=' && op !== '<>' && op !== '<' && op !== '<=' && op !== '>' && op !== '>=') break;
      this.cursor++;
      const right = this.parseConcat();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  private parseConcat(): FormulaAst {
    let left = this.parseAdditive();
    while (this.peekOp() === '&') {
      this.cursor++;
      const right = this.parseAdditive();
      left = { kind: 'binary', op: '&', left, right };
    }
    return left;
  }

  private parseAdditive(): FormulaAst {
    let left = this.parseMultiplicative();
    while (true) {
      const op = this.peekOp();
      if (op !== '+' && op !== '-') break;
      this.cursor++;
      const right = this.parseMultiplicative();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  private parseMultiplicative(): FormulaAst {
    let left = this.parsePower();
    while (true) {
      const op = this.peekOp();
      if (op !== '*' && op !== '/') break;
      this.cursor++;
      const right = this.parsePower();
      left = { kind: 'binary', op, left, right };
    }
    return left;
  }

  /** `^` is right-associative in Excel. */
  private parsePower(): FormulaAst {
    const left = this.parseUnary();
    if (this.peekOp() === '^') {
      this.cursor++;
      const right = this.parsePower();
      return { kind: 'binary', op: '^', left, right };
    }
    return left;
  }

  private parseUnary(): FormulaAst {
    const op = this.peekOp();
    if (op === '+' || op === '-') {
      this.cursor++;
      return { kind: 'unary', op: op as UnaryOp, operand: this.parseUnary() };
    }
    return this.parsePrimary();
  }

  private parsePrimary(): FormulaAst {
    const tok = this.peek();
    switch (tok.type) {
      case 'number':
        this.cursor++;
        return { kind: 'number', value: Number(tok.value) };
      case 'string':
        this.cursor++;
        return { kind: 'string', value: tok.value };
      case 'bool':
        this.cursor++;
        return { kind: 'boolean', value: tok.value === 'TRUE' };
      case 'ident':
        return this.parseIdentExpression();
      case 'lparen': {
        this.cursor++;
        const inner = this.parseExpression();
        this.expect('rparen');
        return inner;
      }
      default:
        throw new FormulaParseError(`Unexpected token "${tok.value}"`, tok.position);
    }
  }

  /**
   * An ident followed by `(` is either the `REF(COLUMN(...),ROW(...))`
   * ref primitive (possibly chained as a range), or a regular function call.
   */
  private parseIdentExpression(): FormulaAst {
    const ident = this.expect('ident');
    const upper = ident.value.toUpperCase();
    if (upper === 'REF' && this.peek().type === 'lparen') {
      const ref = this.parseRefPrimitive(ident.position);
      if (this.peek().type === 'colon') {
        this.cursor++;
        const endIdent = this.expect('ident');
        if (endIdent.value.toUpperCase() !== 'REF' || this.peek().type !== 'lparen') {
          throw new FormulaParseError('Expected `REF(` after `:` in range', endIdent.position);
        }
        const endRef = this.parseRefPrimitive(endIdent.position);
        return { kind: 'range', start: ref, end: endRef };
      }
      return { kind: 'ref', ref };
    }
    // Regular function call.
    this.expect('lparen');
    const args: FormulaAst[] = [];
    if (this.peek().type !== 'rparen') {
      args.push(this.parseExpression());
      while (this.peek().type === 'comma') {
        this.cursor++;
        args.push(this.parseExpression());
      }
    }
    this.expect('rparen');
    return { kind: 'call', name: upper, args };
  }

  /**
   * Parse `REF(COLUMN("field")[,ROW(N) [,"$C"|"$R"|"$CR"]])` starting from
   * just after the `REF` ident. Returns the `StructuredRef`. A missing
   * `ROW(...)` arg marks the ref as same-row (resolves against the host
   * cell's row at evaluation time).
   */
  private parseRefPrimitive(position: number): StructuredRef {
    this.expect('lparen');

    const colIdent = this.expect('ident');
    if (colIdent.value.toUpperCase() !== 'COLUMN') {
      throw new FormulaParseError('Expected `COLUMN(` inside REF', colIdent.position);
    }
    this.expect('lparen');
    const fieldTok = this.expect('string');
    this.expect('rparen');

    // Same-row form: `REF(COLUMN("field"))` — no ROW arg.
    if (this.peek().type === 'rparen') {
      this.cursor++;
      void position;
      return {
        field: fieldTok.value,
        row: 0,
        absField: false,
        absRow: false,
        sameRow: true,
      };
    }

    this.expect('comma');

    const rowIdent = this.expect('ident');
    if (rowIdent.value.toUpperCase() !== 'ROW') {
      throw new FormulaParseError('Expected `ROW(` inside REF', rowIdent.position);
    }
    this.expect('lparen');
    const rowTok = this.expect('number');
    this.expect('rparen');

    const row = Number(rowTok.value);
    if (!Number.isFinite(row) || row < 1 || !Number.isInteger(row)) {
      throw new FormulaParseError('ROW must be a positive integer', rowTok.position);
    }

    let absField = false;
    let absRow = false;
    if (this.peek().type === 'comma') {
      this.cursor++;
      const lockTok = this.expect('string');
      const lock = lockTok.value;
      if (lock !== '$C' && lock !== '$R' && lock !== '$CR' && lock !== '') {
        throw new FormulaParseError(
          `Invalid REF lock marker: "${lock}" (expected "$C", "$R", or "$CR")`,
          lockTok.position,
        );
      }
      absField = lock === '$C' || lock === '$CR';
      absRow = lock === '$R' || lock === '$CR';
    }

    this.expect('rparen');

    void position;
    return { field: fieldTok.value, row, absField, absRow };
  }

  private peek(): Token {
    return this.tokens[this.cursor];
  }

  private peekOp(): BinaryOp | null {
    const tok = this.tokens[this.cursor];
    if (tok?.type !== 'op') return null;
    return tok.value as BinaryOp;
  }

  private guarded<T>(fn: () => T): T {
    if (++this.depth > this.maxDepth) {
      throw new FormulaParseError(`Formula exceeds max depth (${this.maxDepth})`, this.peek().position);
    }
    try {
      return fn();
    } finally {
      this.depth--;
    }
  }
}

