import { Directive, TemplateRef, Type, contentChild, input } from '@angular/core';
import { CellEditorType, ColumnDef } from '../models/column.model';
import { MozSelectOption } from '@mozaic-ds/angular';
import { CellError } from '../models/cell.model';
import {
  FilterDataType,
  FilterOperator,
  FilterValue,
  AdeoGridCustomFilter,
} from '../models/filter.model';

@Directive({
  selector: 'ad-grid-column-def',
})
export class AdeoGridColumnDef<T = unknown> {
  readonly field = input.required<string>();
  readonly headerName = input<string>();
  readonly width = input<string>();
  readonly minWidth = input<string>();
  readonly maxWidth = input<string>();
  readonly flex = input<number>();

  readonly sortable = input<boolean>(true);
  readonly resizable = input<boolean>(true);
  readonly reorderable = input<boolean>(true);
  readonly groupable = input<boolean>(false);
  readonly filterable = input<boolean>(false);
  readonly filterType = input<FilterDataType | undefined>(undefined);
  readonly filterOperators = input<FilterOperator[] | undefined>(undefined);
  readonly defaultFilterOperator = input<FilterOperator | undefined>(undefined);
  readonly filterOptions = input<{ value: unknown; label: string }[] | undefined>(undefined);
  readonly filterComponent = input<Type<AdeoGridCustomFilter> | undefined>(undefined);
  readonly filterIsComplete = input<((value: FilterValue) => boolean) | undefined>(undefined);
  readonly filterPredicate = input<((row: unknown, value: FilterValue) => boolean) | undefined>(undefined);
  readonly editable = input<boolean>(false);
  readonly visible = input<boolean>(true);
  readonly hideable = input<boolean>(true);
  readonly freezable = input<boolean>(true);
  readonly headerMenuDisabled = input<boolean>(false);
  /**
   * Mirrors `ColumnDef.allowFormula`. Required so the template binding
   * `[allowFormula]="true"` is forwarded into the generated column def —
   * without it, `FormulaEngine.syncFromSource` cannot detect this column
   * and any baked-in `=…` value is rendered as a raw string.
   */
  readonly allowFormula = input<boolean>(false);

  /**
   * Accepts both canonical Angular values (`'start' | 'end'`) and the Vue
   * aliases (`'left' | 'right'`). The latter are normalized at the
   * `toColumnDef()` boundary so downstream engines (state, layout, drawer)
   * only ever see `'start' | 'end' | null`.
   */
  readonly pinned = input<'start' | 'end' | 'left' | 'right' | null>(null);
  readonly cellEditor = input<CellEditorType>();
  readonly cellEditorOptions = input<MozSelectOption[]>();
  readonly cellValidator = input<
    ((value: unknown, row: unknown) => CellError | null) | undefined
  >();

  readonly cellTemplateInput = input<TemplateRef<unknown> | null>(null, { alias: 'cellTemplate' });
  readonly editTemplateInput = input<TemplateRef<unknown> | null>(null, { alias: 'editTemplate' });
  readonly filterTemplateInput = input<TemplateRef<unknown> | null>(null, {
    alias: 'filterTemplate',
  });
  readonly cellTemplateContent = contentChild<TemplateRef<unknown>>('cell');
  readonly editTemplateContent = contentChild<TemplateRef<unknown>>('edit');
  readonly filterTemplateContent = contentChild<TemplateRef<unknown>>('filter');

  toColumnDef(): ColumnDef<T> {
    return {
      field: this.field(),
      headerName: this.headerName(),
      width: this.width(),
      minWidth: this.minWidth(),
      maxWidth: this.maxWidth(),
      flex: this.flex(),
      sortable: this.sortable(),
      resizable: this.resizable(),
      reorderable: this.reorderable(),
      groupable: this.groupable(),
      filterable: this.filterable(),
      editable: this.editable(),
      visible: this.visible(),
      hideable: this.hideable(),
      freezable: this.freezable(),
      headerMenuDisabled: this.headerMenuDisabled(),
      pinned: normalizePinned(this.pinned()),
      cellEditor: this.cellEditor(),
      cellEditorOptions: this.cellEditorOptions(),
      cellTemplate: this.cellTemplateInput() ?? this.cellTemplateContent(),
      editTemplate: this.editTemplateInput() ?? this.editTemplateContent(),
      filterTemplate: this.filterTemplateInput() ?? this.filterTemplateContent(),
      filterType: this.filterType(),
      filterOperators: this.filterOperators(),
      defaultFilterOperator: this.defaultFilterOperator(),
      filterOptions: this.filterOptions(),
      filterComponent: this.filterComponent(),
      filterIsComplete: this.filterIsComplete(),
      filterPredicate: this.filterPredicate() as ColumnDef<T>['filterPredicate'],
      cellValidator: this.cellValidator(),
      allowFormula: this.allowFormula(),
    };
  }
}

/**
 * Map the Vue-flavoured aliases onto Angular's canonical pinned values:
 *  - `'left'`  → `'start'`
 *  - `'right'` → `'end'`
 *  - everything else passes through unchanged.
 *
 * Done at the directive boundary so the state manager, layout engines, and
 * column-resize/drag features keep their `'start' | 'end' | null` type
 * narrowing intact.
 */
function normalizePinned(
  v: 'start' | 'end' | 'left' | 'right' | null,
): 'start' | 'end' | null {
  if (v === 'left') return 'start';
  if (v === 'right') return 'end';
  return v;
}

import { Directive, TemplateRef, inject, input } from '@angular/core';

/**
 * Discriminator for the empty-state context.
 * - `no-data`     : the source dataset is empty (no rows ever loaded).
 * - `no-results`  : the dataset is non-empty but the active filter / search
 *                   produced zero rows.
 *
 * A template registered without an explicit kind defaults to `no-data` and
 * is also used as the fallback when `no-results` has no dedicated template.
 */
export type GridEmptyKind = 'no-data' | 'no-results';

/**
 * Marks a `<ng-template>` projected into `<ad-grid-angular>` as the renderer for
 * the empty state. Register one or two templates:
 *
 * ```html
 * <ad-grid-angular [data]="rows">
 *   <ng-template mozGridEmptyDef>
 *     <p>Aucune donnée pour le moment</p>
 *   </ng-template>
 *
 *   <ng-template mozGridEmptyDef="no-results" let-ctx>
 *     <p>Aucun résultat pour vos filtres ({{ ctx.activeFilterCount }})</p>
 *     <button (click)="ctx.clearFilters()">Réinitialiser</button>
 *   </ng-template>
 * </ad-grid-angular>
 * ```
 *
 * The implicit context (`let-ctx`) exposes `{ activeFilterCount, clearFilters }`.
 */
@Directive({
  selector: '[mozGridEmptyDef]',
})
export class AdeoGridEmptyDef {
  readonly kind = input<GridEmptyKind>('no-data', { alias: 'mozGridEmptyDef' });
  readonly template = inject<TemplateRef<GridEmptyContext>>(TemplateRef);
}

/** Context object passed to a `mozGridEmptyDef` template. */
export interface GridEmptyContext {
  /** Number of active filter conditions; `0` when called with `no-data`. */
  activeFilterCount: number;
  /** Convenience callback to clear all filter conditions. */
  clearFilters: () => void;
}

import { ComponentRef, Directive, ElementRef, Injector, OnDestroy, inject } from '@angular/core';
import { Overlay, OverlayConfig, OverlayRef, ConnectedPosition } from '@angular/cdk/overlay';
import { ComponentPortal } from '@angular/cdk/portal';
import { FilterEngine } from '../features/filter.engine';
import { AdeoGridFilterBuilderComponent } from '../components/filter-builder/grid-filter-builder';
import { FilterColumnDescriptor, FilterModel } from '../models/filter.model';

/**
 * Programmatically opens a CDK overlay anchored on the host element that
 * renders the filter builder. Unlike the action-listbox directive, the
 * overlay does not toggle on click — the host is simply the anchor. Open
 * the overlay by injecting this directive via a template ref (`#filter`)
 * and calling `filter.open(options)`.
 */
@Directive({
  selector: '[mozGridFilterOverlay]',
  exportAs: 'mozGridFilterOverlay',
})
export class AdeoGridFilterOverlayDirective implements OnDestroy {
  private readonly overlay = inject(Overlay);
  private readonly host = inject(ElementRef<HTMLElement>);
  private readonly injector = inject(Injector);
  private readonly engine = inject(FilterEngine, { optional: true }) as FilterEngine | null;

  private overlayRef: OverlayRef | null = null;
  private componentRef: ComponentRef<AdeoGridFilterBuilderComponent> | null = null;

  /** Opens the overlay anchored on the host. No-op if already open. */
  open(options: {
    columns: FilterColumnDescriptor[];
    model: FilterModel;
    /** Optional pre-selected column to seed a new condition. */
    seedField?: string;
    onChange: (model: FilterModel) => void;
  }): void {
    if (this.overlayRef) return;
    if (!this.engine) return;

    const positions: ConnectedPosition[] = [
      { originX: 'start', originY: 'bottom', overlayX: 'start', overlayY: 'top', offsetY: 4 },
      { originX: 'end', originY: 'bottom', overlayX: 'end', overlayY: 'top', offsetY: 4 },
      { originX: 'start', originY: 'top', overlayX: 'start', overlayY: 'bottom', offsetY: -4 },
    ];

    const positionStrategy = this.overlay
      .position()
      .flexibleConnectedTo(this.host)
      .withPositions(positions)
      .withPush(true)
      .withViewportMargin(8);

    const config = new OverlayConfig({
      hasBackdrop: true,
      backdropClass: 'cdk-overlay-transparent-backdrop',
      panelClass: 'ad-grid-filter-overlay',
      positionStrategy,
      scrollStrategy: this.overlay.scrollStrategies.reposition(),
    });

    const overlayRef = this.overlay.create(config);
    this.overlayRef = overlayRef;

    // Seed the draft with a new condition targeting the clicked column, if any
    const seededModel =
      options.seedField && options.model.conditions.length === 0
        ? { conditions: [this.engine.makeCondition(options.seedField, true)] }
        : options.model;

    const portal = new ComponentPortal(AdeoGridFilterBuilderComponent, null, this.injector);
    const compRef = overlayRef.attach(portal);

    compRef.setInput('model', seededModel);
    compRef.setInput('availableColumns', options.columns);
    compRef.setInput('applyMode', 'auto');
    compRef.setInput('showSubtitle', true);
    compRef.setInput('defaultField', options.seedField ?? null);

    compRef.instance.modelChange.subscribe((next: FilterModel) => {
      compRef.setInput('model', next);
      options.onChange(next);
    });

    this.componentRef = compRef;

    overlayRef.backdropClick().subscribe(() => this.close());
    overlayRef.keydownEvents().subscribe((event) => {
      if (event.key === 'Escape') this.close();
    });
  }

  close(): void {
    if (!this.overlayRef) return;
    this.overlayRef.dispose();
    this.overlayRef = null;
    this.componentRef = null;
    // A condition the user added but never gave a value to must not survive
    // once the builder is dismissed — drop it so it isn't a phantom filter.
    this.engine?.dropIncompleteConditions();
  }

  ngOnDestroy(): void {
    this.close();
  }
}

import { Directive, TemplateRef, inject, input } from '@angular/core';

export type GridToolbarSlot = 'start' | 'end';

@Directive({
  selector: '[mozGridToolbarDef]',
})
export class AdeoGridToolbarDef {
  readonly slot = input<GridToolbarSlot>('end', { alias: 'mozGridToolbarDef' });
  readonly template = inject(TemplateRef);
}

import {
  ComponentRef,
  Directive,
  OnChanges,
  OnDestroy,
  OutputRefSubscription,
  SimpleChanges,
  Type,
  ViewContainerRef,
  inject,
  input,
  output,
} from '@angular/core';
import { FilterCondition, FilterValue, AdeoGridCustomFilter } from '../../models/filter.model';

/**
 * Structural host for custom filter components inside the filter builder.
 *
 * Usage in template:
 *   <ng-container mozCustomFilterHost
 *     [componentType]="descriptor.filterComponent"
 *     [condition]="condition"
 *     (conditionChange)="onValueChange(condition.id, $event)"
 *   />
 */
@Directive({ selector: '[mozCustomFilterHost]', standalone: true })
export class MozCustomFilterHostDirective implements OnChanges, OnDestroy {
  readonly componentType = input.required<Type<AdeoGridCustomFilter>>();
  readonly condition = input.required<FilterCondition>();
  readonly conditionChange = output<FilterValue>();

  private readonly vcr = inject(ViewContainerRef);
  private ref: ComponentRef<AdeoGridCustomFilter> | undefined;
  private sub: OutputRefSubscription | undefined;

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['componentType']) {
      this.teardown();
      this.ref = this.vcr.createComponent(this.componentType());
      this.sub = this.ref.instance.conditionChange.subscribe((v: FilterValue) =>
        this.conditionChange.emit(v)
      );
    }
    if (this.ref) {
      this.ref.setInput('condition', this.condition());
    }
  }

  ngOnDestroy(): void {
    this.teardown();
  }

  private teardown(): void {
    this.sub?.unsubscribe();
    this.ref?.destroy();
    this.ref = undefined;
    this.sub = undefined;
  }
}

