:host {
  display: block;
  height: 100%;
  min-width: 0;
  background: inherit;
}

/* Pinned cells use position: sticky on the host element. Inherit
   background so the row tint (selected, hover) propagates and we
   never see the underlying scrollable content through the sticky cell. */
:host.grid-cell--pinned {
  background: inherit;
}

:host.grid-cell--pinned-left-edge {
  box-shadow: 4px 0 8px -2px rgba(0, 0, 0, 0.1);
}

:host.grid-cell--pinned-right-edge {
  box-shadow: -4px 0 8px -2px rgba(0, 0, 0, 0.1);
}

.grid-cell {
  display: flex;
  align-items: center;
  position: relative;
  padding: 0 var(--spacing-100, 8px);
  height: 100%;
  border-right: 1px solid var(--color-border-primary);
  overflow: hidden;
  box-sizing: border-box;
  min-width: 0;
  background: inherit;
  cursor: pointer;
}

.grid-cell--last {
  border-right: none;
}

.grid-cell--pinned-end {
  border-right: none;
  border-left: 1px solid var(--color-border-primary);
}

:host(:first-child) .grid-cell--pinned-end {
  border-left: none;
}

.grid-cell__value {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: var(--font-size-100, 14px);
  color: var(--color-text-primary);
  position: relative;
  z-index: 1;
}

.grid-cell__editor {
  width: 100%;
  min-width: 0;
  max-width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  overflow: hidden;
  box-sizing: border-box;
  position: relative;
  z-index: 1;
}

.grid-cell__editor-custom {
  width: 100%;
  min-width: 0;
  max-width: 100%;
  overflow: hidden;
  box-sizing: border-box;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-050, 4px);
}

.grid-cell__editor input,
.grid-cell__editor moz-select {
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
}

/* A combobox supplied through a consumer's `editTemplate` is projected
   content, so its `moz-combobox` host does not carry this component's
   encapsulation attribute — it must be reached through `::ng-deep`. The
   component also ships a fixed default width (~300px) on its inner
   `.mc-combobox`. Stretch both so the in-cell editor always matches the
   column width. */
