.grid-cell__editor ::ng-deep .mc-combobox {
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
}

.grid-cell__input--plain {
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: var(--font-size-100, 14px);
  color: var(--color-text-primary);
  padding: 0;
  height: 100%;
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
}

.grid-cell__input--plain:focus {
  outline: none;
}

/* Hide number input spinners for cleaner look */
.grid-cell__input--plain[type='number']::-webkit-inner-spin-button,
.grid-cell__input--plain[type='number']::-webkit-outer-spin-button {
  -webkit-appearance: none;
  margin: 0;
}

