  -moz-appearance: textfield;
}

.grid-cell__editor ::ng-deep .text-input {
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
}

.grid-cell__editor ::ng-deep .select,
.grid-cell__editor ::ng-deep .select__trigger {
  min-width: 0;
  width: 100%;
}

.grid-cell__editor ::ng-deep * {
  max-width: 100%;
}

.grid-cell__editor moz-datepicker {
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
}

.grid-cell__editor ::ng-deep .mc-datepicker,
.grid-cell__editor ::ng-deep .mc-text-input {
  width: 100%;
  min-width: 0;
  box-sizing: border-box;
  height: 28px; // custom value — no matching Mozaic token
  font-size: var(--font-size-50, 12px);
}

.grid-cell__editor ::ng-deep moz-datepicker label {
  display: none;
}

.grid-cell > *:not(.grid-cell__fill-handle) {
  position: relative;
  z-index: 1;
}

.grid-cell::before {
  content: '';
  position: absolute;
  inset: 3px 3px 3px 3px; // custom value — no matching Mozaic token
  border-radius: var(--border-radius-s, 4px);
  pointer-events: none;
  z-index: 0;
}

.grid-cell:hover::before {
  background: var(--color-background-secondary, #f1f3f4);
}

.grid-cell--focused:hover::before,
.grid-cell--in-range:hover::before,
.grid-cell--in-fill-range:hover::before,
.grid-cell--in-fill-reject-range:hover::before {
  background: transparent;
}

.grid-cell--focused {
  z-index: 2;
}

.grid-cell--focused::after {
  content: '';
  position: absolute;
  inset: 0;
  border: 2px solid var(--color-background-accent-inverse);
  border-radius: var(--border-radius-s, 4px);
  pointer-events: none;
}

/* Coloured border painted on cells referenced by a formula being edited.
   Uses a separate layer (`box-shadow` inset) so it stacks cleanly on top
   of the hover/range backgrounds without disturbing layout. */
.grid-cell--ref-highlight {
  z-index: 2;
}

.grid-cell--ref-highlight::after {
  content: '';
  position: absolute;
  inset: 0;
  border: 2px solid var(--ad-grid-ref-color, transparent);
  border-radius: var(--border-radius-s, 4px);
  pointer-events: none;
  z-index: 3;
}

.grid-cell--in-range {
  background: var(--color-background-accent);
}

.grid-cell--readonly .grid-cell__value {
  color: var(--color-text-secondary, #666);
}

.grid-cell--in-fill-range {
  background: rgba(52, 168, 83, 0.08); // success color tint — no matching Mozaic token
}

.grid-cell--in-fill-range::after {
  content: '';
  position: absolute;
  inset: 0;
  border: 1px dashed var(--color-status-border-success, #34a853);
  border-radius: var(--border-radius-s, 4px);
  pointer-events: none;
}

.grid-cell--in-fill-reject-range {
  background: rgba(234, 48, 45, 0.12); // error color tint — no matching Mozaic token
  cursor: not-allowed;
  z-index: 2;
}

.grid-cell--in-fill-reject-range::after {
  content: '';
  position: absolute;
  inset: 0;
  border: 2px dashed var(--color-status-standalone-error, #ea302d);
  border-radius: var(--border-radius-s, 4px);
  pointer-events: none;
  z-index: 3;
}

/* Excel-style "marching ants" for the cut (Ctrl+X) range. Each cell renders
   only the edge strips that face outward — the union of cells in the range
   forms the animated dashed rectangle around the cut region. */
.grid-cell--cut {
  background: rgba(26, 115, 232, 0.06); // accent color tint — no matching Mozaic token
}

.grid-cell__cut-mark {
  position: absolute;
  pointer-events: none;
  z-index: 5;
  --cut-color: var(--color-background-accent-inverse, #1a73e8);
}

.grid-cell__cut-mark--top,
.grid-cell__cut-mark--bottom {
  left: 0;
  right: 0;
  height: 2px;
  background-image: linear-gradient(90deg, var(--cut-color) 50%, transparent 50%);
  background-size: 8px 2px;
  background-repeat: repeat-x;
  animation: ad-grid-marching-ants-x 0.5s linear infinite;
}

.grid-cell__cut-mark--top {
  top: 0;
}

.grid-cell__cut-mark--bottom {
  bottom: 0;
}

.grid-cell__cut-mark--left,
.grid-cell__cut-mark--right {
  top: 0;
  bottom: 0;
  width: 2px;
  background-image: linear-gradient(180deg, var(--cut-color) 50%, transparent 50%);
  background-size: 2px 8px;
  background-repeat: repeat-y;
  animation: ad-grid-marching-ants-y 0.5s linear infinite;
}

.grid-cell__cut-mark--left {
  left: 0;
}

.grid-cell__cut-mark--right {
  right: 0;
}

@keyframes ad-grid-marching-ants-x {
  from {
    background-position-x: 0;
  }
  to {
    background-position-x: 8px;
  }
}

@keyframes ad-grid-marching-ants-y {
  from {
    background-position-y: 0;
  }
  to {
    background-position-y: 8px;
  }
}

.grid-cell__fill-handle {
  position: absolute;
  right: 0;
  bottom: 0;
  width: 8px;
  height: 8px;
  background: var(--color-background-accent-inverse);
  cursor: crosshair;
  z-index: 4;
}

.grid-cell--error {
  outline: 1px solid var(--color-status-border-error, #ef5f5c);
  outline-offset: -2px;
  z-index: 1;
  border-radius: var(--border-radius-s, 4px);
}

.grid-cell--error:hover::before {
  background: transparent;
}

/*
  Formula errors use a softer visual than validation errors: the cell stays
  readable and the error code (e.g. `#DIV/0!`) is rendered in-place by the
  span. A subtle red tint keeps the affordance without competing with real
  validation problems which use the filled icon + outline above.
 */
.grid-cell--formula-error .grid-cell__value {
  color: var(--color-status-text-error, #d0021b);
  font-style: italic;
}

.grid-cell__error-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  margin-left: auto;
  cursor: help;
  position: relative;
  z-index: 2;
  fill: var(--color-status-standalone-error, #ea302d);
}

// Pending cell: shimmer indicates an optimistic mutation is in flight.
.ad-grid-cell--pending {
  overflow: hidden;
  position: relative;
}

.ad-grid-cell--pending::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent 25%,
    rgba(26, 115, 232, 0.12) 50%,
    transparent 75%
  );
  background-size: 200% 100%;
  animation: ad-grid-cell-pending-shimmer 1.5s ease-in-out infinite;
  pointer-events: none;
  z-index: 3;
}

@keyframes ad-grid-cell-pending-shimmer {
  0% { background-position: 200% center; }
  100% { background-position: -200% center; }
}

